            private function resolveAccess($user): array
                {
                    /* ✅ Resolve Authority User (Team → Admin) */
                    $authorityUser = $user->team_id
                        ? User::find($user->team_id)
                        : $user;

                    if (!$authorityUser) {
                        return ['level' => 'none', 'plan' => null];
                    }

                    /* ✅ RULE 1 — Partner = FULL ACCESS */
                    if ($authorityUser->is_partner == 1) {
                        return ['level' => 'full', 'plan' => 'partner'];
                    }

                    /* ✅ RULE 2 — chk_subscription is KING */
                    if ($authorityUser->chk_subscription != 1) {
                        return ['level' => 'none', 'plan' => null];
                    }

                    /* ✅ RULE 3 — Fetch LATEST subscription safely */
                    $sub = PlannerSubscription::where('user_id', $authorityUser->id)
                        ->orderBy('id', 'desc')
                        ->first();

                    $plan = null;

                    /* ✅ Only ACTIVE subscriptions count */
                    if ($sub && $sub->subscription_closed == 0) {
                        $plan = $sub->subscription_plan;
                    }

                    /* ✅ PARTIAL PLAN */
                    
                        if ($plan === 'launch_499_partial') {
                            return ['level' => 'partial', 'plan' => $plan];
                        }
                     

                    /* ✅ FULL PLAN */
                    return [
                        'level' => $plan ? 'full' : 'none',
                        'plan'  => $plan
                    ];
                }

           private function getActiveSubscriptionPlan($user)
                {
                    return $this->resolveAccess($user)['plan'];
                }

           private function isPartialPlan($user): bool
                {
                    return $this->resolveAccess($user)['level'] === 'partial';
                }
           private function getAccessLevel($user): string
                {
                    return $this->resolveAccess($user)['level'];
                }
             private function safeName($text)
                {
                    if (!$text) return '-';

                    /* ✅ Detect Tamil / Unicode text */
                    if (preg_match('/[\x{0B80}-\x{0BFF}]/u', $text)) {
                        return $text; // ✅ DO NOT TOUCH TAMIL
                    }

                    return transliterateTextKeepNumbers($text);
                }

            private function safeTranslate($text)
                {
                    if (!$text) return '-';

                    /* If already Tamil → DO NOT TRANSLATE */
                    if (preg_match('/[\x{0B80}-\x{0BFF}]/u', $text)) {
                        return $text;
                    }

                    return translateText($text, app()->getLocale());
                }

            private function mapEventStatus($status)
                {
                    if (!$status) return '-';

                    $status = strtolower(trim($status));

                    $map = [
                        'completed' => 'நிறைவடைந்தது',
                        'complete'  => 'நிறைவடைந்தது',
                        'ongoing'   => 'நடைபெற்று வருகிறது',
                        'pending'   => 'Pending',
                    ];

                    return $map[$status] ?? $this->safeTranslate($status);
                }

            private function mapProfitLoss($value)
                {
                    if (!$value) return '-';

                    $value = strtolower(trim($value));

                    $map = [
                        'profit' => 'லாபம்',
                        'loss'   => 'இழப்பு',
                    ];

                    return $map[$value] ?? '-';
                }

            private function getVendorCount($eventId)
                {
                    return \DB::table('vendor_event_mappings')
                                ->where('event_id', $eventId)
                                ->count();
                }

            private function formatIndiaCurrency($amount)
                {
                    $amount = (float) $amount;

                    $decimal = sprintf("%.2f", $amount);
                    $exploded = explode('.', $decimal);

                    $lastThree = substr($exploded[0], -3);
                    $restUnits = substr($exploded[0], 0, -3);

                    if ($restUnits != '') {
                        $lastThree = ',' . $lastThree;
                    }

                    $restUnits = preg_replace("/\B(?=(\d{2})+(?!\d))/", ",", $restUnits);

                    return $restUnits . $lastThree . '.' . $exploded[1];
                }

