            (
            string $image,
            string $sidebar_image,
            string $sub_text,
            bool $main_menu,
            bool $sidebar,
            bool $next_page,
            int $dashboard_order,
            int $sidemenu_order,
            string $icon_name,
            string $page_name,
            bool $highlight_sidebar = false,
            bool $show_subscription_popup = false,
            bool $show_popup_backbutton = true,
            ?string $video_link = null,
            ?string $sidebar_icon = null
            ): array
            {
                return [
                'image' => $image,
                'sidebar_image' => $sidebar_image,
                'sub_text' => $sub_text,
                'main_menu' => $main_menu,
                'sidebar' => $sidebar,
                'next_page' => $next_page,
                'dashboard_order' => $dashboard_order,
                'sidemenu_order' => $sidemenu_order,
                'icon_name' => $icon_name,
