                'highlight_sidebar' => $highlight_sidebar,
                'show_subscription_popup' => $show_subscription_popup,
                'show_popup_backbutton' => $show_popup_backbutton,
                'video_link' => $video_link,
                'sidebar_icon' => $sidebar_icon,
                ];
            }


            private function canAccessFeature_1($user): bool
            {
                $authorityUser = $user->team_id
                    ? User::find($user->team_id)
                    : $user;

                if (!$authorityUser) return false;

                /* ✅ RULE #1 — Partner Admin */
                if ($authorityUser->is_partner == 1) {
                    return true;
                }

                /* ✅ RULE #2 — chk_subscription is KING 🔥 */
                if ($authorityUser->chk_subscription == 1) {
                    return true;     // ✅ THIS FIXES LEGACY USERS
                }

                /* ✅ RULE #3 — fallback to plan */
                $plan = $this->getActiveSubscriptionPlan($authorityUser);

                return (bool) $plan;
            }

            private function canAccessFeature($user): bool
            {
                return $this->resolveAccess($user)['level'] !== 'none';
            }

