                    $parentUser = $user->team_id
                        ? User::find($user->team_id)
                        : $user;

                    $latestSubscription = PlannerSubscription::where('user_id', $parentUser->id)
                        ->where('subscription_exist', 1)
                        ->latest('id')
                        ->first();

                    $chk_subscription = $user->chk_subscription;

                    $newZeroSubscriptionUser =
                        $chk_subscription == "1" &&
                        $latestSubscription &&
                        $latestSubscription->subscriptoin_amount == 0 &&
                        $latestSubscription->subscription_plan == 'zero_plan' &&
                        \Carbon\Carbon::parse($latestSubscription->created_at)->gte(
                            \Carbon\Carbon::parse('2026-06-03')->startOfDay()
                        );


                    $spec_items = array_map('trim', explode(',', strtolower($user->specialization ?? 'wedding')));
                    $isVenueSpecialist = in_array('venue', $spec_items);

                    $partialLockedPages = [
                        'Find Venues',
                        'List Venue',
                        'Photo Sharing',
                        'Create',
                    ];

                    $resolveAccess = function ($page) use ($isPartial, $canAccess, $partialLockedPages) {

                        if ($isPartial && in_array($page, $partialLockedPages)) {
                            return [false, true];   // next_page, popup
                        }

                        if ($isPartial) {
                            return [true, false];
                        }

                        return [$canAccess, !$canAccess];
                    };

