            // =========================================================================
            // HELPER — Logged-in user identity block
            // =========================================================================
            private function buildUserDetails($user): array
                {
                        
                    $parentUser = $user->team_id
                        ? User::find($user->team_id)   // Team Member → Admin
                        : $user;                       // Admin → Self

                    $plan = $this->getActiveSubscriptionPlan($parentUser);

                    $latestSubscription = PlannerSubscription::where('user_id', $parentUser->id)
                        ->where('subscription_exist', 1)
                        ->latest('id')
                        ->first();

                     $chk_subscription = $user->chk_subscription;   

                    $newZeroSubscriptionUser =
                        $chk_subscription == "1" &&
                        $latestSubscription &&
                        $latestSubscription->subscriptoin_amount == 0 &&
                        $latestSubscription->subscription_plan == 'zero_plan' &&
                        \Carbon\Carbon::parse($latestSubscription->created_at)->gte(
                            \Carbon\Carbon::parse('2026-06-03')->startOfDay()
                        );



                    if ($parentUser->is_partner == 1) {

                        $accessType = 'Full Access';

                    } 
                    elseif ($newZeroSubscriptionUser) {

                        $accessType = 'Wedding Leads & My Leads Only';

                    } 
                    elseif ($plan === 'launch_499_partial') {

                        $accessType = 'Partial Access';

                    } elseif ($plan) {

                        $accessType = 'Full Access';

                    } else {

                        $accessType = 'No Access';
                    }

                    return [
                        'id' => $user->id,
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name' => $user->business_name,

                        'subscription_plan' => $plan,
                        'access_type' => $accessType,
                        'is_team_member' => $user->team_id ? true : false,
                    ];
                }


