                        private function getPurchaseAllowedColumn($spec_items): string
                        {
                            $map = [
                                'photo&videographer' => 'purchase_allowed_photovideo',
                                'makeup-artists' => 'purchase_allowed_makeup',
                                'mehendi' => 'purchase_allowed_mehendi',
                                'catering' => 'purchase_allowed_catering',
                                'flower-decorators' => 'purchase_allowed_flower',
                                'priest' => 'purchase_allowed_priest',
                                'dj' => 'purchase_allowed_dj',
                                'venue' => 'purchase_allowed_venue',
                                'jewellers' => 'purchase_allowed_jewellers',
                                'weddingwear' => 'purchase_allowed_weddingwear',
                                'wedding' => 'purchase_allowed',
                            ];
                            foreach ($spec_items as $spec) {
                                if (isset($map[$spec])) return $map[$spec];
                            }
                            return 'purchase_allowed';
                        }

                        private function getPurchaseMadeCounts()
                        {
                            return GeneralLeadBuy::join(
                                    'general_leads',
                                    'general_leads_buy.general_leads_id',
                                    '=',
                                    'general_leads.id'
                                )
                                ->select(
                                    'general_leads_buy.general_leads_id',
                                    'general_leads.package_type',
                                    \DB::raw('count(*) as total')
                                )
                                ->groupBy(
                                    'general_leads_buy.general_leads_id',
                                    'general_leads.package_type'
                                )
                                ->get()
                                ->groupBy('general_leads_id')
                                ->map(function ($items) {
                                    return $items->pluck('total', 'package_type');
                                });
                        }

                        private function fetchNewLeads_1($user, $spec_items, $purchaseMadeCounts): array
                        {
                            $spec_items = array_map('trim', explode(',', strtolower($user->specialization ?? 'wedding')));

                            $leads = GeneralLead::select(
                                    'id',
                                    'package_type',
                                    'event_date',
                                    'approx_wedding',
                                    'event_location',
                                    'city',
                                    'name',
                                    'expiry_date',
                                    'purchase_allowed',
                                    'purchase_allowed_photovideo',
                                    'purchase_allowed_makeup',
                                    'purchase_allowed_catering',
                                    'purchase_allowed_flower',
                                    'purchase_allowed_priest',
                                    'purchase_allowed_mehendi',
                                    'purchase_allowed_dj',
                                    'purchase_allowed_venue',
                                    'purchase_allowed_jewellers',
                                    'purchase_allowed_weddingwear',
                                    'from_source',
                                    'not_show_wp',
                                    'this_user_id'
                                )
                                ->where('mute', '0')
                                ->where('from_source', 'PAW Leads')

                                /* ✅ SPECIALIZATION FILTER (LEGACY MATCH) */
                                ->where(function ($q) use ($spec_items) {

                                    if (in_array('venue', $spec_items)) {

                                        /* ✅ OLD DASHBOARD STRICT RULE → VENUE ONLY */
                                        $q->whereRaw('LOWER(package_type) LIKE ?', ['%venue%']);

                                    } else {

                                        foreach ($spec_items as $spec) {
                                            $q->orWhereRaw('LOWER(package_type) LIKE ?', ["%{$spec}%"]);
                                        }
                                    }
                                })

                                /* ✅ OLD EXPIRY WINDOW */
                                ->whereRaw("
                                    STR_TO_DATE(expiry_date, '%Y-%m-%d')
                                    BETWEEN DATE_SUB(CURDATE(), INTERVAL 6 DAY)
                                    AND DATE_ADD(CURDATE(), INTERVAL 3 DAY)
                                ")

                                /* ✅ OLD WP VISIBILITY */
                                ->where(function ($q) use ($user) {
                                    $q->where('not_show_wp', '!=', 1)
                                    ->orWhere('this_user_id', $user->id);
                                })

                                ->orderBy('id', 'desc')
                                ->get();

                            /* ✅ PURCHASE ELIGIBILITY FILTER */

                            $filtered = $leads->filter(function ($lead) use ($user, $spec_items, $purchaseMadeCounts) {

                                $pkg_types = array_map('trim', explode(',', strtolower($lead->package_type)));

                                /* ✅ VENUE LOGIC */

                                if (in_array('venue', $spec_items)) {

                                    $allowed = (int) $lead->purchase_allowed_venue;
                                    $purchased = (int) ($purchaseMadeCounts[$lead->id]['venue'] ?? 0);

                                    return ($purchased < $allowed);
                                }

                                /* ✅ OTHER SPECIALIZATIONS */

                                foreach ($spec_items as $spec) {

                                    if (in_array($spec, $pkg_types)) {

                                        $allowedColumn = $this->resolvePurchaseColumn($spec);

                                        $allowed = (int) ($lead->{$allowedColumn} ?? 0);
                                        $purchased = (int) ($purchaseMadeCounts[$lead->id][$spec] ?? 0);

                                        return ($purchased < $allowed);
                                    }
                                }

                                return false;
                            });

                            $total = $filtered->count();

                            $list = $filtered->take(5)->map(function ($lead) use ($user) {

                                $categoryKey = $this->getMatchedCategory($user->specialization, $lead->package_type);

                                return [
                                    'name' => transliterateTextKeepNumbers($lead->name), 
                                    'Category' => __('dashboard.categories.' . $categoryKey),
                                    'wedding date' => $lead->event_date ?: ($lead->approx_wedding ?? '-'),
                                    'location' => translateVenueLocation(trim($lead->event_location . ', ' . $lead->city)),
                                    'id' => $lead->id,
                                ];

                            })->values()->toArray();

                            return [
                                'total' => $total,
                                'list' => $list
                            ];
                        }



                        private function fetchNewLeads($user, $spec_items, $purchaseMadeCounts): array
                            {
                                $subscription = DB::table('planners_subscription')
                                    ->where('user_id', $user->id)
                                    ->orderBy('created_at', 'desc')
                                    ->first();

                                $subAmount = $subscription->subscriptoin_amount ?? 0;
                                $subPlan   = $subscription->subscription_plan ?? '';

                                $isPartner = (int)$user->is_partner === 1;

                                $isLegacyFull4999 =
                                    $user->chk_subscription == 1 &&
                                    in_array($subAmount, [4999, 9999]) &&
                                    $subPlan == 'legacy_full';

                                $isNoSubscription = $user->chk_subscription == 0;

                                $alreadyPurchased = DB::table('general_leads_buy')
                                    ->join('general_leads', 'general_leads.id', '=', 'general_leads_buy.general_leads_id')
                                    ->where('general_leads_buy.user_id', $user->id)
                                    ->where('general_leads.mute', 0)
                                    ->pluck('general_leads_buy.general_leads_id')
                                    ->toArray();

                                $purchaseCounts = DB::table('general_leads_buy')
                                    ->select('general_leads_id', 'purchase_type', DB::raw('COUNT(*) as total'))
                                    ->groupBy('general_leads_id', 'purchase_type')
                                    ->get()
                                    ->groupBy(fn ($row) => $row->general_leads_id . '_' . $row->purchase_type);

                                $leads = GeneralLead::where('from_source', 'PAW Leads')
                                    ->where('mute', 0)
                                    ->whereNotIn('id', $alreadyPurchased)
                                    ->orderBy('id', 'desc')
                                    ->get();

                                $final = [];

                                foreach ($leads as $lead) {

                                    /* ✅ SAME AS BUYLEADS */

                                    if ((int)$lead->not_show_wp === 1 && (int)$lead->this_user_id !== (int)$user->id) continue;

                                    $packageTypes = array_map('trim', explode(',', strtolower($lead->package_type ?? '')));
                                    $spec = strtolower($user->specialization ?? '');

                                    /* ✅ VENUE RULE */
                                    if ($spec === 'venue' && !(
                                        in_array('venue', $packageTypes) ||
                                        in_array('wedding', $packageTypes)
                                    )) {
                                        continue;
                                    }

                                    $matchedCat = null;
                                    $dbPrice = null;

                                    /* ✅ CATEGORY MATCH EXACT COPY */
                                    if (in_array('photo&videographer', $packageTypes) && str_contains($spec, 'photo')) {
                                        $matchedCat = 'photo&videographer';
                                        $dbPrice = $lead->price_photovideo;

                                    } elseif (in_array('catering', $packageTypes) && str_contains($spec, 'cater')) {
                                        $matchedCat = 'catering';
                                        $dbPrice = $lead->price_catering;

                                    } elseif (in_array('flower-decorators', $packageTypes) && str_contains($spec, 'flower')) {
                                        $matchedCat = 'flower-decorators';
                                        $dbPrice = $lead->price_flower;

                                    } elseif (in_array('venue', $packageTypes) && str_contains($spec, 'venue')) {
                                        $matchedCat = 'venue';
                                        $dbPrice = $lead->price_venue;

                                    } elseif (in_array('wedding', $packageTypes)) {
                                        $matchedCat = 'wedding';
                                        $dbPrice = $lead->price;

                                    } else {
                                        continue;
                                    }

                                    /* ✅ PURCHASE LIMIT */
                                    $multiPurchaseCategories = ['wedding', 'photo&videographer'];
                                    $maxPurchase = in_array($matchedCat, $multiPurchaseCategories) ? 3 : 1;

                                    $key = $lead->id . '_' . $matchedCat;
                                    $currentCount = isset($purchaseCounts[$key])
                                        ? optional($purchaseCounts[$key]->first())->total
                                        : 0;

                                    if ($currentCount >= $maxPurchase) continue;

                                    /* ✅ DATE LOGIC */
                                    if (empty($lead->expiry_date)) continue;

                                    $today  = \Carbon\Carbon::today();
                                    $expiry = \Carbon\Carbon::parse($lead->expiry_date)->startOfDay();

                                    if ($isLegacyFull4999) {

                                        $freeEnd = $expiry->copy()->addDays(3);
                                        if ($today->gt($freeEnd)) continue;

                                    } elseif ($isPartner) {

                                        if ($today->gt($expiry)) continue;

                                    } else {

                                        $paid75End = $expiry->copy()->addDays(3);
                                        if ($today->gt($paid75End)) continue;
                                    }

                                    /* ✅ FREE BLOCK */
                                    $cleanPrice = strtolower(trim((string)$dbPrice));

                                    if ($isNoSubscription && $cleanPrice === 'free') {
                                        continue;
                                    }

                                    /* ✅ FINAL PUSH */
                                    $final[] = $lead;
                                }

                                /* ✅ COUNT */
                                $total = count($final);

                                /* ✅ LIST (NO KEY CHANGE) */
                                $list = collect($final)->take(5)->map(function ($lead) use ($user) {

                                    $categoryKey = $this->getMatchedCategory($user->specialization, $lead->package_type);

                                    return [
                                        'name' => transliterateTextKeepNumbers($lead->name),
                                        'Category' => __('dashboard.categories.' . $categoryKey),
                                        'wedding date' => $lead->event_date ?: ($lead->approx_wedding ?? '-'),
                                        'location' => translateVenueLocation(trim($lead->event_location . ', ' . $lead->city)),
                                        'id' => $lead->id,
                                    ];

                                })->values()->toArray();

                                return [
                                    'total' => $total,
                                    'list' => $list
                                ];
                            }
                        
                         



                        

                        private function resolvePurchaseColumn($spec): string
                        {
                            $map = [
                                'photo&videographer' => 'purchase_allowed_photovideo',
                                'makeup-artists'     => 'purchase_allowed_makeup',
                                'mehendi'            => 'purchase_allowed_mehendi',
                                'catering'           => 'purchase_allowed_catering',
                                'flower-decorators'  => 'purchase_allowed_flower',
                                'priest'             => 'purchase_allowed_priest',
                                'dj'                 => 'purchase_allowed_dj',
                                'venue'              => 'purchase_allowed_venue',
                                'jewellers'          => 'purchase_allowed_jewellers',
                                'weddingwear'        => 'purchase_allowed_weddingwear',
                                'wedding'            => 'purchase_allowed',
                            ];

                            return $map[$spec] ?? 'purchase_allowed';
                        }

