                        private function fetchFollowups($user): array
                        {
                            $today = \Carbon\Carbon::today()->toDateString();
                            $lead_followups = GeneralLeadBuy::where('general_leads_buy.user_id', $user->id)
                                ->join('general_leads', 'general_leads_buy.general_leads_id', '=', 'general_leads.id')
                                ->join('general_leads_remarks', 'general_leads_buy.id', '=', 'general_leads_remarks.general_leads_buy_id')
                                ->whereDate('general_leads_remarks.followup', $today)
                                ->select('general_leads.name', 'general_leads.mobile', 'general_leads.from_source', 'general_leads.id as lead_id', 'general_leads_remarks.status', 'general_leads_remarks.followup')
                                ->get()->map(function ($l) {
                                    return [
                                        'name' => transliterateTextKeepNumbers($l->name),
                                        'mobile' => $l->mobile,
                                        'from_source' => $l->from_source,
                                        'status' => $l->status,
                                        'followup' => $l->followup,
                                        'event_title' => null,
                                    ];
                                });

                            $events = FollowupEvent::where('user_id', $user->id)
                                ->whereDate('date', $today)
                                ->get()->map(function ($e) {
                                    return [
                                        'name' => transliterateTextKeepNumbers($e->name),
                                        'mobile' => $e->mobile,
                                        'from_source' => 'Followup Event',
                                        'status' => 'Pending',
                                        'followup' => $e->date . ' ' . ($e->time ?? '00:00:00'),
                                        'event_title' => $e->title,
                                    ];
                                });

                            $merged = $lead_followups->concat($events);
                            return ['total' => $merged->count(), 'list' => $merged->take(5)->toArray()];
                        }

