                        private function fetchWeddingGuide($user, $user_role): array
                        {
                            $users = [$user->id];

                            if ($user_role == 'admin' || $user_role == 'partner admin') {
                                $team = User::where('team_id', $user->id)->pluck('id')->toArray();
                                $users = array_merge($users, $team);
                            }

                            $query = Client::whereIn('user_id', $users);

                            $total = $query->count();

                            $list = $query->orderBy('id', 'desc')
                                ->take(5)
                                ->get()
                                ->map(function ($c) use ($user) {

                                    $guestsText = __('dashboard.not_selected');

                                    if (!empty($c->guests)) {

                                        $guests = (int) $c->guests;

                                        if ($guests < 50) {
                                            $guestsText = 'Less than 50 Guests';
                                        } 
                                        elseif ($guests <= 100) {
                                            $guestsText = '50 – 100 Guests';
                                        } 
                                        elseif ($guests <= 300) {
                                            $guestsText = '100 – 300 Guests';
                                        } 
                                        else {
                                            $guestsText = $guests . ' Guests';
                                        }
                                    }

                                    return [

                                        'id' => $c->id,
                                        'main_id' => $c->main_id ?? null,

                                        'name' => translateText($c->name ?? '-', app()->getLocale()),
                                        'email' => $c->email ?? null,
                                        'mobile' => $c->mobile ?? null,

                                        'partner_name' => translateText($c->partner_name ?? '-', app()->getLocale()),
                                        'partner_mobile' => $c->partner_mobile ?? null,

                                        'location' => $c->location
                                            ? translateText($c->location, app()->getLocale())
                                            : null,
                                        'budget' => $c->budget ?? null,
                                        'guests' => $c->guests ?? null,
                                        'remarks' => $c->remarks ?? null,

                                        /* ✅ DUPLICATE FIELDS (OLD UI EXPECTED THESE) */

                                        'bride_name' => translateText($c->name ?? '-', app()->getLocale()),
                                        'bride_mobile' => $c->mobile ?? null,

                                        'groom_name' => translateText($c->partner_name ?? '-', app()->getLocale()),
                                        'groom_mobile' => $c->partner_mobile ?? null,

                                        /* ✅ ADMIN / TEAM INFO */

                                        'admin_userid' => $c->user_id,
                                        'admin_username' => optional(User::find($c->user_id))->name,

                                        'team_userid' => null,
                                        'team_username' => null,

                                        /* ✅ GUESTS TEXT (OLD LOGIC) */
 
                                        'guests_text' => translateText($guestsText, app()->getLocale()),
                                    ];
                                })
                                ->values()
                                ->toArray();

                            return [
                                'total' => $total,
                                'list' => $list
                            ];
                        }

