                        private function fetchMyEvents($user): array
                        {
                            // ✅ SAME formatter from OLD dashboard
                            $formatINR = function ($amount) {

                                if ($amount === null)
                                    return "₹0.00";

                                $decimal = number_format($amount, 2, '.', '');
                                $expl = explode('.', $decimal);

                                $num = $expl[0];
                                $dec = $expl[1];

                                $last3 = substr($num, -3);
                                $rest = substr($num, 0, -3);

                                if ($rest != '') {
                                    $last3 = ',' . $last3;
                                }

                                $rest = preg_replace("/\B(?=(\d{2})+(?!\d))/", ",", $rest);

                                return '₹' . $rest . $last3 . '.' . $dec;
                            };

                            // ✅ SAME query as OLD dashboard
                            $events = DB::table('vendor_events')
                                ->select('id', 'event_name', 'event_date', 'total_budget', 'event_status')
                                ->where('planner_id', $user->id)
                                ->orderBy('id', 'desc')
                                ->get();

                            $list = $events->map(function ($event) use ($formatINR) {

                                // ✅ REAL vendor count
                                $vendorCount = DB::table('vendor_events_myvendors')
                                    ->where('event_id', $event->id)
                                    ->count();

                                // ✅ REAL vendor payment
                                $totalVendorPayment = DB::table('vendor_advance_payment')
                                    ->where('event_id', $event->id)
                                    ->sum('advance_paid');

                                // ✅ REAL profit calculation
                                $profit = $event->total_budget - $totalVendorPayment;

                                // ✅ Profit / Loss label (OLD logic)
                                $profitLossStatus = $profit >= 0
                                    ? __('dashboard.profit')
                                    : __('dashboard.loss');

                                // ✅ STATUS MAPPING (OLD logic 🔥)
                                $statusKey = strtolower(trim($event->event_status));

                                if ($statusKey === 'ongoing') {
                                    $translatedStatus = __('dashboard.event_status_ongoing');
                                } elseif ($statusKey === 'completed') {
                                    $translatedStatus = __('dashboard.event_status_completed');
                                } elseif ($statusKey === 'upcoming') {
                                    $translatedStatus = __('dashboard.event_status_upcoming');
                                } else {
                                    $translatedStatus = $event->event_status;
                                }

                                return [
                                    "event_id" => $event->id,

                                    // ✅ CORRECT translator
                                    "event_name" => translateEventName($event->event_name),

                                    "event_date" => $event->event_date,

                                    // ✅ TRUE legacy currency format
                                    "total_budget" => $formatINR($event->total_budget),

                                    "event_status" => $translatedStatus,

                                    "total_number_of_vendors" => $vendorCount,

                                    "total_payment_made_to_vendors" => $formatINR($totalVendorPayment),

                                    "profit_loss_earned" => $formatINR($profit),

                                    "profit_or_loss_status" => $profitLossStatus,
                                ];
                            });

                            return [
                                'total' => $list->count(),
                                'list'  => $list->take(5)->values()->toArray()
                            ];
                        }

                        private function fetchNotifications($user): array
                        {
                            $notificationQuery = \App\BuyleadNotificationsLog::select(
                                    'buylead_notifications_logs.created_at',
                                    'buylead_notification_user_status.is_read'
                                )
                                ->join(
                                    'buylead_notification_user_status',
                                    'buylead_notifications_logs.id',
                                    '=',
                                    'buylead_notification_user_status.log_id'
                                )
                                ->where('buylead_notification_user_status.user_id', $user->id)
                                ->orderBy('buylead_notifications_logs.created_at', 'desc')
                                ->get();

                            $today_unread = 0;
                            $yesterday_unread = 0;
                            $earlier_unread = 0;

                            foreach ($notificationQuery as $noti) {

                                if ($noti->is_read == 0) {

                                    $created = \Carbon\Carbon::parse($noti->created_at);

                                    if ($created->isToday()) {
                                        $today_unread++;
                                    } elseif ($created->isYesterday()) {
                                        $yesterday_unread++;
                                    } else {
                                        $earlier_unread++;
                                    }
                                }
                            }

                            $total_unread = $today_unread + $yesterday_unread + $earlier_unread;

                            return [
                                'unread_today' => $today_unread,
                                'unread_yesterday' => $yesterday_unread,
                                'unread_earlier' => $earlier_unread,
                                'total_unread' => $total_unread,
                            ];
                        }

                        private function getMatchedCategory($spec, $pkg_type): string
                        {
                            $spec = strtolower(trim($spec));
                            $pkg_types = collect(explode(',', strtolower($pkg_type)))->map(fn($v) => trim($v))->filter()->values()->toArray();
                            $aliasMap = [
                                'wedding' => ['wedding', 'weddings'],
                                'makeup-artists' => ['makeup-artists', 'makeup', 'makeup artist', 'makeup artists'],
                                'photo&videographer' => ['photo&videographer', 'photographer', 'videographer', 'photo video'],
                                'catering' => ['catering', 'caterers', 'caterer'],
                                'flower-decorators' => ['flower-decorators', 'flower decorators', 'florist', 'decorator', 'flower'],
                                'mehendi' => ['mehendi', 'mehndi', 'mehendi artist'],
                                'priest' => ['priest', 'pandit'],
                                'dj' => ['dj', 'disc jockey'],
                                'venue' => ['venue', 'banquet', 'hall'],
                                'jewellers' => ['jewellers', 'jewelry', 'jeweller', 'jewelers'],
                                'weddingwear' => ['wedding wear', 'weddingwear', 'bridal wear', 'groom wear'],
                            ];
                            foreach ($aliasMap as $key => $aliases) {
                                if (in_array($spec, $aliases, true) && in_array($key, $pkg_types, true)) return $key;
                            }
                            return '-';
                        }


