                                    $show_date_counter = true;

                                    $chkplanner = PlannerSubscription::where('user_id', $user->id)
                                        ->orderBy('id', 'desc')
                                        ->first();

                                    $subsscription_end_date = $chkplanner
                                        ? $chkplanner->actual_subscription_end_date
                                        : null;
                                }

