                         public function getDashboardsubscription3(Request $request)
                            {
                                $langHeader = strtolower($request->header('Accept-Language', 'en'));
                                $lang = substr($langHeader, 0, 2);

                                $allowedLangs = ['en', 'ta', 'hi', 'te', 'kn', 'ml', 'gu', 'mr'];
                                if (!in_array($lang, $allowedLangs)) {
                                    $lang = 'en';
                                }

                                app()->setLocale($lang);

                                $token = $request->header('Authorization');
                                $user  = $this->getuser($token);

                                if (!$user) {
                                    return response()->json([
                                        'status' => '0',
                                        'message' => translateText('User not found', app()->getLocale()),
                                        'data' => [],
                                    ], 401);
                                }

                                /* ✅ CENTRALIZED ACCESS RESOLUTION */
                                $access     = $this->resolveAccess($user);
                                $canAccess  = $access['level'] !== 'none';
                                $isPartial  = $access['level'] === 'partial';

                                $useraccess = $this->chkuseraccessstatistics($token);
                                $user_role  = $useraccess['role'];
                                $chk_subscription = $user->chk_subscription;

                            

                                /* ✅ App Versioning */
                                $chkuser   = \App\Usertoken::where('user_id', $user->id)->latest()->first();
                                $chkdevice = \App\Userfcmtoken::where('user_id', $user->id)->latest()->first();
                                $mobdevice = $chkdevice ? $chkdevice->device : null;

                                $appPayload = $this->buildAppVersionPayload($chkuser, $mobdevice);

                                /* ✅ Subscription Popup Engine */
                                $show_auto_subscription_popup = $useraccess['show_auto_subscription_popup'];

                                if ($user_role == 'admin' && $chk_subscription == "0") {
                                    $show_auto_subscription_popup = false;
                                }

                                if ($user_role == 'admin') {
                                    $chkusersubscribed = PlannerSubscription::where('user_id', $user->id)->count();

                                    if ($chkusersubscribed > 0) {
                                        $show_auto_subscription_popup = false;
                                    }
                                }

                                /* ✅ Date Counter */
                                $subsscription_end_date = null;
                                $show_date_counter = false;

                                if ($user_role == 'admin' && $chk_subscription == "1") {
                                    $show_date_counter = true;

                                    $chkplanner = PlannerSubscription::where('user_id', $user->id)
                                        ->orderBy('id', 'desc')
                                        ->first();

                                    $subsscription_end_date = $chkplanner
                                        ? $chkplanner->actual_subscription_end_date
                                        : null;
                                }

                                /* ✅ Team Members */
                                $team_members = User::where('team_id', $user->id)
                                    ->where('is_active', 1)
                                    ->select('id', 'name')
                                    ->orderBy('id', 'DESC')
                                    ->paginate(10);

                                $team_members->getCollection()->transform(function ($item) {
                                    $item->user = User::where('id', $item->id)
                                        ->where('is_admin', 1)
                                        ->pluck('id');

                                    return $item;
                                });

                                /* ✅ Dashboard Data */
                                $stats_data = $this->buildStatsV3($user, $user_role);


                                /* TEST: New ₹499 rules after Mar 12 2026 */
                                $stats_data = $this->applyNew499RestrictionsAfterMarch12($stats_data, $user);



                                $subscription = PlannerSubscription::where('user_id', $user->id)
                                    ->where('subscription_exist', 1)
                                    ->latest('id')
                                    ->first();

                                $subAmount = $subscription->subscriptoin_amount ?? null;
                                $subPlan   = $subscription->subscription_plan ?? null;

                                $latestSubscription = PlannerSubscription::where('user_id', $user->id)
                                    ->where('subscription_exist', 1)
                                    ->latest('id')
                                    ->first();

                                $newZeroSubscriptionUser =
                                    $chk_subscription == "1" &&
                                    $subscription &&
                                    $subAmount == 0 &&
                                    $subPlan == 'zero_plan' &&
                                    Carbon::parse($subscription->created_at)->gte(
                                        Carbon::parse('2026-06-03')->startOfDay()
                                    );

                                $new1999SubscriptionUser =
                                    $chk_subscription == "1" &&
                                    $subscription &&
                                    $subAmount == 1999 &&
                                    $subPlan == 'launch_1999_full' &&
                                    Carbon::parse($subscription->created_at)->gte(
                                        Carbon::parse('2026-06-03')->startOfDay()
                                    );

                                $new19999SubscriptionUser =
                                    $chk_subscription == "1" &&
                                    $subscription &&
                                    $subAmount == 19999 &&
                                    $subPlan == 'launch_19999_full' &&
                                    Carbon::parse($subscription->created_at)->gte(
                                        Carbon::parse('2026-06-03')->startOfDay()
                                    );

                                /*
                                     $shouldShowPopup1 = in_array($access['level'], ['none', 'partial']);
                               

                                        $shouldShowPopup =
                                        $newZeroSubscriptionUser ||
                                        in_array($access['level'], ['none', 'partial']);

                                 */

                                if ($new1999SubscriptionUser || $new19999SubscriptionUser) {
                                    $shouldShowPopup = false;
                                } else {
                                    $shouldShowPopup =
                                        $newZeroSubscriptionUser ||
                                        in_array($access['level'], ['none', 'partial']);
                                }
                               

                                if (!empty($stats_data['shownonsubscriberpopup'])) {
                                    $shouldShowPopup = true;
                                }
                                
                                unset($stats_data['shownonsubscriberpopup']);



                                if ($new1999SubscriptionUser || $new19999SubscriptionUser) {

                                    $shouldShowPopup = false;

                                } elseif ($newZeroSubscriptionUser) {

                                    $shouldShowPopup = true;

                                } elseif ($chk_subscription == "0" && $user->is_partner != 1) {

                                    $shouldShowPopup = true;

                                } 
                                else {

                                    $shouldShowPopup = in_array($access['level'], ['none', 'partial']);
                                }


                                 
                                $loggedInUser = $this->buildUserDetails($user);

                                /*
                                    $noAccessUser =
                                    empty($loggedInUser['subscription_plan']) &&
                                    $loggedInUser['access_type'] == 'No Access';

                                */ 

                                    $noAccessUser = $loggedInUser['access_type'] === 'No Access';


                                    
                                    
                                return response()->json([

                                    'status' => 1,
                                    'message' => __('dashboard.user_access_array_and_count'),

                                    'page_heading' => [
                                        'show' => 1,
                                        'name' => __('dashboard.dashboard_heading'),
                                    ],

                                    'page_content' => [
                                        'show' => 1,
                                        'name' => __('dashboard.dashboard_subtext'),
                                    ],

                                    'burger_heading' => [
                                        'show' => 1,
                                        'name' => __('dashboard.burger_heading'),
                                    ],

                                    'dashboard_page_heading' => __('dashboard.dashboard_heading'),

                                    'showpopup' => !empty($stats_data['followups']['list']),

                                    'PAW Leads' => [],

                                    'dashboard_images_url' => $useraccess['dashboard_images_url'],
                                    'dashboard_video_url'  => $useraccess['dashboard_video_url'],

                                    'user_role'   => $user_role,
                                    'user_access' => $useraccess['useraccess'],

                                    'data' => $stats_data,

                                    'logged_in_user' => $this->buildUserDetails($user),

                                    'team_members' => $team_members,

                                    'newversion' => $appPayload['newversion'],

                                    'show_date_counter' => $show_date_counter,
                                    'subsscription_end_date' => $subsscription_end_date,

                                    /* ✅ FIXED POPUP LOGIC */
                                    /*
                                        'shownonsubscriberpopup' => $access['level'] === 'none',

                                        'show_popup_backbutton' => $noAccessUser ? false : true,

                                        'popup_subscription_content' => $canAccess
                                            ? ""
                                            : $this->getSubscriptionPopupBySpecialization($user->specialization),

                                    */
                                    'shownonsubscriberpopup' => $shouldShowPopup,

                                    'show_popup_backbutton' => $noAccessUser ? false : true,

                                    'popup_subscription_content' => $shouldShowPopup
                                        ? $this->getSubscriptionPopupNewDesign1($user->specialization, $user)
                                        : "",


                                    'show_auto_subscription_popup' => $noAccessUser ? true : $show_auto_subscription_popup,

                                    'show_tutorial' => false,

                                    'top_line' => __('dashboard.top_line_new_dashboard'),

                                    'whatsapp_link' => "https://wa.me/919403890373?text=Dear%20CRM%20Team,%0AI%20have%20a%20question%20regarding%20your%20CRM%20tool",


                                    'call_for_demo' => "9403890373",

                                    'base_url' => 'https://planawedding.in/storage/',

                                ], 200);
                            }

                            
        /* New Dashboard Ends */

        private function today()
        {
            return date('Y-m-d');
        }

        private function isAdminUser($user)
        {
            return $user && ($user->is_admin == "1" || $user->is_partner == "2");
        }

        private function
            resolveUserScope(
            $user
        ) {
            $scope = [
                'owner_id' => $user->id,
                'team_id' => $user->team_id,
                'is_team_member' => false,
                'is_team_admin' => false,
            ];

            if ($user->team_id) {
                $scope['owner_id'] =
                    $user->team_id;
                $scope['is_team_member'] = true;

                if ($this->isAdminUser($user)) {
                    $scope['is_team_admin'] = true;
                }
            }

            return $scope;
        }

        private function
            buildAppVersionPayload(
            $chkuser,
            $device
        ) {
            if (
                !in_array(
                    $device,
                    ['android', 'ios']
                )
            ) {
                return [
                    'newversion' => null,
                    'newupdate' => null
                ];
            }

            return [
                'newversion' => [
                    'paw_android_version' =>
                        [
                            'version' =>
                                (string) $chkuser->paw_android_version
                        ],
                    'paw_ios_version' => [
                        'version'
                        =>
                            (string) $chkuser->paw_ios_version
                    ],
                ],
                'newupdate' => [
                    'paw_android_newupdatelist' =>
                        [
                            'Bug Fix' => 'We added few features and fixed few bugs'
                        ],
                    'paw_ios_newupdatelist' => ['Bug Fix' => 'We added few features and fixed few bugs' ],
                ]
            ];
        }

        private function
            baseLeadQuery(
            $filter_user_id,
            $managed_by = false
        ) {
            $query =
                \DB::table('leads')->where(
                    'user_id',
                    $filter_user_id
                );
            if ($managed_by) {
                $query->where(
                    'managed_by',
                    $filter_user_id
                );
            }
            return $query;
        }

        private function
            countLeadsByStatus(
            $query,
            $status
        ) {
            return (clone
            $query)->where(
                    'status',
                    $status
                )->count();
        }

        private function
            countLeadsByStatuses(
            $query,
            array $statuses
        ) {
            return (clone
            $query)->whereIn(
                    'status',
                    $statuses
                )->count();
        }

        private function
            countLeadsBetweenDates(
            $query,
            $from,
            $to
        ) {
            return (clone
            $query)->whereBetween(
                    'created_at',
                    [$from, $to]
                )->count();
        }

        private function
            monthlyStats(
            $query,
            $year
        ) {
            $stats = [];
            for ($m = 1; $m <= 12; $m++) {
                $stats[] = (clone $query)->
                    whereMonth('created_at', $m)
                    ->whereYear(
                        'created_at',
                        $year
                    )
                    ->count();
            }
            return $stats;
        }

        private function
            buildDashboardCard(
            $key,
            $label,
            $count,
            $icon =
            null
        ) {
            return [
                'key' => $key,
                'label' => $label,
                'count' => $count,
                'icon' => $icon
            ];
        }

        private function
            buildMenuItem(
            $title,
            $route,
            $icon,
            $enabled =
            true
        ) {
            return [
                'title' => $title,
                'route' => $route,
                'icon' => $icon,
                'enabled' => $enabled
            ];
        }

        private function
            dashboardText(
            $heading,
            $content,
            $burger
        ) {
            return [
                'page_heading' =>
                    ['show' => 1, 'name' => $heading],
                'page_content' =>
                    ['show' => 1, 'name' => $content],
                'burger_heading' =>
                    ['show' => 1, 'name' => $burger],
            ];
        }

        private function
            isSubscriptionActive(
            $subscription,
            $today
        ) {
            if (!$subscription) {
                return false;
            }
            return
                $subscription->end_date >=
                $today;
        }

        private function
            isSubscriptionExpired(
            $subscription,
            $today
        ) {
            return (!$subscription ||
                $subscription->end_date <
                $today);
        }
        private
            function
            subscriptionDaysLeft(
            $subscription,
            $today
        ) {
            if
            (
                !$subscription ||
                $subscription->end_date
                < $today
            ) {
                return 0;
            }
            return
                (int) ((strtotime($subscription->
                    end_date) -
                    strtotime($today)) /
                    86400);
        }

        private function
            needsSubscriptionRenewalWarning(
            $subscription,
            $today,
            $threshold =
            7
        ) {
            return
                $this->subscriptionDaysLeft(
                    $subscription,
                    $today
                ) <=
                $threshold;
        }
        private function
            apiSuccessResponse(
            array
            $data
        ) {
            return
                response()->
                    json(array_merge([
                        'status'
                        => 1
                    ], $data));
        }

