        public function cities1(Request $request)
            {
                $lang = app()->getLocale(); // en, ta, hi...

                return Cache::remember(
                    "cities_{$lang}",
                    now()->addDays(30), // cache for 30 days
                    function () use ($lang) {

                        return City::where('status', 1)
                            ->orderBy('name')
                            ->get()
                            ->map(function ($city) use ($lang) {

                                return [
                                    'id' => $city->id,
                                    'state_id' => $city->state_id,
                                    'name' => translateCity($city->name),
                                    'status' => $city->status,
                                ];
                            });
                    }
                );
            } 

 

