       public function getprofile_1(Request $request)
            {
                $token = $request->header('Authorization');
                $user = $this->getuser($token);
                
                if($user) 
                {
                    if(!empty($user->company_logo))
                    {
                        $logo = $user->company_logo;
                    }
                    else
                    {
                        $logo = "";
                    }
                    
                    if (strtolower($user->specialization) === 'wedding') {
                        $specialization = 'Wedding Planner';
                    } else {
                        $specialization = $user->specialization;
                    }

                    /* ✅ NEW — USE YOUR CENTRALIZED ACCESS ENGINE */
                    $accessData = $this->resolveAccess($user);

                    $plan = $accessData['plan'];
                    $level = $accessData['level'];

                    if ($level === 'full') {
                        $accessType = 'Full Access';
                    } elseif ($level === 'partial') {
                        $accessType = 'Partial Access';
                    } else {
                        $accessType = 'No Access';
                    }

                    $items = array(
                        'id' => $user->id,
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'username' => $user->username,
                        'account_number' => $user->account_number,
                        'bank_name' => $user->bank_name,
                        'ifsc' => $user->ifsc,
                        'branch_name' => $user->branch_name,
                        'terms_conditions' => $user->terms_conditions,
                        'business_name' => $user->business_name,
                        'address1' => $user->address1,
                        'area_name' => $user->area_name,
                        'city' => $user->city,
                        'specialization' => translateText($specialization, app()->getLocale()),
                        'gstnumber' => $user->gstnumber,
                        'pannumber' => $user->pannumber,
                        'business_years' => $user->business_years,
                        'completed_events' => $user->completed_events,
                        'company_logo' => $logo,
                        'company_website' => $user->compweb,
                        'insta_link' => $user->insta_link,

                        /* ✅ NEW KEYS ADDED BELOW — NOTHING REMOVED */
                        'subscription_plan' => $plan,
                        'access_type' => $accessType,
                        'is_team_member' => $user->team_id ? true : false,
                    );
                
                    return response()->json([
                        'message' => translateText('User found', app()->getLocale()),
                        'status' => '1',
                        'data' => $items,
                    ], 200);
                } 
                else 
                {
                    return response()->json([
                        'message' => translateText('User not found', app()->getLocale()),
                        'status' => '0',
                        'data' => [],
                    ], 401);
                }
            }
        public function getprofile(Request $request)
            {
                $token = $request->header('Authorization');
                $user = $this->getuser($token);
                
                if ($user) 
                {
                    if (!empty($user->company_logo))
                    {
                        $logo = $user->company_logo;
                    }
                    else
                    {
                        $logo = "";
                    }
                    
                    if (strtolower($user->specialization) === 'wedding') {
                        $specialization = 'Wedding Planner';
                    } else {
                        $specialization = $user->specialization;
                    }

                    /* ✅ CENTRALIZED ACCESS RESOLUTION */
                    $access = $this->resolveAccess($user);

                    $accessType = $access['level'] === 'partial'
                        ? 'Partial Access'
                        : ($access['level'] === 'full' ? 'Full Access' : 'No Access');

                    /* ✅ Show popup for NONE + PARTIAL */
                    $shouldShowPopup = in_array($access['level'], ['none', 'partial']);

                    $items = array(
                        'id' => $user->id,
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'username' => $user->username,
                        'account_number' => $user->account_number,
                        'bank_name' => $user->bank_name,
                        'ifsc' => $user->ifsc,
                        'branch_name' => $user->branch_name,
                        'terms_conditions' => $user->terms_conditions,
                        'business_name' => $user->business_name,
                        'address1' => $user->address1,
                        'area_name' => $user->area_name,
                        'city' => $user->city,
                        'specialization' => translateText($specialization, app()->getLocale()),
                        'gstnumber' => $user->gstnumber,
                        'pannumber' => $user->pannumber,
                        'business_years' => $user->business_years,
                        'completed_events' => $user->completed_events,
                        'company_logo' => $logo,
                        'company_website' => $user->compweb,
                        'insta_link' => $user->insta_link,

                        /* ✅ NEW ACCESS KEYS */
                        'subscription_plan' => $access['plan'],
                        'access_type' => $accessType,
                        'is_team_member' => $user->team_id ? true : false,
                    );
                
                    return response()->json([
                        'message' => translateText('User found', app()->getLocale()),
                        'status' => '1',
                        'data' => $items,

                        /* ✅ POPUP LOGIC */
                        'show_popup_backbutton' => $shouldShowPopup,

                        'popup_subscription_content' => $shouldShowPopup
                            ? $this->getSubscriptionPopupBySpecialization($user->specialization, $user)
                            : null,

                    ], 200);
                } 
                else 
                {
                    return response()->json([
                        'message' => translateText('User not found', app()->getLocale()),
                        'status' => '0',
                        'data' => [],
                    ], 401);
                }
            }
    /* get profile ends */

    /* profile update starts */ 
       public function profileupdate(Request $request)
            {
                $token = $request->header('Authorization');
                
                $data = $this->getuser($token);
                
                if($data) 
                {
                    $useraccess = $this->checkeditaccess($token);
                    
                    $user_role = $useraccess['role'];
                    $user_access_array = $useraccess['access_array'];
                    
                    $user_details = ['name' => $data->name,'email' => $data->email,'mobile' => $data->mobile,'business_name' => $data->business_name];
                    
                    if($user_role !== 'team member')
                    {
                        $path = "";
                    
                        if ($request->hasFile('company_logo'))
                        {
                            $rules = array(
                                'business_name' => 'required',
                                'name' => 'required',
                                //'email' => 'required|email|unique:users,email,'.$data->id,
                                //'mobile' => 'required|numeric',
                                //'gstnumber' => 'required',
                            // 'pannumber' => 'required',
                            // 'bank_name' => 'required',
                                //'account_number' => 'required|numeric',
                            // 'branch_name' => 'required',
                            // 'ifsc' => 'required',
                                //'business_years' => 'required',
                                //'completed_events' => 'required',
                            // 'terms_conditions' => 'required',
                                //'company_logo' => 'required|image|mimes:jpeg,png,jpg,gif,svg|max:2048'
                            );
                
                            $error = Validator::make($request->all(), $rules);
                
                            if($error->fails())
                            {
                                $errors = $error->errors()->toArray();

                                // 🌐 Translate each validation message
                                foreach ($errors as $field => &$messages) {
                                    foreach ($messages as &$msg) {
                                        $msg = t($msg);
                                    }
                                }

                                return response()->json([
                                    'message' => $errors,
                                ], 422);
                            }
                
                            if(Storage::disk('public')->exists($data->company_logo))
                            {
                                Storage::delete($data->company_logo);
                            }
                            
                            $path = $request->file('company_logo')->store('event_planners');
                        }
                        else
                        {
                            $rules = array(
                                'business_name' => 'required',
                                'name' => 'required',
                                //'email' => 'required|email|unique:users,email,'.$data->id,
                                //'mobile' => 'required|numeric',
                                //'gstnumber' => 'required',
                            // 'pannumber' => 'required',
                            // 'bank_name' => 'required',
                                //'account_number' => 'required|numeric',
                            // 'branch_name' => 'required',
                            // 'ifsc' => 'required',
                                //'business_years' => 'required',
                                //'completed_events' => 'required',
                                //'terms_conditions' => 'required',
                                //'company_logo' => 'required|image|mimes:jpeg,png,jpg,gif,svg|max:2048'
                            );
                
                            $error = Validator::make($request->all(), $rules);
                
                            if($error->fails())
                            {
                                $errors = $error->errors()->toArray();

                                // 🌐 Translate each validation message
                                foreach ($errors as $field => &$messages) {
                                    foreach ($messages as &$msg) {
                                        $msg = t($msg);
                                    }
                                }

                                return response()->json([
                                    'message' => $errors,
                                ], 422);
                            }
                            
                            $path = $data->company_logo;
                            
                            if(empty($data->company_logo))
                            {
                                $path = "";
                            }
                        }
                        
                        $form_data = array(
                            'name'  =>  $request->name,
                            'email' =>  $request->email,
                            //'mobile' =>  $request->mobile,
                            //'account_number' =>  $request->account_number,
                            //'bank_name' =>  $request->bank_name,
                            //'ifsc' =>  $request->ifsc,
                            //'branch_name'  =>  $request->branch_name,
                            'terms_conditions' =>  nl2br($request->terms_conditions),
                            'business_name' =>  $request->business_name,
                            'gstnumber' =>  $request->gstnumber,
                            'pannumber' =>  $request->pannumber,
                            'business_years' =>  $request->business_years,
                            'completed_events'  =>  $request->completed_events,
                            'company_logo' =>  $path,
                            'compweb'  =>  $request->company_website,
                            'insta_link'  =>  $request->insta_link
                        );
                        
                        // team member related changes
                        
                        if(empty($data->team_id))
                        {
                            $data->name = $request->name;
                            $data->email = $request->email;
                            //$data->mobile = $request->mobile;
                            //$data->account_number = $request->account_number;
                            //$data->bank_name = $request->bank_name;
                            //$data->ifsc = $request->ifsc;
                            //$data->branch_name = $request->branch_name;
                            $data->terms_conditions = nl2br($request->terms_conditions);
                            $data->business_name = $request->business_name;
                            $data->gstnumber = $request->gstnumber;
                            $data->pannumber = $request->pannumber;
                            $data->business_years = $request->business_years;
                            $data->completed_events = $request->completed_events;
                            $data->company_logo = $path;

                            $data->compweb = $request->company_website;
                            $data->insta_link = $request->insta_link; 
                            if($data->save())
                            {
                                $user_details = ['name' => $data->name,'email' => $data->email,'mobile' => $data->mobile,'business_name' => $data->business_name];
                                
                                $users = User::where('team_id',$data->id)->get();
                                
                                foreach($users as $user)
                                {
                                    $user->account_number = $request->account_number;
                                    //$user->bank_name = $request->bank_name;
                                    //$user->ifsc = $request->ifsc;
                                    //$user->branch_name = $request->branch_name;
                                    $user->terms_conditions = nl2br($request->terms_conditions);
                                    $user->business_name = $request->business_name;
                                    $user->gstnumber = $request->gstnumber;
                                    $user->pannumber = $request->pannumber;
                                    $user->business_years = $request->business_years;
                                    $user->completed_events = $request->completed_events;
                                    $user->company_logo = $path;
                                    $user->compweb = $request->company_website;
                                    $user->insta_link = $request->insta_link; 
                                    $user->save();
                                }
                                
                                return response()->json([ 
                                    'message' => translateText('User profile updated', app()->getLocale()),
                                    'status' => '1',
                                    'data' => $form_data,
                                    'user_role' => $user_role,
                                    'logged_in_user' => $user_details
                                ], 201);
                            }
                            else
                            {
                                return response()->json([ 
                                    'message' => translateText('User profile not updated', app()->getLocale()),
                                    'status' => '0',
                                    'data' => [],
                                    'user_role' => $user_role,
                                    'logged_in_user' => $user_details,
                                ], 503);
                            }
                        }
                        else
                        {
                            return response()->json([ 
                                'message' => translateText('Team member do not have access to update the profile', app()->getLocale()),
                                'status' => '0',
                                'data' => [],
                                'user_role' => $user_role,
                                'logged_in_user' => $user_details,
                            ], 401);
                        }
                    }
                    else
                    {
                        return response()->json([ 
                            'message' => translateText('User do not have access', app()->getLocale()),
                            'status' => '0',
                            'data' => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 401);
                    }
                } 
                else 
                {
                    return response()->json([ 
                        'message' => translateText('User not found', app()->getLocale()),
                        'status' => '0',
                        'data' => [],
                        'user_role' => "",
                        'logged_in_user' => [],
                    ], 401);
                }
            }
    /* profile update ends */ 

    /* profile delete starts */
        public function deleteprofileimage(Request $request)
            {
                $token = $request->header('Authorization');
                $data = $this->getuser($token);

                if(!$data) {
                    return response()->json([ 
                        'message' => translateText('User not found', app()->getLocale()),
                        'status' => '0',
                    ], 401);
                }

                // Check access
                $useraccess = $this->checkeditaccess($token);
                $user_role = $useraccess['role'];

                $user_details = [
                    'name' => $data->name,
                    'email' => $data->email,
                    'mobile' => $data->mobile,
                    'business_name' => $data->business_name
                ];


                if($user_role === 'team member') {
                        
                    return response()->json([ 
                        'message'       => translateText('Team member do not have access to delete profile image', app()->getLocale()),
                        'status'         => 0, 
                        'user_role'      => $user_role,
                        'logged_in_user' => $user_details,
                        'base_url'       => 'https://planawedding.in/storage/',
                    ], 401);
                }

                

                // Only owner (team_id empty) can delete
                if(!empty($data->team_id)) {
                    
                    return response()->json([ 
                        'message'        => translateText('Team member do not have access', app()->getLocale()),
                        'status'         => 0, 
                        'user_role'      => $user_role,
                        'logged_in_user' => $user_details,
                        'base_url'       => 'https://planawedding.in/storage/',
                    ], 401);
                }

                // Check if image exists
                if(!empty($data->company_logo) && Storage::disk('public')->exists($data->company_logo)) {
                    Storage::disk('public')->delete($data->company_logo);
                }

                // Remove image reference from DB
                $data->company_logo = NULL;
                $data->save();

                // Delete logo for all team members also
                $teamMembers = User::where('team_id', $data->id)->get();
                foreach($teamMembers as $member) {
                    $member->company_logo = NULL;
                    $member->save();
                }

                

                return response()->json([ 
                    'message'       => translateText('Profile image deleted successfully', app()->getLocale()),
                    'status'         => 1, 
                    'user_role'      => $user_role,
                    'logged_in_user' => $user_details,
                    'base_url'       => 'https://planawedding.in/storage/',
                ], 200);

            }
    /* profile delete ends */

