         /* notification listing starts */
                public function getNotificationLogs(Request $request)
                    {
                        $token = $request->header('Authorization');
                           
                        // -----------------------------------
                        // Get User
                        // -----------------------------------
                        $user = $this->getuser($token);

                        if (!$user) {
                            return response()->json([ 
                                'message' => translateText('User not found', app()->getLocale()),
                                'status'  => 0
                            ], 401);
                        }

                        $useraccess = $this->checkeditaccess($token);
                        $user_role  = $useraccess['role'];

                        $user_details = [
                            'name'          => $user->name,
                            'email'         => $user->email,
                            'mobile'        => $user->mobile,
                            'business_name' => $user->business_name
                        ];

                        // -----------------------------------
                        // SPECIALIZATION FILTER
                        // -----------------------------------
                        $specialization = $user->specialization;
                        $specialization_array = array_map('trim', explode(',', $specialization));

                        // -----------------------------------
                        // Pagination
                        // -----------------------------------
                        $page      = $request->input('page', 1);
                        $per_page  = 20;
                        $offset    = ($page - 1) * $per_page;

                        // -----------------------------------
                        // BASE QUERY
                        // -----------------------------------
                        $baseQuery = \App\BuyleadNotificationsLog::select(
                                'buylead_notifications_logs.id',
                                'lead_id',
                                'custom_lead_id',
                                'lead_name',
                                'package_type',
                                'type',
                                'sent_for',
                                'message',
                                'buylead_notifications_logs.created_at',
                                'buylead_notification_user_status.is_read'
                            )
                            ->join(
                                'buylead_notification_user_status',
                                'buylead_notifications_logs.id',
                                '=',
                                'buylead_notification_user_status.log_id'
                            )
                            ->where('buylead_notification_user_status.user_id', $user->id)

                            // BUY LEAD → matches specialization
                            // NEWS + COUPLE → visible to all
                            ->where(function($q) use ($specialization_array) {
                                $q->where('type', 'news')                 // NEWS
                                ->orWhere('type', 'create')             // COUPLE NOTIFICATION
                                ->orWhereIn('sent_for', $specialization_array); // BUY LEADS
                            });

                        // -----------------------------------
                        // TOTAL RECORDS
                        // -----------------------------------
                        $total_records = $baseQuery->count();
                        $total_pages   = ceil($total_records / $per_page);

                        // -----------------------------------
                        // FETCH PAGINATED LOGS
                        // -----------------------------------
                        $logs = $baseQuery
                                ->orderBy('buylead_notifications_logs.created_at', 'desc')
                                ->offset($offset)
                                ->limit($per_page)
                                ->get();

                        // -----------------------------------
                        // GROUPING
                        // -----------------------------------
                        $today_list     = [];
                        $yesterday_list = [];
                        $earlier_list   = [];

                        foreach ($logs as $log) {

                            // FIXED Carbon usage
                            $created = Carbon::parse($log->created_at);

                            $clean = [
                                'id'            => $log->id,
                                'lead_id'       => $log->lead_id,
                                'custom_lead_id'=> $log->custom_lead_id,
                                'lead_name'      => transliterateTextKeepNumbers($log->lead_name, app()->getLocale()),
                                'package_type'  => $log->package_type,
                                'type'          => $log->type,
                                'sent_for'      => $log->sent_for,
                                'message'        => translateText($log->message, app()->getLocale()),
                                'read_status'   => ($log->is_read == 1 ? 'read' : 'unread'),
                            ];

                            if ($created->isToday()) {
                                $today_list[] = $clean;
                            }
                            elseif ($created->isYesterday()) {
                                $yesterday_list[] = $clean;
                            }
                            else {
                                $earlier_list[] = $clean;
                            }
                        }

                        // -----------------------------------
                        // UNREAD COUNTS
                        // -----------------------------------
                        $today_unread     = collect($today_list)->where('read_status', 'unread')->count();
                        $yesterday_unread = collect($yesterday_list)->where('read_status', 'unread')->count();
                        $earlier_unread   = collect($earlier_list)->where('read_status', 'unread')->count();

                        // -----------------------------------
                        // RESPONSE
                        // -----------------------------------
                        return response()->json([ 
                            'message'           => translateText('Log list fetched successfully', app()->getLocale()),
                            'status'         => 1,

                            'today'          => $today_list,
                            'yesterday'      => $yesterday_list,
                            'earlier'        => $earlier_list,

                            'unread_counts'  => [
                                'today'     => $today_unread,
                                'yesterday' => $yesterday_unread,
                                'earlier'   => $earlier_unread,
                            ],

                            // PAGINATION
                            'pagination' => [
                                'current_page'  => (int)$page,
                                'per_page'      => (int)$per_page,
                                'total_records' => (int)$total_records,
                                'total_pages'   => (int)$total_pages,
                            ],

                            'user_role'      => $user_role,
                            'logged_in_user' => $user_details,
                            'base_url'       => 'https://planawedding.in/storage/',
                        ], 200);
                    }
         /* notification listing ends */

         /* mark notification read starts */
                public function markNotificationRead(Request $request)
                    {
                        $token = $request->header('Authorization');
                        $user = $this->getuser($token);

                        if (!$user) {
                            return response()->json([
                                'message' => translateText('User not found', app()->getLocale()),
                                'status'  => 0
                            ], 401);
                        }

                        $useraccess = $this->checkeditaccess($token);
                        $user_role  = $useraccess['role'];

                        $user_details = [
                            'name'          => $user->name,
                            'email'         => $user->email,
                            'mobile'        => $user->mobile,
                            'business_name' => $user->business_name
                        ];

                        $log_id = $request->input('log_id');

                        // Validate log_id
                        if (empty($log_id) || !is_numeric($log_id)) {
                            return response()->json([ 
                                'message' => translateText('log_id is required and must be numeric', app()->getLocale()),
                                'status'  => 0
                            ], 400);
                        }

                        $logId = (int) $log_id;

                        // Attempt update — only for this user
                        $updated = \DB::table('buylead_notification_user_status')
                            ->where('log_id', $logId)
                            ->where('user_id', $user->id)
                            ->update([
                                'is_read'    => 1,
                                'updated_at' => now(),
                            ]);

                        if ($updated === 0) {
                            // nothing updated — either row doesn't exist, already marked read, or belongs to another user
                            return response()->json([ 
                                'message' => translateText('No notification found for this user with the given log_id (already deleted, already read, or not owned)', app()->getLocale()),
                                'status'         => 0,
                                'user_role'      => $user_role,
                                'logged_in_user' => $user_details,
                                'base_url'       => 'https://planawedding.in/storage/',
                            ], 404);
                        }

                        // Optional: return remaining unread count for UI
                        $remaining_unread = \DB::table('buylead_notification_user_status')
                            ->where('user_id', $user->id)
                            ->where('is_read', 0)
                            ->count();

                        return response()->json([ 
                            'message' => translateText('Notification marked as read', app()->getLocale()),
                            'status'            => 1,
                            'updated_count'     => $updated,               // usually 1
                            'remaining_unread'  => $remaining_unread,
                            'user_role'         => $user_role,
                            'logged_in_user'    => $user_details,
                            'base_url'          => 'https://planawedding.in/storage/',
                        ], 200);
                    }
         /* mark notification read ends */

