                            ], 401);
                        }

                        $useraccess = $this->checkeditaccess($token);
                        $user_role  = $useraccess['role'];

                        $user_details = [
                            'name'          => $user->name,
                            'email'         => $user->email,
                            'mobile'        => $user->mobile,
                            'business_name' => $user->business_name
                        ];

                        $log_id = $request->input('log_id');

                        // Validate
                        if (empty($log_id) || !is_numeric($log_id)) {
                            return response()->json([ 
                                'message' => translateText('log_id is required and must be numeric', app()->getLocale()),
                                'status'  => 0
                            ], 400);
                        }

                        $logId = (int) $log_id;

                        // Attempt delete — only for this user
                        $deleted = \DB::table('buylead_notification_user_status')
                            ->where('log_id', $logId)
                            ->where('user_id', $user->id)
                            ->delete();

                        if ($deleted === 0) {
                            // nothing deleted — either not present or belongs to another user or already deleted
                            return response()->json([ 
                                'message' => translateText('No notification found for this user with the given log_id (already deleted or not owned)', app()->getLocale()),
                                'status'         => 0,
                                'user_role'      => $user_role,
                                'logged_in_user' => $user_details,
                                'base_url'       => 'https://planawedding.in/storage/',
                            ], 404);
                        }

                        // Get remaining notifications count for this user (optional but useful for frontend)
                        $remaining = \DB::table('buylead_notification_user_status')
                            ->where('user_id', $user->id)
                            ->count();

                        return response()->json([ 
                            'message' => translateText('Notification deleted for this user only', app()->getLocale()),
                            'status'          => 1,
                            'deleted_count'   => $deleted,
                            'remaining_count' => $remaining,
                            'user_role'       => $user_role,
                            'logged_in_user'  => $user_details,
                            'base_url'        => 'https://planawedding.in/storage/',
                        ], 200);
                    }
