         /* delete multiple notification starts */
                public function deleteNotificationMultiple(Request $request)
                    {
                        $token = $request->header('Authorization');
                        $user  = $this->getuser($token);

                        if (!$user) {
                            return response()->json([
                                'message' => translateText('User not found', app()->getLocale()),
                                'status'  => 0
                            ], 401);
                        }

                        $useraccess = $this->checkeditaccess($token);
                        $user_role  = $useraccess['role'];

                        $user_details = [
                            'name'          => $user->name,
                            'email'         => $user->email,
                            'mobile'        => $user->mobile,
                            'business_name' => $user->business_name
                        ];

                        // -----------------------------------
                        // Validate array
                        // -----------------------------------
                        $log_ids = $request->log_ids;

                        if (!is_array($log_ids) || empty($log_ids)) {
                            return response()->json([ 
                                'message' => translateText('log_ids must be a non-empty array', app()->getLocale()),
                                'status'  => 0
                            ], 400);
                        }

                        // -----------------------------------
                        // DELETE only for THIS USER
                        // -----------------------------------
                        $deleted = DB::table('buylead_notification_user_status')
                                    ->where('user_id', $user->id)
                                    ->whereIn('log_id', $log_ids)
                                    ->delete();

                        return response()->json([ 
                            'message'       => $deleted > 0 ? translateText('Notifications deleted successfully', app()->getLocale()) : translateText('No matching notifications found', app()->getLocale()),
                            'deleted_count'  => $deleted,
                            'status'         => 1,
                            'user_role'      => $user_role,
                            'logged_in_user' => $user_details,
                            'base_url'       => 'https://planawedding.in/storage/',
                        ]);
                    }
