                    'flower-decorators'  => ['limit_col' => 'purchase_allowed_flower', 'type' => 'flower-decorators'],
                    'mehendi'            => ['limit_col' => 'purchase_allowed_mehendi', 'type' => 'mehendi'],
                    'priest'             => ['limit_col' => 'purchase_allowed_priest', 'type' => 'priest'],
                    'dj'                 => ['limit_col' => 'purchase_allowed_dj', 'type' => 'dj'],
                    'venue'              => ['limit_col' => 'purchase_allowed_venue', 'type' => 'venue'],
                    'jewellers'          => ['limit_col' => 'purchase_allowed_jewellers', 'type' => 'jewellers'],
                    'wedding wear'       => ['limit_col' => 'purchase_allowed_weddingwear', 'type' => 'weddingwear'],
                ];

                $alreadyPurchased = DB::table('general_leads_buy')
                    ->where('user_id', $user->id)
                    ->pluck('general_leads_id')
                    ->flip();

                $purchaseCounts = DB::table('general_leads_buy')
                    ->select('general_leads_id', 'purchase_type', DB::raw('COUNT(*) as total'))
                    ->groupBy('general_leads_id', 'purchase_type')
                    ->get()
                    ->groupBy(fn ($row) => $row->general_leads_id . '_' . $row->purchase_type);

                $leads = GeneralLead::where('from_source', 'PAW Leads')
                    ->orderBy('id', 'desc')
                    ->get();

                $finalLeads = [];

                foreach ($leads as $lead) {

                    if (isset($alreadyPurchased[$lead->id])) continue;

                    if ((int)$lead->not_show_wp === 1 && (int)$lead->this_user_id !== (int)$user->id) continue;

                    if ($filterState !== '' && strcasecmp($lead->actual_state_tbl_name ?? '', $filterState) !== 0) continue;

                    if ($filterLeadCategory !== '' && strcasecmp($lead->actual_lead_from_to_show ?? '', $filterLeadCategory) !== 0) continue;

                    $packageTypes = array_map('trim', explode(',', strtolower($lead->package_type ?? '')));
                    $spec = strtolower($user->specialization ?? '');
                        /* ✅ SPECIALIZATION FILTER */
                    if ($spec === 'venue' && !(
                            in_array('venue', $packageTypes) ||
                            in_array('wedding', $packageTypes)
                        )) {
                        continue;
                    }
                    $matchedCat = null;

                    if (in_array('photo&videographer', $packageTypes) && str_contains($spec, 'photo')) {
                        $matchedCat = 'photo&videographer';
                        $desc = $lead->lead_description_photovideo;
                        $dbPrice = $lead->price_photovideo;
                        $eventCat = $lead->event_category_photovideo;

                    } elseif (in_array('catering', $packageTypes) && str_contains($spec, 'cater')) {
                        $matchedCat = 'catering';
                        $desc = $lead->lead_description_catering;
                        $dbPrice = $lead->price_catering;
                        $eventCat = $lead->event_category_catering;

                    } elseif (in_array('flower-decorators', $packageTypes) && str_contains($spec, 'flower')) {
                        $matchedCat = 'flower-decorators';
                        $desc = $lead->lead_description_flower;
                        $dbPrice = $lead->price_flower;
                        $eventCat = $lead->event_category_flower;

                    } elseif (in_array('venue', $packageTypes) && str_contains($spec, 'venue')) {
                        $matchedCat = 'venue';
                        $desc = $lead->lead_description_venue;
                        $dbPrice = $lead->price_venue;
                        $eventCat = $lead->event_category_venue;

                    } elseif (in_array('wedding', $packageTypes)) {
                        $matchedCat = 'wedding';
                        $desc = $lead->lead_description;
                        $dbPrice = $lead->price;
                        $eventCat = $lead->event_category;

                    } else {
                        continue;
                    }

                    $today  = \Carbon\Carbon::today();
                    $expiry = \Carbon\Carbon::parse($lead->expiry_date)->startOfDay();

                    $cleanPrice = strtolower(trim($dbPrice));

                    /* ✅ HARD FREE LOCK */
                    if ($cleanPrice === 'free') {

                        $Payment_api = 0;
                        $price_to_pass = "Free Purchase";
                        $price_to_display = __('dashboard.buttons.free_purchase');
                        $button_label = __('dashboard.buttons.free_purchase');

                    } else {

                        $paid75Start = $expiry->copy()->addDays(1);
                        $paid75End   = $expiry->copy()->addDays(3);
                        $freeStart   = $expiry->copy()->addDays(4);
                        $freeEnd     = $expiry->copy()->addDays(6);

                        if ($today->lte($expiry)) {

                            $Payment_api = 1;
                            $price_to_pass = $dbPrice;
                            $price_to_display = "₹ {$dbPrice}/-";
                            $button_label = __('dashboard.buttons.buy_now');

                        } elseif ($today->between($paid75Start, $paid75End)) {

                            $Payment_api = 1;
                            $price_to_pass = "75";
                            $price_to_display = "₹ 75/-";
                            $button_label = __('dashboard.buttons.buy_now');

                        } elseif ($today->between($freeStart, $freeEnd)) {

                            $Payment_api = 0;
                            $price_to_pass = "Free Purchase";
                            $price_to_display = __('dashboard.buttons.free_purchase');
                            $button_label = __('dashboard.buttons.free_purchase');

                        } else {
                            continue;
                        }
                    }

                    $location = trim(($lead->event_location ?? '') . ', ' . ($lead->actual_state_tbl_name ?? ''), ', ');

                    $finalLeads[] = [
                        'lead_type' => __('dashboard.buy_leads'),
                        'id' => $lead->id,
                        'name' => t($lead->name),
                        'category' => __('dashboard.categories.' . $matchedCat),
                        'wedding_date' => $lead->event_date
                            ? \Carbon\Carbon::parse($lead->event_date)->format('d/m/Y')
                            : '-',

                        'lead_time' => $lead->lead_time,
                        'location' => translateText($location, app()->getLocale()),
                        'requirement' => translateText($eventCat, app()->getLocale()),
                        'additional_requirements' => translateLongText($desc),
                        'actual_lead_from_to_show' => $lead->actual_lead_from_to_show ?? '',
                        'enable_paynow_button' => 1,
                        'Payment_api' => $Payment_api,
                        'price_to_display' => $price_to_display,
                        'price_to_pass' => $price_to_pass,
                        'button_label' => $button_label,
                        'purchase_allowed' => 0,
                    ];
                }

                 $perPage = 15;
                $total = count($finalLeads);
                $pagedData = array_slice($finalLeads, ($page - 1) * $perPage, $perPage);


                return response()->json([
                    'status' => '1',
                    'message' => __('dashboard.buy_leads'),
                    'page_title' => $page_title,
                    'page_description' => $page_description,
                    'data' => [
                        'current_page' => $page,
                        'per_page' => $perPage,
                        'total' => $total,
                        'last_page' => ceil($total / $perPage),
                        'data' => $pagedData,
                    ],
                    'user_id' => $user->id,
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                    'base_url' => 'https://planawedding.in/storage/',
                ], 200);
            } 
        public function getstateweddingleads_1(Request $request)
            {
                $token = $request->header('Authorization');
                $user  = $this->getuser($token);

