                        'status' => '0',
                        'message' => t('User not found'),
                        'data' => []
                    ], 401);
                }

                $user_details = [
                    'name' => $user->name,
                    'email' => $user->email,
                    'mobile' => $user->mobile,
                    'business_name' => $user->business_name
                ];

                $user_role = $this->checkeditaccess($token)['role'] ?? '';

                /* ================= STATES ================= */

                $states = CustomerState::select('state_name')
                    ->where('state_status', 1)
                    ->orderBy('state_name', 'asc')
                    ->get()
                    ->map(function ($state) {
                        /*
                            $state->state_name = translateText($state->state_name, app()->getLocale());
                        */
                            $stateName = $state->state_name;
                            $lang = app()->getLocale();

                             
                            $state->state_name = trans("dashboard.$stateName") !== "dashboard.$stateName"? trans("dashboard.$stateName"): translateText($stateName, $lang);

                            return $state;
                    });

                /* ================= LEAD CATEGORIES ================= */

                $lead_category_labels = [
                    'Buy Lead',
                    'Package Lead',
                    'Reels Lead',
                    'Couple Lead',
