                foreach ($lead_category_labels as $label) {

                    $key = 'dashboard.lead_categories.' . $label;

                    $translatedLabel = __($key) !== $key
                        ? __($key)
                        : translateText($label, app()->getLocale());

                    $lead_category[] = [
                        'label' => $translatedLabel
                    ];
                }

                return response()->json([
                    'status' => '1',
                    'message' => __('dashboard.buy_leads'),
                    'page_title' => null,
                    'page_description' => null,
                    'data' => [
                        'states' => $states,
                        'lead_category' => $lead_category
                    ],
                    'user_id' => $user->id,
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                    'base_url' => 'https://planawedding.in/storage/',
                ], 200);
            }
