        public function paymentinitiateenhanced1_old(Request $request)
            {
                $token = $request->header('Authorization');
                $user = $this->getuser($token);

                if (!$user) {
                    return response()->json([
                        'message' => t('User not found'),
                        'status' => '0',
                        'page_title' => '',
                        'page_description' => '',
                        'data' => [],
                        'user_specialization' => '',
                        'buytype' => '',
                        'user_id' => "",
                        'user_role' => "",
                        'logged_in_user' => [],
                    ], 401);
                }

                // Subscription / Partner Check
                if ($user->chk_subscription != 1 || $user->is_partner != 1)
                {
                    return response()->json([
                        'message' => t('Access restricted. Subscription or Partner access required.'),
                        'status'  => '2',
                        'next_api' => 'no',
                        'allow_next_api' => '0',
                        'user_role' => '',
                        'logged_in_user' => [
                            'name' => $user->name,
                            'email' => $user->email,
                            'mobile' => $user->mobile,
                            'business_name' => $user->business_name
                        ],
                    ], 200);
                }

                // Allowed User
                $allow_next_api = "1";

                $validator = Validator::make($request->all(), [
                    'itemid' => 'required|integer',
                ]);
                
                if ($validator->fails()) {
                    $messages = $validator->messages()->toArray();
                
                    $translatedMessages = [];

                    foreach ($messages as $field => $errs) {
                        foreach ($errs as $err) {
                            $translatedMessages[$field][] = t($err);
                        }
                    }
                    return response()->json([
                        'message' => $translatedMessages,
                        'status'  => '0',
                        'allow_next_api' => $allow_next_api
                    ], 422);
                }

                $lead_id = $request->itemid;
                $lead = GeneralLead::find($lead_id);

                if (!$lead) {
                    return response()->json([
                        'message' => t('Lead not found'),
                        'status'  => '0',
                        'allow_next_api' => $allow_next_api
                    ], 404);
                }

                // User role and details
                $useraccess = $this->checkeditaccess($token);
                $user_role = $useraccess['role'];
                $user_details = [
                    'name' => $user->name,
                    'email' => $user->email,
                    'mobile' => $user->mobile,
                    'business_name' => $user->business_name
                ];

                // Date Logic
                $todayDate = \Carbon\Carbon::today();
                $threeDaysAgo = $todayDate->copy()->subDays(3);
                $sixDaysAgo = $todayDate->copy()->subDays(6);

                if (empty($lead->expiry_date)) {
                    return response()->json([
                        'message' => t('Lead has invalid expiry date'),
                        'status' => '0',
                        'next_api' => 'no',
                        'allow_next_api' => $allow_next_api
                    ], 200);
                }

                $expiry = \Carbon\Carbon::parse($lead->expiry_date)->startOfDay();

                $isFree = false;
                $next_api = "yes";

                $category_price_value = preg_replace('/[^0-9.]/', '', $lead->price ?? '0');
                $actual_price = floatval($category_price_value);
                $actual_price_final = $actual_price;

                if ($expiry->gte($todayDate)) {
                    $isFree = false;
                    $price_to_pass = $actual_price_final;
                } elseif ($expiry->lt($todayDate) && $expiry->gte($threeDaysAgo)) {
                    $isFree = false;
                    $price_to_pass = 75;
                } elseif ($expiry->lt($threeDaysAgo) && $expiry->gte($sixDaysAgo)) {
                    $isFree = true;
                    $price_to_pass = "Free Purchase";
                    $next_api = "no";
                } else {
                    return response()->json([
                        'message' => t('Lead expired'),
                        'status'  => '0',
                        'next_api' => 'no',
                        'allow_next_api' => $allow_next_api
                    ], 200);
                }

                // Free Purchase Flow
                if ($isFree) {
                    $buytype = "Free Purchase";
                    $today = date('Y-m-d');

                    $freePurchasesToday = GeneralLeadBuy::where('user_id', $user->id)
                        ->where('price_purchase', 'Free Purchase')
                        ->whereDate('created_at', $today)
                        ->count();

                    if ($freePurchasesToday >= 3) {
                        return response()->json([
                            'message' => t('Your free purchase limit exceeded for today.'),
                            'status'  => '0',
                            'next_api' => 'no',
                            'payment' => '',
                            'leadbuy' => '',
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                            'allow_next_api' => $allow_next_api
                        ], 200);
                    }

                    $payment = new Payment();
                    $payment->user_id   = $user->id;
                    $payment->orderid   = "FreePurchase-" . $lead_id;
                    $payment->reference = '';
                    $payment->status    = 'success';
                    $lead->payments()->save($payment);

                    $leadbuy = new GeneralLeadBuy();
                    $leadbuy->general_leads_id = $lead->id;
                    $leadbuy->user_id = $payment->user_id;
                    $leadbuy->purchase_type = 'general';
                    $leadbuy->price_purchase = "Free Purchase";
                    $leadbuy->save();

                    return response()->json([
                        'message' => t('Free Purchase successful'),
                        'status'  => '1',
                        'next_api' => 'no',
                        'payment' => $payment,
                        'leadbuy' => $leadbuy,
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                        'base_url' => 'https://planawedding.in/storage/',
                        'allow_next_api' => $allow_next_api
                    ], 200);
                }

                // Paid Purchase Flow
                $orderid = 'Order-' . uniqid();

                $payment = new Payment();
                $payment->user_id   = $user->id;
                $payment->orderid   = $orderid;
                $payment->reference = '';
                $payment->status    = 'initiated';
                $lead->payments()->save($payment);

                return response()->json([
                    'message' => t('Payment Initiated'),
                    'status'  => '1',
                    'next_api' => $next_api,
                    'orderid' => $orderid,
                    'price_to_pass' => $price_to_pass,
                    'display_price' => is_numeric($price_to_pass) ? "₹ " . number_format($price_to_pass, 0) . "/-" : $price_to_pass,
                    'button_label' => 'Buy Now',
                    'lead_id' => $lead->id,
                    'user_id' => $user->id,
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                    'base_url' => 'https://planawedding.in/storage/',
                    'allow_next_api' => $allow_next_api
                ], 200);
            }

