        private function initiatetransaction($cus_mobile,$cusId,$amountpaypable,$orderid,$callBackUrl)
            { 
                $paytmParams = array();
            
                $paytmParams["body"] = array(
                    "requestType" => "Payment",
                    "mid" => "aUrqBh85345734866262",
                    "websiteName" => "DEFAULT",
                    "orderId" => "$orderid",
                    "callbackUrl" => "$callBackUrl",
                    "txnAmount" => array(
                        "value" => "$amountpaypable",
                        "currency" => "INR",
                    ),
                    "userInfo" => array(
                        "custId" => "$cusId",
                    ),
                );
                
                /*
                * Generate checksum by parameters we have in body
                * Find your Merchant Key in your Paytm Dashboard at https://dashboard.paytm.com/next/apikeys
                */
                $checksum = $this->generateSignature(json_encode($paytmParams["body"], JSON_UNESCAPED_SLASHES), "X_b1mPyvIOMp@ry0");
                
                $paytmParams["head"] = array(
                    "signature" => $checksum
                );
                
                $post_data = json_encode($paytmParams, JSON_UNESCAPED_SLASHES);
                
                /* for Staging */
                //$url = "https://securegw-stage.paytm.in/theia/api/v1/initiateTransaction?mid=YOUR_MID_HERE&orderId=ORDERID_98765";
                
                /* for Production */
                /*
                    $url = "https://securegw.paytm.in/theia/api/v1/initiateTransaction?mid=aUrqBh85345734866262&orderId=$orderid";
                */

                    $url = "https://secure.paytmpayments.com/theia/api/v1/initiateTransaction?mid=aUrqBh85345734866262&orderId=$orderid";
                $ch = curl_init($url);
                curl_setopt($ch, CURLOPT_POST, 1);
                curl_setopt($ch, CURLOPT_POSTFIELDS, $post_data);
                curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
                curl_setopt($ch, CURLOPT_HTTPHEADER, array("Content-Type: application/json"));
                $response = curl_exec($ch);
                return $response;
            }


