        public function resetleadspayment(Request $request)
            {
                $token = $request->header('Authorization');
                $user = $this->getuser($token);
                
                if($user) 
                {
                    $user_details = ['name' => $user->name,'email' => $user->email,'mobile' => $user->mobile,'business_name' => $user->business_name];
                    
                    $useraccess = $this->checkeditaccess($token);
                    
                    $user_role = $useraccess['role'];
                    $user_access_array = $useraccess['access_array'];

                    if($user_role == 'partner admin' || $user_role == 'admin')
                    {
                        // Validations
                        $rules = [
                            'itemid' => 'required|numeric',
                        ];
                        
                        $validator = Validator::make($request->all(), $rules);
                
                        if ($validator->fails()) 
                        {
                            $messages = $validator->messages()->toArray();
                            $translatedMessages = [];

                            foreach ($messages as $field => $errs) {
                                foreach ($errs as $err) {
                                    $translatedMessages[$field][] = t($err);
                                }
                            }

                            return response()->json([
                                'message' => $translatedMessages,
                                'status'  => '0',
                            ], 422);
                        }
                        else
                        {
                            $itemid = $request->itemid;
                            $lead = GeneralLead::whereId($itemid)->first();
                                
                            if($lead)
                            {
                                $lead->payment_initiated = 0;
                                $lead->save();
                                
                                return response()->json([
                                    'message' => t('Lead Reset Scuccessfuly'),
                                    'status' => '1',
                                    'data' => $lead,
                                    'user_role' => $user_role,
                                    'logged_in_user' => $user_details,
                                ], 200);
                            }
                            else
                            {
                                return response()->json([
                                    'message' => t('Lead not found'),
                                    'status' => '0',
                                    'data' => [],
                                    'user_role' => $user_role,
                                    'logged_in_user' => $user_details,
                                ], 200);
                            }
                        }
                    }
                    else 
                    {
                        return response()->json([
                            'message' => t('User do not have access'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 401);
                    }
                } 
                else 
                {
                    return response()->json([
                        'message' => t('User not found'),
                        'status' => '0',
                        'data' => [],
                        'user_role' => "",
                        'logged_in_user' => [],
                    ], 401);
                }
            } 

