                            else 
                                {
                                    $newcrm = new CrmCounter();
                                        
                                    $newcrm->page_name = $pagename;
        
                                    $newcrm->planner_id  = $planner_actual_id;
                                    $newcrm->planner_team_id  = $planner_actual_team_id;
                                    $newcrm->planner_main_id   = $planner_main_id;
                                    $newcrm->planner_business_name  = $planner_buiness_name;
                                    $newcrm->planner_name  = $planner_name;
                                    $newcrm->planner_mobile  = $planner_mobile;
                                    $newcrm->planner_role  = $palnner_role;
                                    $newcrm->planner_subscriptions  = $planner_subscriptions;
                                    $newcrm->no_of_visti_times  = $visitcount;
                                    $newcrm->recent_visit  = $recent_visit;
                                    $newcrm->planner_state  = $planner_state;
                                    $newcrm->planner_city  = $planner_city;
        
                                    $newcrm->save(); 
                                        
                                }    
        
                        /* CRM Ends*/ 
                        
                        if ($leads_data && app()->getLocale() !== 'en') {

                            $leads_data->getCollection()->transform(function ($lead) {

                                // Simple fields
                                $lead->name = transliterateTextKeepNumbers($lead->name);
                                $lead->city = translateCity($lead->city);
                                $lead->event_location = translateVenueLocation($lead->event_location);

                                // event_category (same as other function)
                                if (!empty($lead->event_category)) {
                                    $lead->event_category = __('dashboard.categories.' . strtolower($lead->event_category));
                                }

                                // package_type (comma separated)
                                if (!empty($lead->package_type)) {
                                    $items = explode(',', $lead->package_type);
                                    $lead->package_type = collect($items)->map(function ($item) {
                                        return __('dashboard.categories.' . strtolower(trim($item)));
                                    })->implode(', ');
                                }

                                // Long descriptions
                                $fields = [
                                    'lead_description',
                                    'lead_description_makeup',
                                    'lead_description_photovideo',
                                    'lead_description_catering',
                                    'lead_description_flower',
                                    'lead_description_mehendi',
                                    'lead_description_priests',
                                    'lead_description_dj',
                                    'lead_description_venue',
                                    'lead_description_jewellers',
                                    'lead_description_weddingwear',
                                ];

                                foreach ($fields as $field) {
                                    if (!empty($lead->$field)) {
                                        $lead->$field = translateLongText($lead->$field);
                                    }
                                }

                                // new_noteremarks (Unicode FIX INCLUDED)
                                if (!empty($lead->new_noteremarks)) {

                                    $remarks = json_decode($lead->new_noteremarks, true);

                                    if (is_array($remarks)) {
                                        foreach ($remarks as &$remark) {
                                            if (!empty($remark['remarkcolumn'])) {
                                                $remark['remarkcolumn'] = t($remark['remarkcolumn']);
                                            }
                                        }
                                        $lead->new_noteremarks = json_encode($remarks, JSON_UNESCAPED_UNICODE);
                                    }
                                }

                                return $lead;
                            });
                        }

                        return response()->json([
                            'message' => __('dashboard.my_leads'),
                            'status' => '1',
                            'page_title'        => $page_title,
                            'page_description'  => $page_description,
                            'show_add_leads_button' => $show_add_leads_button, 
                            'wedding_date_dropdown' => $wedding_date_dropdown, 
                            'sources_from_dropdown' => $sources_from_dropdown, 
