        public function updatemyleads(Request $request)
            {
                $token = $request->header('Authorization');
                $user = $this->getuser($token);
                
                if($user) 
                {
                    $managebypawrole = $user->manageby_pawrole;
                    
                    $user_details = ['name' => $user->name,'email' => $user->email,'mobile' => $user->mobile,'business_name' => $user->business_name];
                    
                    $useraccess = $this->checkeditaccess($token);
                    $user_role = $useraccess['role'];
                    $user_access_array = $useraccess['access_array'];
                    
                    $users = [];

                    $team_id = $user->team_id;

                    if($team_id == null)
                    {
                        $team_members = User::where('team_id',$user->id)->where('is_active',1)->select('id')->get()->pluck('id')->toArray();
                    }
                    else
                    {
                        $team_members = User::where('team_id',$user->team_id)->where('is_active',1)->select('id')->get()->pluck('id')->toArray();
                    }

                    if(!empty($request->status))
                    {
