         public function getmypackages(Request $request)
            {
                $token = $request->header('Authorization');
                $user = $this->getuser($token);

                if (!$user) {
                    return response()->json([
                        'message' => t('User not found'),
                        'status' => '0',
                        'data' => [],
                        'user_role' => "",
                        'logged_in_user' => [],
                    ], 401);
                }

                $user_details = [
                    'name' => $user->name,
                    'email' => $user->email,
                    'mobile' => $user->mobile,
                    'business_name' => $user->business_name
                ];

                $useraccess = $this->checkeditaccess($token);
                $user_role = $useraccess['role'];

                // 🌐 TRANSLATABLE HEADERS
                $page_heading = [
                    'show' => 1,
                    'name' => t('My Packages'),
                ];

                $pagecontent = [
                    'show' => 1,
                    'name' => t('Package Listings'),
                ];

                // 📦 FETCH PACKAGES
                $packages = WpplannerPackage::where('user_id', $user->id)
                    ->orderBy('id', 'desc')
                    ->paginate(10);

                // 🌐 TRANSLATE ONLY REQUIRED FIELDS (RESPONSE-ONLY)
                $packages->getCollection()->transform(function ($item) {

                    if (!empty($item->package_type)) {
                        $item->package_type = transliterateTextKeepNumbers($item->package_type);
                    }

                    if (!empty($item->package_city)) {
                        $item->package_city = translateCity($item->package_city);
                    }

                    if (!empty($item->package_description)) {
                        $item->package_description = t($item->package_description);
                    }

                    return $item;
                });

                $pawcode = $user->thcode;
                $packagewebsite = "https://planawedding.in/weddingpackages/$pawcode";

                return response()->json([
                    'message' => t('Packages list'),
                    'status' => '1',
                    'page_heading' => $page_heading,
                    'page_content' => $pagecontent,
                    'package_website' => $packagewebsite,
                    'data' => $packages,
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                    'base_url' => 'https://planawedding.in/storage/',
                ], 200);
            }

        public function getpackagestype(Request $request)
            {
                $mypackagestype = [
                    'Muhurat Package',
                    'Reception Package',
                    'Muhurat & Reception Package',
                    'Engagement Package',
                    'Destination Wedding',
                    'Photography Package',
                    'Videography Package',
                    'Photo & Videography Package',
                    'Catering Package',
                    'Bridal Makeup Package'
                ];

                // 🌐 Transform to value + display_text (response-only)
                $data = collect($mypackagestype)->map(function ($item) {
                    return [
                        'value' => $item,
                        'display_text' => domainTranslatePure($item),
                    ];
                })->values();

                return response()->json([
                    'message' => t('Supported Packages Type'),
                    'status' => '1',
                    'data' => $data,
                ], 200);
            }
