                        'value' => $item,
                        'display_text' => transliterateTextKeepNumbers($item),
                    ];
                })->values();

                return response()->json([
                    'message' => t('Packages Essentials'),
                    'status' => '1',
                    'data' => $data,
                ], 200);
            }
        public function addmypackages(Request $request)
            {
                $token = $request->header('Authorization');
                $user = $this->getuser($token);

                if(!$user) {
                    return response()->json([
                        'message' => t('User not found'),
                        'status' => '0',
                        'data' => [],
                        'user_role' => "",
                        'logged_in_user' => [],
                    ], 401);
                }

                $user_details = [
                    'name' => $user->name,
                    'email' => $user->email,
                    'mobile' => $user->mobile,
                    'business_name' => $user->business_name
                ];

                $useraccess = $this->checkeditaccess($token);
                $user_role  = $useraccess['role'];

                // -----------------------------
                // VALIDATION (image optional)
                // -----------------------------
                $rules = [
                    'package_type' => 'required|in:Muhurat Package,Reception Package,Muhurat & Reception Package,Engagement Package,Destination Wedding,Photography Package,Videography Package,Photo & Videography Package,Catering Package,Bridal Makeup Package',
                    'package_amount' => 'required|numeric',
                    'listeditems' => 'required',
                    //'package_image' => 'nullable|file', // 🔥 OPTIONAL NOW
                    "package_pax" => "required_if:package_type,Muhurat Package,Muhurat & Reception Package",
                    "reception_pax" => "required_if:package_type,Reception Package,Muhurat & Reception Package",
                    "engagement_pax" => "required_if:package_type,Engagement Package",
                    "destination_city" => "required_if:package_type,Destination Wedding",
                    "package_pax1" => "required_if:package_type,Destination Wedding",
                    "reception_pax1" => "required_if:package_type,Destination Wedding",
                    "catering_pax1" => "required_if:package_type,Catering Package",
                ];

                $error = Validator::make($request->all(), $rules);

                if($error->fails()) {
                    $errors = $error->errors()->toArray();

                                // 🌐 Translate each validation message
                                foreach ($errors as $field => &$messages) {
                                    foreach ($messages as &$msg) {
                                        $msg = t($msg);
                                    }
                                }

                                return response()->json([
                                    'message' => $errors,
                                ], 422);
                }

                // -----------------------------
                // PROCESS INPUTS
                // -----------------------------
                $package_type = ($request->package_type == "Photo & Videography Package")
                    ? "PhotoandVideography Package"
                    : $request->package_type;

                $package_city   = $request->package_city;
                $package_amount = $request->package_amount;

                $engagement_pax = $request->engagement_pax ?? NULL;
                $package_pax    = $request->package_pax1 ?? $request->package_pax ?? NULL;
                $reception_pax  = $request->reception_pax1 ?? $request->reception_pax ?? NULL;
                $catering_pax   = $request->catering_pax1 ?? NULL;

                // Destination Wedding override
                if ($package_type == "Destination Wedding") {
                    $package_city  = $request->destination_city ?? NULL;
                    $package_pax   = $request->package_pax1 ?? NULL;
                    $reception_pax = $request->reception_pax1 ?? NULL;
                }

                // Engagement override
                if ($package_type == "Engagement Package") {
                    $engagement_pax = $request->engagement_pax ?? NULL;
                }

                // Default additional remarks
                $addremarks = $request->addremarks ??
                    "Any Additional Services Requested Outside The Package Will Be Subject To Additional Charges.";

                $listeditems   = $request->listeditems;
                $mydateinsert  = date('d/m/Y');

                // -----------------------------
                // OPTIONAL FILE UPLOAD
                // -----------------------------
                $upload_location = "/home/gjymj6oxru2v/planawedding/storage/app/public/";
                $newfilename = null; // default if no image

                if ($request->hasFile('package_image')) {

                    $file = $request->file('package_image');
                    $originalName = $file->getClientOriginalName();

                    $temp = explode(".", $originalName);
                    $unique = time() . uniqid() . '.' . end($temp);

                    $newfilename = "weddingplannerpackage/" . strtolower($unique);

                    // move to storage folder
                    $file->move($upload_location . "weddingplannerpackage/", strtolower($unique));
                }

                // -----------------------------
                // SAVE PACKAGE
                // -----------------------------
                $data = new WpplannerPackage();

                $data->user_id               = $user->id;
                $data->package_type          = $package_type;
                $data->package_city          = $package_city;
                $data->package_amount        = $package_amount;
                $data->final_discount        = $request->package_discountamount;
                $data->wedding_pax           = $package_pax;
                $data->reception_pax         = $reception_pax;
                $data->package_description   = $listeditems;
                $data->package_image         = $newfilename; // 🔥 NULL allowed
                $data->uploaded_date         = $mydateinsert;
                $data->engagement_pax        = $engagement_pax;
                $data->additonal_remarks     = $addremarks;
                $data->catering_pax          = $catering_pax;

                if ($data->save()) {

                    // 🌐 RESPONSE-ONLY TRANSLATION
                    $data->package_type = t($data->package_type);

                    if (!empty($data->package_description)) {
                        $data->package_description = collect(
                            explode(',', $data->package_description)
                        )->map(function ($item) {
                            return t(trim($item));
                        })->implode(', ');
                    }
                    return response()->json([
                        'message' => t('Package added'),
                        'status'  => '1',
                        'data'    => $data,
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                        'base_url' => 'https://planawedding.in/storage/',
                    ], 201);
                }

                return response()->json([
                    'message' => t('Issues in Package addition'),
                    'status'  => '0',
                    'data'    => [],
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                    'base_url' => 'https://planawedding.in/storage/',
                ], 304);
            }
