        public function getBiteTags_1(Request $request)
            {
                $token = $request->header('Authorization');
                $user  = $this->getuser($token);

                if (!$user) {
                    return response()->json([
                        'success' => false,
                        'message' => t('Unauthorized. Please login again.')
                    ], 401);
                }

                $defaultTags = [
                    'Muhurat',
                    'Marriage',
                    'Reception',
                    'Mehandi',
                    'End-to-End Wedding',
                    'Venue',
                    'Sangeeth',
                    'Bridal Makeup',
                    'Catering',
                ];

                $specialization = strtolower($user->specialization ?? '');

                if (str_contains($specialization, 'wedding') || str_contains($specialization, 'venue')) {
                    $tags = $defaultTags;
                } else {
                    $tags = array_map('trim', explode(',', $user->specialization));
                }

                // 🌐 Transform tags → value + display_text
                $tags = collect($tags)->map(function ($tag) {
                    return [
                        'value' => $tag,
                        'display_text' => domainTranslate($tag),
                    ];
                })->values();

                return response()->json([
                    'success' => true,
                    'tags' => $tags,
                    'logged_in_user' => [
                        'userid'   => $user->id,
                        'name'     => $user->name,
                        'email'    => $user->email,
                        'mobile'   => $user->mobile,
                        'specialization' => $user->specialization
                    ],
                    'base_path' => 'https://planawedding.in/storage/'
                ], 200);
            }

