        public function listbites(Request $request) 
            {
                $token = $request->header('Authorization');
                $user  = $this->getuser($token);

                if (!$user) {
                    return response()->json([
                        'success' => false,
                        'message' => t('Unauthorized'),
                        'logged_in_user' => [],
                        'base_url' => 'https://planawedding.in/storage/'
                    ], 401);
                }

                $baseUrl = 'https://planawedding.in/storage/';

                /* =====================================================
                FETCH ALL REELS (LATEST FIRST)
                ===================================================== */

                $rows = DB::table('reel_bites')
                    ->where('user_id', $user->id)
                    ->orderBy('id', 'desc')
                    ->get();

                $inReview = [];
                $approved = [];
                $rejected = [];

                foreach ($rows as $row) {

                    $item = [
                        'reel_bite_id'   => $row->id,
                        'video_url'     => $baseUrl . $row->video_path,
                        'thumbnail_url' => $baseUrl . $row->thumbnail_path,
                        'video_duration'=> $row->video_duration,
                        /*'tags'          => json_decode($row->tags, true),*/
                        'tags' => collect(json_decode($row->tags, true))->map(function ($tag) {
                            return [
                                'value' => $tag,
                                'display_text' => domainTranslate($tag),
                            ];
                        })->values(),
                    ];

                    /* ===============================
                    IN REVIEW (status = 0)
                    =============================== */
                    if ($row->status == 0) {

                        $item['comment_title']   = 'In Review';
                        $item['comment_content'] =
                            'Your video is under review and will be available once approved';

                        $inReview[] = $item;
                    }

                    /* ===============================
                    APPROVED (status = 1)
                    =============================== */
                    elseif ($row->status == 1) {

                        // ✅ COUNT LIKES
                        $likesCount = DB::table('reel_bite_likes')
                            ->where('reel_bite_id', $row->id)
                            ->count();

                        $item['likes_count'] = $likesCount;

                        $approved[] = $item;
                    }

                    /* ===============================
                    REJECTED (status = 2)
                    =============================== */
                    elseif ($row->status == 2) {

                        $item['comment_title']   = 'Rejected';
                        $item['comment_content'] =
                            'Due to ' . ($row->reason ?? 'policy violation');

                        $rejected[] = $item;
                    }
                }

                /* =====================================================
                RESPONSE
                ===================================================== */

                return response()->json([
                    'success' => true,
                    'message' => t('Reel bites listed successfully'),
                    'data' => [
                        'in_review' => $inReview,
                        'approved'  => $approved,
                        'rejected'  => $rejected,
                    ],
                    'logged_in_user' => [
                        'userid' => $user->id,
                        'name'   => $user->name,
                        'mobile' => $user->mobile,
                    ],
                    'base_url' => $baseUrl
                ], 200);
            }
        public function deleteBites(Request $request)
            {
                $token = $request->header('Authorization');
                $user  = $this->getuser($token);

                if (!$user) {
                    return response()->json([
                        'success' => false,
                        'message' => t('Unauthorized')
                    ], 401);
                }

                /* =====================================================
                NORMALIZE bite_ids (string | int | array → array)
                ===================================================== */

                if (!$request->has('bite_ids')) {
                    return response()->json([
                        'success' => false,
                        'message' => t('bite_ids is required')
                    ], 422);
                }

                $biteIdsInput = $request->bite_ids;

                if (is_array($biteIdsInput)) {
                    $biteIds = $biteIdsInput;
                }
                elseif (is_string($biteIdsInput)) {
                    // "6,7,8" → [6,7,8]
                    $biteIds = array_filter(
                        array_map('intval', explode(',', $biteIdsInput))
                    );
                }
                else {
                    // single number like 6
                    $biteIds = [(int)$biteIdsInput];
                }

                if (empty($biteIds)) {
                    return response()->json([
                        'success' => false,
                        'message' => t('Invalid bite_ids')
                    ], 422);
                }

                /* =====================================================
                FETCH ONLY USER OWNED BITES
                ===================================================== */

                $bites = DB::table('reel_bites')
                    ->whereIn('id', $biteIds)
                    ->where('user_id', $user->id) // 🔒 ownership check
                    ->get();

                if ($bites->isEmpty()) {
                    return response()->json([
                        'success' => false,
                        'message' => t('No valid reel bites found to delete')
                    ], 404);
                }

                $deletedIds = [];
                $foundIds   = $bites->pluck('id')->toArray();
                $skippedIds = array_values(array_diff($biteIds, $foundIds));

                /* =====================================================
                DELETE FILES + DB RECORDS
                ===================================================== */

                foreach ($bites as $bite) {

                    if (!empty($bite->video_path)) {
                        $videoPath = storage_path('app/public/' . $bite->video_path);
                        if (file_exists($videoPath)) {
                            @unlink($videoPath);
                        }
                    }

                    if (!empty($bite->thumbnail_path)) {
                        $thumbPath = storage_path('app/public/' . $bite->thumbnail_path);
                        if (file_exists($thumbPath)) {
                            @unlink($thumbPath);
                        }
                    }

                    $deletedIds[] = $bite->id;
                }

                DB::table('reel_bites')
                    ->whereIn('id', $deletedIds)
                    ->delete();

                /* =====================================================
                RESPONSE
                ===================================================== */

                return response()->json([
                    'success' => true,
                    'message' => t('Reel bites deleted successfully'),
                    'data' => [
                        'deleted_ids' => $deletedIds,
                        'skipped_ids' => $skippedIds
                    ],
                    'logged_in_user' => [
                        'userid' => $user->id,
                        'name'   => $user->name,
                        'mobile' => $user->mobile,
                    ],
                    'base_url' => 'https://planawedding.in/storage/'
                ], 200);
            }
        public function uploadbites(Request $request)
            {
                $token = $request->header('Authorization');
                $user  = $this->getuser($token);

                if (!$user) {
                    return response()->json([
                        'success' => false,
                        'message' => t('Unauthorized')
                    ], 401);
                }

                $validator = Validator::make($request->all(), [
                    'video' => 'required|file|mimes:mp4,mov|max:204800', // 200 MB
                ]);

                $errors = $validator->errors()->toArray();

                // 🌐 Translate each validation message
                foreach ($errors as $field => &$messages) {
                    foreach ($messages as &$msg) {
                        $msg = t($msg);
                    }
                }
                if ($validator->fails()) {
                    return response()->json([
                        'success' => false,
                            'message' => $errors,
                    ], 422);
                }

                $file = $request->file('video');

                $originalName = $file->getClientOriginalName();
                $extension    = strtolower($file->getClientOriginalExtension());

                // ✅ Convert filename (safe)
                $convertedName = 'bite_' . $user->id . '_' . time() . '.' . $extension;

                $basePath = storage_path('app/public/reelbites/' . $user->id . '/temp');

                if (!file_exists($basePath)) {
                    mkdir($basePath, 0755, true);
                }

                $videoPath = $basePath . '/' . $convertedName;
                $file->move($basePath, $convertedName);

                /* ===============================
                🎬 CHECK VIDEO DURATION (≤ 60s)
                =============================== */

                $cmd = "ffprobe -v error -show_entries format=duration "
                    . "-of default=noprint_wrappers=1:nokey=1 "
                    . escapeshellarg($videoPath);

                $duration = (int) floor(shell_exec($cmd));

                if ($duration > 60) {
                    @unlink($videoPath);
                    return response()->json([
                        'success' => false,
                        'message' => t('Video duration must be maximum 1 minute')
                    ], 422);
                }

                /* ===============================
                🖼️ EXTRACT FIRST FRAME
                =============================== */

                $thumbName = 'thumb_' . pathinfo($convertedName, PATHINFO_FILENAME) . '.jpg';
                $thumbPath = $basePath . '/' . $thumbName;

                $thumbCmd = "ffmpeg -y -i "
                        . escapeshellarg($videoPath)
                        . " -ss 00:00:01 -vframes 1 "
                        . escapeshellarg($thumbPath) . " 2>&1";

                shell_exec($thumbCmd);

                if (!file_exists($thumbPath)) {
                    @unlink($videoPath);
                    return response()->json([
                        'success' => false,
                        'message' => t('Failed to generate video thumbnail')
                    ], 500);
                }

                /* ===============================
                💾 SAVE TEMP PREVIEW RECORD
                =============================== */

                $previewId = DB::table('reel_bites_previews')->insertGetId([
                    'user_id'            => $user->id,
                    'original_filename'  => $originalName,
                    'converted_filename' => $convertedName,
                    'video_path'         => 'reelbites/' . $user->id . '/temp/' . $convertedName,
                    'thumbnail_path'     => 'reelbites/' . $user->id . '/temp/' . $thumbName,
                    'file_size_mb'       => round(filesize($videoPath) / 1048576, 2),
                    'duration_seconds'   => $duration,
                    'created_at'         => now(),
                    'updated_at'         => now(),
                ]);

                return response()->json([
                    'success' => true,
                    'message' => t('Video preview generated successfully'),
                    'data' => [
                        'preview_id' => $previewId,
                        'thumbnail_url' => asset('storage/reelbites/' . $user->id . '/temp/' . $thumbName),
                        'video_url'     => asset('storage/reelbites/' . $user->id . '/temp/' . $convertedName),
                        'duration'      => $duration . ' sec'
                    ],
                    'logged_in_user' => [
                        'userid' => $user->id,
                        'name'   => $user->name,
                        'mobile' => $user->mobile
                    ],
                    'base_url' => 'https://planawedding.in/storage/'
                ], 200);
            }
        public function savebites(Request $request)
            {
                $token = $request->header('Authorization');
                $user  = $this->getuser($token);

                if (!$user) {
                    return response()->json([
                        'success' => false,
                        'message' => t('Unauthorized')
                    ], 401);
                }

                /* =====================================================
                NORMALIZE TAGS (STRING → ARRAY)
                Accepts: "Reception, Mehandi"
                ===================================================== */

                if ($request->has('tags') && is_string($request->tags)) {
                    $tagsArray = array_filter(array_map('trim', explode(',', $request->tags)));
                    $request->merge(['tags' => $tagsArray]);
                }

                /* =====================================================
                VALIDATION
                ===================================================== */

                $validator = Validator::make($request->all(), [
                    'preview_id' => 'required|integer|exists:reel_bites_previews,id',
                    'tags'       => 'required|array|min:1',
                    'tags.*'     => 'string'
                ]);
                $errors = $validator->errors()->toArray();
                // 🌐 Translate each validation message
                foreach ($errors as $field => &$messages) {
                    foreach ($messages as &$msg) {
                        $msg = t($msg);
                    }
                }
                if ($validator->fails()) {
                    return response()->json([
                        'success' => false,
                        'message' => $errors, 
                    ], 422);
                }

                /* =====================================================
                FETCH PREVIEW (OWNERSHIP CHECK)
                ===================================================== */

                $preview = DB::table('reel_bites_previews')
                    ->where('id', $request->preview_id)
                    ->where('user_id', $user->id)
                    ->first();

                if (!$preview) {
                    return response()->json([
                        'success' => false,
                        'message' => t('Preview not found or access denied')
                    ], 404);
                }

                /* =====================================================
                TAG RESOLUTION (ONLY SELECTED TAGS)
                ===================================================== */

                if (
                    stripos($user->specialization, 'wedding') !== false ||
                    stripos($user->specialization, 'venue') !== false
                ) {
                    // ✅ Wedding / Venue → save ONLY what user selected
                    $tags = $request->tags;
                } else {
                    // ✅ Other vendors → force specialization
                    $tags = [$user->specialization];
                }

                if (empty($tags)) {
                    return response()->json([
                        'success' => false,
                        'message' => t('At least one tag must be selected')
                    ], 422);
                }

                /* =====================================================
                FILE PATH SETUP
                ===================================================== */

                $userId = $user->id;

                $tempVideoPath = storage_path('app/public/' . $preview->video_path);
                $tempThumbPath = storage_path('app/public/' . $preview->thumbnail_path);

                if (!file_exists($tempVideoPath) || !file_exists($tempThumbPath)) {
                    return response()->json([
                        'success' => false,
                        'message' => t('Temporary files missing')
                    ], 404);
                }

                $finalDir = storage_path("app/public/reelbites/{$userId}");

                if (!file_exists($finalDir)) {
                    mkdir($finalDir, 0755, true);
                }

                $finalVideoName = $preview->converted_filename;
                $finalThumbName = basename($preview->thumbnail_path);

                $finalVideoPath = $finalDir . '/' . $finalVideoName;
                $finalThumbPath = $finalDir . '/' . $finalThumbName;

                /* =====================================================
                MOVE FILES (TEMP → FINAL)
                ===================================================== */

                rename($tempVideoPath, $finalVideoPath);
                rename($tempThumbPath, $finalThumbPath);

                $videoDbPath = "reelbites/{$userId}/{$finalVideoName}";
                $thumbDbPath = "reelbites/{$userId}/{$finalThumbName}";

                /* =====================================================
                INSERT INTO reel_bites
                ===================================================== */

                $biteId = DB::table('reel_bites')->insertGetId([
                    'user_id'             => $userId,
                    'video_path'          => $videoDbPath,
                    'thumbnail_path'      => $thumbDbPath,
                    'video_original_name' => $preview->original_filename,
                    'video_mime'          => mime_content_type($finalVideoPath),
                    'video_size'          => $preview->file_size_mb,
                    'video_duration'      => $preview->duration_seconds,
                    'tags'                => json_encode(array_values($tags)),
                    'status'              => 0, // 🔥 IN REVIEW
                    'created_at'          => now(),
                    'updated_at'          => now(),
                ]);

                /* =====================================================
                DELETE TEMP PREVIEW ROW
                ===================================================== */

                DB::table('reel_bites_previews')
                    ->where('id', $preview->id)
                    ->delete();

                /* =====================================================
                RESPONSE
                ===================================================== */

                return response()->json([
                    'success' => true,
                    'message' => t('Reel bite saved successfully'),
                    'data' => [
                        'reel_bite_id'  => $biteId,
                        'video_url'     => 'https://planawedding.in/storage/' . $videoDbPath,
                        'thumbnail_url' => 'https://planawedding.in/storage/' . $thumbDbPath,
                        'status'        => 0
                    ],
                    'logged_in_user' => [
                        'userid' => $user->id,
                        'name'   => $user->name,
                        'mobile' => $user->mobile,
                    ],
                    'base_url' => 'https://planawedding.in/storage/'
                ], 200);
            }    
    /* bites ends */

