                        }

                        if (!empty($item->mapped_state_name)) {
                            $item->mapped_state_name = translateState($item->mapped_state_name);
                        }

                        if (!empty($item->mapped_city_name)) {
                            $item->mapped_city_name = translateCity($item->mapped_city_name);
                        }

                        if (!empty($item->location_display)) {
                            $item->location_display = translateCity($item->location_display);
                        }
                        if (!empty($item->venue_location)) {
                            $item->venue_location = translateVenueLocation($item->venue_location);
                        }
                        return $item;
                    });
                }

                /* ============================================================
                RESPONSE
                ============================================================ */
                return response()->json([
                    'message'        => t('Venue Details'),
                    'status'         => '1',
                    'page_heading'   => [
                        'show' => 1,
                        'name' => t('Explore Our Budget Friendly Wedding Venues Tailored to Suit Every Need')
                    ],
                    'page_content'   => [
                        'show' => 1,
                        'name' => t('Engagement ,Muhurat ,Reception ,Destination Wedding and more...')
                    ],
                    'data'           => ['subthemes_data' => $subthemes_data],
                    'total_counts'   => $total_counts,
                    'user_role'      => $user_role,
                    'logged_in_user' => $user_details,
                    'base_url'       => 'https://planawedding.in/storage/',
                ], 200);
            }  
