                $user_role  = $useraccess['role'];

                // --------------------------------------------------
                // FETCH STATES
                // --------------------------------------------------
                $venuestates = VenueList::select('mapped_state_name')
                    ->join('users','venue_lists.user_id','=','users.id')
                    ->where('users.display_venue_web','yes')
                    ->where('venue_lists.show_web','1')
