    /* Photo sharing starts */
        public function listweddingdetails(Request $request, $id = null)
                {
                    $token = $request->header('Authorization');
                    $user  = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                            'success' => false,
                            'message' => t('Unauthorized. Please login again.')
                        ], 401);
                    }

                    $useraccess = $this->checkeditaccess($token);
                    $user_role  = $useraccess['role'];

                    $user_details = [
                        'name'          => $user->name,
                        'email'         => $user->email,
                        'mobile'        => $user->mobile,
                        'business_name' => $user->business_name
                    ];

                    try {
                        date_default_timezone_set('Asia/Kolkata');

                        $today        = new \DateTime('now', new \DateTimeZone('Asia/Kolkata'));
                        $current_date = $today->format('d/m/Y');

                        $perPage = $request->get('per_page', 10);
                        $search  = $request->search;


                        $search = trim($search);

                        $isNumericSearch = ctype_digit($search);
                        $isMobileSearch  = $isNumericSearch && strlen($search) >= 9;
                        $isDaysSearch    = $isNumericSearch && strlen($search) <= 2;

                        /* -------------------------------
                        BASE QUERY
                        --------------------------------*/
                        $query = DB::table('wedding_details')
                            ->where('user_id', $user->id);

                        // If ID passed in URL
                        if (!empty($id)) {
                            $query->where('id', $id);
                        }

                        /* -------------------------------
                        TEXT SEARCH (DB FIELDS ONLY)
                        --------------------------------*/
                          

                            if (!empty($search)) {

                                // TEXT SEARCH
                                if (!$isNumericSearch) {

                                    $query->where(function ($q) use ($search) {
                                        $q->where('groom_name', 'LIKE', "%$search%")
                                        ->orWhere('bride_name', 'LIKE', "%$search%")
                                        ->orWhere('date_of_wedding', 'LIKE', "%$search%")
                                        ->orWhere('wedding_location', 'LIKE', "%$search%")
                                        ->orWhere('mobile_number', 'LIKE', "%$search%");
                                    });

                                }
                                // MOBILE NUMBER SEARCH
                                elseif ($isMobileSearch) {

                                    $query->where('mobile_number', 'LIKE', "%$search%");
                                }
                            }

                        /* -------------------------------
                        PAGINATION
                        --------------------------------*/
                        $paginated = $query
                            ->select(
                                'id',
                                'groom_name',
                                'bride_name',
                                'date_of_wedding',
                                'wedding_location',
                                'mobile_number',
                                'event_created',
                                'planner_qr_path',
                                'planner_url',
                                'guest_qr_path',
                                'guest_pdf_path'
                            )
                            ->orderBy('id', 'DESC')
                            ->paginate($perPage);

                        /* -------------------------------
                        DAYS REMAINING CALCULATION
                        --------------------------------*/
                        $finalData = [];

                        foreach ($paginated->items() as $wedding) {

                            if (empty($wedding->event_created)) {
                                continue;
                            }

                            $eventDate = \DateTime::createFromFormat(
                                'd/m/Y',
                                $wedding->event_created,
                                new \DateTimeZone('Asia/Kolkata')
                            );

                            if (!$eventDate) {
                                continue;
                            }

                            // Signed difference (past = positive, future = negative)
                            $daysPassed = (int) $eventDate->diff($today)->format('%r%a');

                            // ❌ Skip future dates
                            if ($daysPassed < 0) {
                                continue;
                            }

                            // ✅ 30-day countdown
                            $daysRemaining = 30 - $daysPassed;

                            // ❌ Skip expired
                            if ($daysRemaining <= 0) {
                                continue;
                            }

                            
                            
                            
                            /*
                                // 🔍 SEARCH ON days_remaining (numeric)
                                if (!empty($search) && is_numeric($search)) {
                                    if ((int)$search !== $daysRemaining) {
                                        continue;
                                    }
                                }
                            */

                            if (!empty($search) && $isDaysSearch) {
                                if ((int)$search !== $daysRemaining) {
                                    continue;
                                }
                            }

                            $finalData[] = [
                                'id'               => $wedding->id,
                                'groom_name'       =>  transliterateTextKeepNumbers($wedding->groom_name),
                                'bride_name'       =>  transliterateTextKeepNumbers($wedding->bride_name),
                                'date_of_wedding'  => $wedding->date_of_wedding,
                                'wedding_location' => translateVenueLocation($wedding->wedding_location),
                                'mobile_number'    => $wedding->mobile_number,
                                'event_created'    => $wedding->event_created,
                                'days_remaining'   => $daysRemaining,
                                'planner_qr'       => $wedding->planner_qr_path,
                                'planner_url'       => $wedding->planner_url,
                                'guest_qr'         => $wedding->guest_qr_path,
                                'pdf_file'         => $wedding->guest_pdf_path,
                            ];
                        }

                        return response()->json([
                            'success'          => true,
                            'message'          => t('Wedding details retrieved successfully'),
                            'current_date_ist' => $current_date,

                            'pagination' => [
                                'total'         => $paginated->total(),
                                'per_page'      => $paginated->perPage(),
                                'current_page'  => $paginated->currentPage(),
                                'last_page'     => $paginated->lastPage(),
                                'next_page_url' => $paginated->nextPageUrl(),
                                'prev_page_url' => $paginated->previousPageUrl(),
                            ],

                            'data'            => $finalData,
                            'user_role'       => $user_role,
                            'logged_in_user'  => $user_details,
                            'base_url'        => 'https://planawedding.in/storage/',
                        ], 200);

                    } catch (\Exception $e) {
                        return response()->json([
                            'success' => false,
                            'message' => t('Failed to retrieve wedding details'),
                            'error'   => $e->getMessage(),
                            'line'    => $e->getLine()
                        ], 500);
                    }
                }

        public function saveweddingdetails(Request $request)
                {
                    // Get user from API token
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                        'success' => false,
                        'message' => t('Unauthorized. Please login again.')
                        ], 401);
                    }


                    $useraccess = $this->checkeditaccess($token);
                    $user_role  = $useraccess['role'];

                    $user_details = [
                        'name'          => $user->name,
                        'email'         => $user->email,
                        'mobile'        => $user->mobile,
                        'business_name' => $user->business_name
                    ];


                    $user_id = $user->id;

                    // Validate request
                    $validator = Validator::make($request->all(), [
                        'groom_name' => 'required|string|max:255',
                        'bride_name' => 'required|string|max:255',
                        'date_of_wedding' => 'required|string|regex:/^\d{2}\/\d{2}\/\d{4}$/',
                        'wedding_location' => 'required|string|max:255',
                        'mobile_number' => 'required|digits:10'
                    ]);

                    if ($validator->fails()) {
                        return response()->json([
                        'success' => false,
                        'message' => 'Validation failed',
                        'errors' => $validator->errors()
                        ], 422);
                    }

                    // Get form data
                    $groom_name = $request->groom_name;
                    $bride_name = $request->bride_name;
                    $date_of_wedding = $request->date_of_wedding;
                    $wedding_location = $request->wedding_location;
                    $mobile_number = $request->mobile_number;

                    // Validate date format
                    if (!preg_match('/^(\d{2})\/(\d{2})\/(\d{4})$/', $date_of_wedding, $matches)) {
                        return response()->json([
                        'success' => false,
                        'message' => 'Date of wedding must be in dd/mm/yyyy format'
                        ], 422);
                    }

                    $day = $matches[1];
                    $month = $matches[2];
                    $year = $matches[3];

                    if (!checkdate($month, $day, $year)) {
                        return response()->json([
                        'success' => false,
                        'message' => t('Please enter a valid date')
                        ], 422);
                    }

                    // Get current date in dd/mm/yyyy format (IST)
                    date_default_timezone_set('Asia/Kolkata');
                    $event_created = date('d/m/Y');

                    try {
                            // STEP 1: Insert into database WITHOUT URLs to get wedding_id
                            $wedding_id = DB::table('wedding_details')->insertGetId([
                            'user_id' => $user_id,
                            'groom_name' => $groom_name,
                            'bride_name' => $bride_name,
                            'date_of_wedding' => $date_of_wedding,
                            'wedding_location' => $wedding_location,
                            'mobile_number' => $mobile_number,
                            'event_created' => $event_created,
                            'created_at' => now(),
                            'updated_at' => now()
                    ]);

                    // STEP 2: Generate URLs using event_id (wedding_id)
                    
                    //$dynamic_url = "https://www.business.planawedding.in/listing.php?check_id=" . $user_id . "&event_id=" . $wedding_id;

                    $dynamic_url = "https://www.business.planawedding.in/listing.php?check_id=" . $user_id . "&event_id=" . $wedding_id;


                    $guest_url = "https://planawedding.in/client/client.php?check_id=" . $user_id . "&event_id=" . $wedding_id;

                    // Initialize QR and PDF variables
                    $planner_qr_generated = false;
                    $guest_qr_generated = false;
                    $guest_pdf_generated = false;
                    $planner_qr_relative_path = null;
                    $guest_qr_relative_path = null;
                    $guest_pdf_relative_path = null;
                    $pdf_error_message = '';

                    // STEP 3: Try to load QR library
                    $library_paths = [
                        base_path('libraries/SimpleQRCode.php'),
                        app_path('Libraries/SimpleQRCode.php')
                    ];

                    $qr_library_loaded = false;
                    foreach ($library_paths as $lib_path) {
                        if (file_exists($lib_path)) {
                            require_once $lib_path;
                            $qr_library_loaded = true;
                            break;
                        }
                    }

                    if ($qr_library_loaded) {
                        // Use Laravel storage path
                        $storage_base = storage_path('app/public/qr_codes');

                        // Create folders if they don't exist
                        $planner_qr_folder = $storage_base . '/planner';
                        $guest_qr_folder = $storage_base . '/guest';
                        $pdf_folder = $storage_base . '/pdfs';

                        if (!is_dir($planner_qr_folder)) {
                            @mkdir($planner_qr_folder, 0755, true);
                        }

                        if (!is_dir($guest_qr_folder)) {
                            @mkdir($guest_qr_folder, 0755, true);
                        }

                        if (!is_dir($pdf_folder)) {
                            @mkdir($pdf_folder, 0755, true);
                        }

                        // FIXED: Brand logo path - use absolute path to public_html
                        // Since planawedding and public_html are separate folders
                        $logo_path = '/home/gjymj6oxru2v/public_html/frontend/images/appui/appicons-hq.png';

                        // Fallback: If absolute path doesn't exist, try downloading from URL
                        if (!file_exists($logo_path)) {
                        $logo_url = 'https://planawedding.in/frontend/images/appui/appicons-hq.png';
                        $temp_logo = $storage_base . '/temp_logo.png';

                        // Download logo to temp location
                        $logo_content = @file_get_contents($logo_url);
                        if ($logo_content !== false) {
                            file_put_contents($temp_logo, $logo_content);
                            $logo_path = $temp_logo;
                        }
                    }

                    // STEP 4: Generate planner QR code
                    $planner_qr_filename = 'planner_' . $user_id . '_' . $wedding_id . '_' . time() . '.png';
                    $planner_qr_full_path = $planner_qr_folder . '/' . $planner_qr_filename;
                    $planner_qr_relative_path = 'qr_codes/planner/' . $planner_qr_filename;

                    $planner_qr_generated = \SimpleQRCode::generate($dynamic_url, $planner_qr_full_path, 300, $logo_path);

                    // Small delay for unique timestamp
                    usleep(100000);

                    // STEP 5: Generate guest QR code
                    $guest_qr_filename = 'guest_' . $user_id . '_' . $wedding_id . '_' . time() . '.png';
                    $guest_qr_full_path = $guest_qr_folder . '/' . $guest_qr_filename;
                    $guest_qr_relative_path = 'qr_codes/guest/' . $guest_qr_filename;

                    $guest_qr_generated = \SimpleQRCode::generate($guest_url, $guest_qr_full_path, 300, $logo_path);

                    // Clean up temp logo if it was downloaded
                    if (isset($temp_logo) && file_exists($temp_logo)) {
                        @unlink($temp_logo);
                    }

                    // STEP 6: Generate guest PDF with Playfair Display font
                    if ($guest_qr_generated) {
                        // Try to load PDF library
                        $pdf_library_paths = [
                        base_path('libraries/GuestQRPDF.php'),
                        app_path('Libraries/GuestQRPDF.php')
                    ];

                    $pdf_library_loaded = false;
                    foreach ($pdf_library_paths as $pdf_lib_path) {
                        if (file_exists($pdf_lib_path)) {
                            require_once $pdf_lib_path;
                            $pdf_library_loaded = true;
                            break;
                        }
                    }

                    if ($pdf_library_loaded) {
                    $guest_pdf_filename = 'guest_qr_' . $user_id . '_' . $wedding_id . '_' . time() . '.pdf';
                    $guest_pdf_full_path = $pdf_folder . '/' . $guest_pdf_filename;
                    $guest_pdf_relative_path = 'qr_codes/pdfs/' . $guest_pdf_filename;

                    // Convert relative QR path to absolute for PDF generation
                    $guest_qr_absolute_path = realpath($guest_qr_full_path);
                    if (!$guest_qr_absolute_path) {
                        $guest_qr_absolute_path = $guest_qr_full_path;
                    }

                    // Generate PDF with error handling
                    try {
                        $guest_pdf_generated = \GuestQRPDF::generate(
                        $groom_name,
                        $bride_name,
                        $guest_qr_absolute_path,
                        $guest_pdf_full_path
                    );

                    if (!$guest_pdf_generated) {
                        $pdf_error_message = "GuestQRPDF::generate() returned false";
                        } else if (!file_exists($guest_pdf_full_path)) {
                        $pdf_error_message = "PDF file was not created";
                        $guest_pdf_generated = false;
                        }
                        } catch (\Exception $e) {
                        $pdf_error_message = $e->getMessage();
                        $guest_pdf_generated = false;
                        }
                        } else {
                        $pdf_error_message = "GuestQRPDF library not found";
                        }
                        } else {
                        $pdf_error_message = "Guest QR code was not generated";
                        }

                        // STEP 7: Update database with URLs, QR paths, and PDF path
                        DB::table('wedding_details')
                        ->where('id', $wedding_id)
                        ->update([
                        'planner_url' => $dynamic_url,
                        'guest_url' => $guest_url,
                        'planner_qr_path' => $planner_qr_generated ? $planner_qr_relative_path : null,
                        'guest_qr_path' => $guest_qr_generated ? $guest_qr_relative_path : null,
                        'guest_pdf_path' => $guest_pdf_generated ? $guest_pdf_relative_path : null,
                        'updated_at' => now()
                        ]);
                    }

                    return response()->json([
                        'success' => true,
                        'message' => t('Wedding details saved successfully'),
                        'data' => [
                            'wedding_id' => $wedding_id,
                            'event_id' => $wedding_id,
                            'planner_url' => $dynamic_url,
                            'guest_url' => $guest_url,
                            'planner_qr_path' => $planner_qr_relative_path,
                            'guest_qr_path' => $guest_qr_relative_path,
                            'guest_pdf_path' => $guest_pdf_relative_path,
                            'planner_qr_full_url' => $planner_qr_generated ? 'https://planawedding.in/storage/' . $planner_qr_relative_path : null,
                            'guest_qr_full_url' => $guest_qr_generated ? 'https://planawedding.in/storage/' . $guest_qr_relative_path : null,
                            'guest_pdf_full_url' => $guest_pdf_generated ? 'https://planawedding.in/storage/' . $guest_pdf_relative_path : null,
                            'base_url' => 'https://planawedding.in/storage/',
                            'qr_generated' => $planner_qr_generated && $guest_qr_generated,
                            'pdf_generated' => $guest_pdf_generated,
                            'pdf_error' => $pdf_error_message,
                            'check_id' => $user_id,
                            
                        ],
                        'user_role'         => $user_role,
                        'logged_in_user'    => $user_details,
                        'base_url'          => 'https://planawedding.in/storage/',
                    ], 200);

                    } catch (\Exception $e) {
                        return response()->json([
                            'success' => false,
                            'message' => t('Failed to save wedding details'),
                            'error' => $e->getMessage(),
                            'line' => $e->getLine()
                            ], 500);
                    }
                } 


        public function deleteweddingitem(Request $request, $id)
                {
                    // Get user from API token
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                            'success' => false,
                            'message' => t('Unauthorized. Please login again.')
                        ], 401);
                    }

                    $user_id = $user->id;
                    $useraccess = $this->checkeditaccess($token);
                    $user_role  = $useraccess['role'];

                    $user_details = [
                        'name'          => $user->name,
                        'email'         => $user->email,
                        'mobile'        => $user->mobile,
                        'business_name' => $user->business_name
                    ];
                    try {
                        // Check if wedding item exists
                        $wedding = DB::table('wedding_details')
                            ->where('id', $id)
                            ->first();

                        if (!$wedding) {
                            return response()->json([
                                'success' => false,
                                'message' => t('Wedding item not found'),
                                'user_role'      => $user_role,
                                'logged_in_user' => $user_details,
                                'base_url'       => 'https://planawedding.in/storage/',
                            ], 404);
                        }

                        // Check if the wedding item belongs to the authenticated user
                        if ($wedding->user_id != $user_id) {
                            return response()->json([
                                'success' => false,
                                'message' => t('Unauthorized. You do not have permission to delete this wedding item.')
                            ], 403);
                        }

                        // Optional: Delete associated files (QR codes and PDFs)
                        $storage_base = storage_path('app/public');
                        $files_deleted = [];

                        if (!empty($wedding->planner_qr_path)) {
                            $planner_qr_full_path = $storage_base . '/' . $wedding->planner_qr_path;
                            if (file_exists($planner_qr_full_path)) {
                                @unlink($planner_qr_full_path);
                                $files_deleted[] = 'planner_qr';
                            }
                        }

                        if (!empty($wedding->guest_qr_path)) {
                            $guest_qr_full_path = $storage_base . '/' . $wedding->guest_qr_path;
                            if (file_exists($guest_qr_full_path)) {
                                @unlink($guest_qr_full_path);
                                $files_deleted[] = 'guest_qr';
                            }
                        }

                        if (!empty($wedding->guest_pdf_path)) {
                            $guest_pdf_full_path = $storage_base . '/' . $wedding->guest_pdf_path;
                            if (file_exists($guest_pdf_full_path)) {
                                @unlink($guest_pdf_full_path);
                                $files_deleted[] = 'guest_pdf';
                            }
                        }

                        // Delete the wedding item from database
                        $deleted = DB::table('wedding_details')
                            ->where('id', $id)
                            ->delete();

                        if ($deleted) {
                            return response()->json([
                                'success' => true,
                                'message' => t('Wedding item deleted successfully'),
                                'data' => [
                                    'deleted_id' => $id,
                                    'files_deleted' => $files_deleted
                                ],
                                'user_role'      => $user_role,
                                'logged_in_user' => $user_details,
                                'base_url'       => 'https://planawedding.in/storage/',
                            ], 200);
                        } else {
                            return response()->json([
                                'success' => false,
                                'message' => t('Failed to delete wedding item'),
                                'user_role'      => $user_role,
                                'logged_in_user' => $user_details,
                                'base_url'       => 'https://planawedding.in/storage/',
                            ], 500);
                        }

                    } catch (\Exception $e) {
                        return response()->json([
                            'success' => false,
                            'message' => t('Failed to delete wedding item'),
                            'error' => $e->getMessage(),
                            'line' => $e->getLine()
                        ], 500);
                    }
                }

        public function editweddingdetails(Request $request, $id)
                {
                    // Get user from API token
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                            'success' => false,
                            'message' => t('Unauthorized. Please login again.')
                        ], 401);
                    }

                    $user_id = $user->id;
                    $useraccess = $this->checkeditaccess($token);
                    $user_role  = $useraccess['role'];

                    $user_details = [
                        'name'          => $user->name,
                        'email'         => $user->email,
                        'mobile'        => $user->mobile,
                        'business_name' => $user->business_name
                    ];

                    // Validate request
                    $validator = Validator::make($request->all(), [
                        'groom_name' => 'required|string|max:255',
                        'bride_name' => 'required|string|max:255',
                        'date_of_wedding' => 'required|string|regex:/^\d{2}\/\d{2}\/\d{4}$/',
                        'wedding_location' => 'required|string|max:255',
                        'mobile_number' => 'required|digits:10'
                    ]);

                    if ($validator->fails()) {
                        return response()->json([
                            'success' => false,
                            'message' => t('Validation failed'),
                            'errors' => $validator->errors()
                        ], 422);
                    }

                    // Get form data
                    $groom_name = $request->groom_name;
                    $bride_name = $request->bride_name;
                    $date_of_wedding = $request->date_of_wedding;
                    $wedding_location = $request->wedding_location;
                    $mobile_number = $request->mobile_number;

                    // Validate date format
                    if (!preg_match('/^(\d{2})\/(\d{2})\/(\d{4})$/', $date_of_wedding, $matches)) {
                        return response()->json([
                            'success' => false,
                            'message' => 'Date of wedding must be in dd/mm/yyyy format'
                        ], 422);
                    }

                    $day = $matches[1];
                    $month = $matches[2];
                    $year = $matches[3];

                    if (!checkdate($month, $day, $year)) {
                        return response()->json([
                            'success' => false,
                            'message' => t('Please enter a valid date')
                        ], 422);
                    }

                    try {
                        // Check if wedding item exists
                        $wedding = DB::table('wedding_details')
                            ->where('id', $id)
                            ->first();

                        if (!$wedding) {
                            return response()->json([
                                'success' => false,
                                'message' => t('Wedding item not found'),
                                'user_role'      => $user_role,
                                'logged_in_user' => $user_details,
                                'base_url'       => 'https://planawedding.in/storage/',
                            ], 404);
                        }

                        // Check if the wedding item belongs to the authenticated user
                        if ($wedding->user_id != $user_id) {
                            return response()->json([
                                'success' => false,
                                'message' => t('Unauthorized. You do not have permission to edit this wedding item.')
                            ], 403);
                        }

                        // Delete old files before regenerating
                        $storage_base = storage_path('app/public');
                        $files_deleted = [];

                        if (!empty($wedding->planner_qr_path)) {
                            $planner_qr_full_path = $storage_base . '/' . $wedding->planner_qr_path;
                            if (file_exists($planner_qr_full_path)) {
                                @unlink($planner_qr_full_path);
                                $files_deleted[] = 'planner_qr';
                            }
                        }

                        if (!empty($wedding->guest_qr_path)) {
                            $guest_qr_full_path = $storage_base . '/' . $wedding->guest_qr_path;
                            if (file_exists($guest_qr_full_path)) {
                                @unlink($guest_qr_full_path);
                                $files_deleted[] = 'guest_qr';
                            }
                        }

                        if (!empty($wedding->guest_pdf_path)) {
                            $guest_pdf_full_path = $storage_base . '/' . $wedding->guest_pdf_path;
                            if (file_exists($guest_pdf_full_path)) {
                                @unlink($guest_pdf_full_path);
                                $files_deleted[] = 'guest_pdf';
                            }
                        }

                        // Update wedding details in database (without QR/PDF paths yet)
                        DB::table('wedding_details')
                            ->where('id', $id)
                            ->update([
                                'groom_name' => $groom_name,
                                'bride_name' => $bride_name,
                                'date_of_wedding' => $date_of_wedding,
                                'wedding_location' => $wedding_location,
                                'mobile_number' => $mobile_number,
                                'updated_at' => now()
                            ]);

                        // Generate URLs using event_id (wedding_id)
                        /*
                            $dynamic_url = "https://www.business.planawedding.in/listing.php?check_id=" . $user_id . "&event_id=" . $id;
                        */
                        $dynamic_url = "https://www.business.planawedding.in/listing.php?check_id=" . $user_id . "&event_id=" . $id;
                       
                        $guest_url = "https://planawedding.in/client/client.php?check_id=" . $user_id . "&event_id=" . $id;

                        // Initialize QR and PDF variables
                        $planner_qr_generated = false;
                        $guest_qr_generated = false;
                        $guest_pdf_generated = false;
                        $planner_qr_relative_path = null;
                        $guest_qr_relative_path = null;
                        $guest_pdf_relative_path = null;
                        $pdf_error_message = '';

                        // Try to load QR library
                        $library_paths = [
                            base_path('libraries/SimpleQRCode.php'),
                            app_path('Libraries/SimpleQRCode.php')
                        ];

                        $qr_library_loaded = false;
                        foreach ($library_paths as $lib_path) {
                            if (file_exists($lib_path)) {
                                require_once $lib_path;
                                $qr_library_loaded = true;
                                break;
                            }
                        }

                        if ($qr_library_loaded) {
                            // Use Laravel storage path
                            $qr_storage_base = storage_path('app/public/qr_codes');

                            // Create folders if they don't exist
                            $planner_qr_folder = $qr_storage_base . '/planner';
                            $guest_qr_folder = $qr_storage_base . '/guest';
                            $pdf_folder = $qr_storage_base . '/pdfs';

                            if (!is_dir($planner_qr_folder)) {
                                @mkdir($planner_qr_folder, 0755, true);
                            }

                            if (!is_dir($guest_qr_folder)) {
                                @mkdir($guest_qr_folder, 0755, true);
                            }

                            if (!is_dir($pdf_folder)) {
                                @mkdir($pdf_folder, 0755, true);
                            }

                            // Brand logo path
                            $logo_path = '/home/gjymj6oxru2v/public_html/frontend/images/appui/appicons-hq.png';

                            // Fallback: If absolute path doesn't exist, try downloading from URL
                            if (!file_exists($logo_path)) {
                                $logo_url = 'https://planawedding.in/frontend/images/appui/appicons-hq.png';
                                $temp_logo = $qr_storage_base . '/temp_logo.png';

                                // Download logo to temp location
                                $logo_content = @file_get_contents($logo_url);
                                if ($logo_content !== false) {
                                    file_put_contents($temp_logo, $logo_content);
                                    $logo_path = $temp_logo;
                                }
                            }

                            // Generate planner QR code
                            $planner_qr_filename = 'planner_' . $user_id . '_' . $id . '_' . time() . '.png';
                            $planner_qr_full_path = $planner_qr_folder . '/' . $planner_qr_filename;
                            $planner_qr_relative_path = 'qr_codes/planner/' . $planner_qr_filename;

                            $planner_qr_generated = \SimpleQRCode::generate($dynamic_url, $planner_qr_full_path, 300, $logo_path);

                            // Small delay for unique timestamp
                            usleep(100000);

                            // Generate guest QR code
                            $guest_qr_filename = 'guest_' . $user_id . '_' . $id . '_' . time() . '.png';
                            $guest_qr_full_path = $guest_qr_folder . '/' . $guest_qr_filename;
                            $guest_qr_relative_path = 'qr_codes/guest/' . $guest_qr_filename;

                            $guest_qr_generated = \SimpleQRCode::generate($guest_url, $guest_qr_full_path, 300, $logo_path);

                            // Clean up temp logo if it was downloaded
                            if (isset($temp_logo) && file_exists($temp_logo)) {
                                @unlink($temp_logo);
                            }

                            // Generate guest PDF with Playfair Display font
                            if ($guest_qr_generated) {
                                // Try to load PDF library
                                $pdf_library_paths = [
                                    base_path('libraries/GuestQRPDF.php'),
                                    app_path('Libraries/GuestQRPDF.php')
                                ];

                                $pdf_library_loaded = false;
                                foreach ($pdf_library_paths as $pdf_lib_path) {
                                    if (file_exists($pdf_lib_path)) {
                                        require_once $pdf_lib_path;
                                        $pdf_library_loaded = true;
                                        break;
                                    }
                                }

                                if ($pdf_library_loaded) {
                                    $guest_pdf_filename = 'guest_qr_' . $user_id . '_' . $id . '_' . time() . '.pdf';
                                    $guest_pdf_full_path = $pdf_folder . '/' . $guest_pdf_filename;
                                    $guest_pdf_relative_path = 'qr_codes/pdfs/' . $guest_pdf_filename;

                                    // Convert relative QR path to absolute for PDF generation
                                    $guest_qr_absolute_path = realpath($guest_qr_full_path);
                                    if (!$guest_qr_absolute_path) {
                                        $guest_qr_absolute_path = $guest_qr_full_path;
                                    }

                                    // Generate PDF with error handling
                                    try {
                                        $guest_pdf_generated = \GuestQRPDF::generate(
                                            $groom_name,
                                            $bride_name,
                                            $guest_qr_absolute_path,
                                            $guest_pdf_full_path
                                        );

                                        if (!$guest_pdf_generated) {
                                            $pdf_error_message = "GuestQRPDF::generate() returned false";
                                        } else if (!file_exists($guest_pdf_full_path)) {
                                            $pdf_error_message = "PDF file was not created";
                                            $guest_pdf_generated = false;
                                        }
                                    } catch (\Exception $e) {
                                        $pdf_error_message = $e->getMessage();
                                        $guest_pdf_generated = false;
                                    }
                                } else {
                                    $pdf_error_message = "GuestQRPDF library not found";
                                }
                            } else {
                                $pdf_error_message = "Guest QR code was not generated";
                            }

                            // Update database with URLs, QR paths, and PDF path
                            DB::table('wedding_details')
                                ->where('id', $id)
                                ->update([
                                    'planner_url' => $dynamic_url,
                                    'guest_url' => $guest_url,
                                    'planner_qr_path' => $planner_qr_generated ? $planner_qr_relative_path : null,
                                    'guest_qr_path' => $guest_qr_generated ? $guest_qr_relative_path : null,
                                    'guest_pdf_path' => $guest_pdf_generated ? $guest_pdf_relative_path : null,
                                    'updated_at' => now()
                                ]);
                        }

                        return response()->json([
                            'success' => true,
                            'message' => t('Wedding details updated successfully'),
                            'data' => [
                                'wedding_id' => $id,
                                'event_id' => $id,
                                'planner_url' => $dynamic_url,
                                'guest_url' => $guest_url,
                                'planner_qr_path' => $planner_qr_relative_path,
                                'guest_qr_path' => $guest_qr_relative_path,
                                'guest_pdf_path' => $guest_pdf_relative_path,
                                'planner_qr_full_url' => $planner_qr_generated ? 'https://planawedding.in/storage/' . $planner_qr_relative_path : null,
                                'guest_qr_full_url' => $guest_qr_generated ? 'https://planawedding.in/storage/' . $guest_qr_relative_path : null,
                                'guest_pdf_full_url' => $guest_pdf_generated ? 'https://planawedding.in/storage/' . $guest_pdf_relative_path : null,
                                'base_url' => 'https://planawedding.in/storage/',
                                'qr_generated' => $planner_qr_generated && $guest_qr_generated,
                                'pdf_generated' => $guest_pdf_generated,
                                'pdf_error' => $pdf_error_message,
                                'check_id' => $user_id,
                                'files_deleted' => $files_deleted,
                            ],
                            'user_role'         => $user_role,
                            'logged_in_user'    => $user_details,
                            'base_url'          => 'https://planawedding.in/storage/',
                        ], 200);

                    } catch (\Exception $e) {
                        return response()->json([
                            'success' => false,
                            'message' => t('Failed to update wedding details'),
                            'error' => $e->getMessage(),
                            'line' => $e->getLine()
                        ], 500);
                    }
                }
    /* Photo sharing ends */

    /* Get quote starts */
        public function eventstates(Request $request)   
                {
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);

                    if($user) 
                        {
                                $user_details = ['id' => $user->id,'name' => $user->name,'email' => $user->email,'mobile' => $user->mobile,'business_name' => $user->business_name];
                                $useraccess = $this->chkuseraccessstatistics($token);
                                $user_role = $useraccess['role'];
                                $user_access = $useraccess['useraccess'];

                                // ✅ Fetch distinct state names
                                

                                $states = \DB::table('users')
                                        ->where('role_id', 4)
                                        ->where('is_active', 1)
                                        ->whereNull('team_id')
                                        ->whereNotNull('user_lead_state_name')
                                        ->where(function($q) {
                                            $q->where('chk_subscription', 1)
                                            ->orWhere('is_partner', 1);
                                        })
                                        ->select('user_lead_state_name')
                                        ->distinct()
                                        ->orderBy('user_lead_state_name', 'asc')
                                        ->pluck('user_lead_state_name')
                                ->toArray();

                                $statesFormatted = array_map(function ($state) {
                                    return [
                                        'value'        => $state,                 // original DB value
                                        'display_text'=> translateState($state),  // translated (cached)
                                    ];
                                }, $states);

                                return response()->json([
                                    'status' => '1',
                                    'message' => t('States'),
                                    'data' => $statesFormatted,
                                    'user_role' => $user_role,
                                    'user_access' => $user_access, 
                                    'logged_in_user' => $user_details,

                                    'base_url' => 'https://planawedding.in/storage/',
                                ], 200); 
                                 

                        }
                    else 
                        {
                            return response()->json([
                                'message' => t('User not found'),
                                'status' => '0',
                                'page_heading' => [],
                                'data' => [],
                                'user_role' => "",
                                'logged_in_user' => [], 
                                'base_url' => 'https://planawedding.in/storage/',
                            ], 401);
                        }
                }

        public function addediteventdetails(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);
                    if($user) 
                        {
                            $user_details = ['name' => $user->name,'email' => $user->email,'mobile' => $user->mobile,'business_name'=> $user->business_name];                    
                            $useraccess = $this->checkeditaccess($token);
