                                                $myevents = VendorMarketPlaceEvent::where('id',$request->event_id)->where('user_id',$user_id)->latest()->first();
                                                $myevents->event_name   = $request->event_name;
                                                $myevents->event_date   = $request->event_date;
                                                $myevents->valid_date   = $request->valid_date;
                                                $myevents->event_state  = $request->event_state;
                                                $myevents->event_location   = $request->event_location;
                                                $myevents->event_remarks   = $request->event_remarks;
                                                $myevents->dataedited_on   = now()->format('d/m/Y H:i:s');

                                                $myevents->display_request   = $display_request; 
                                                
                                                if($myevents->save())
                                                    {
                                                        return response()->json([
                                                            'message' => t('Edited Event'),
                                                            'status' => '1',
                                                            /*'data' => $myevents,*/
                                                            'data' => [
                                                                'id'              => $myevents->id,
                                                                'event_name'      => translateEventName($myevents->event_name),  
                                                                'event_date'      => $myevents->event_date,
                                                                'valid_date'      => $myevents->valid_date,
                                                                'event_state'     => translateState($myevents->event_state),
                                                                'event_location'  => translateVenueLocation($myevents->event_location),
                                                                'event_remarks'   => transliterateTextKeepNumbers($myevents->event_remarks), // user content → keep as-is
                                                                'display_request' => $myevents->display_request,
                                                            ],
                                                            'page_heading' => $page_heading,
                                                            'page_i_content' => $page_i_content,
                                                            'user_role' => $user_role,
                                                            'logged_in_user' => $user_details,
                                                            'base_url' => 'https://planawedding.in/storage/',
                                                        ], 200);
                                                    }
                                                else 
                                                    {
                                                        return response()->json([
                                                                'message' => t('Unable to Add Event'),
                                                                'status' => '0',
                                                                'data' => [],
                                                                'page_heading' => NULL,
                                                                'page_i_content' => NULL,
                                                                'user_role' => $user_role,
                                                                'logged_in_user' => $user_details,
                                                                'base_url' => 'https://planawedding.in/storage/',
                                                            ], 200);
                                                    }
                                            }
                                        }
                                }    
                        }
                    else 
                        {
                            return response()->json([
                                'message' => t('User not found'),
                                'status' => '0',
                                'data' => [],
                                'user_role' => "",
                                'logged_in_user' => [],
                                'base_url' => 'https://planawedding.in/storage/',
                            ], 401);
                        }
                }
        public function geteventdetails(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                            'message' => t('User not found'),
                            'status' => '0',
                            'page_heading' => [],
                            'data' => [],
                            'user_role' => "",
                            'logged_in_user' => [],
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 401);
                    }

                    $user_details = [
                        'id' => $user->id,
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name' => $user->business_name
                    ];

                    $useraccess = $this->chkuseraccessstatistics($token);
                    $user_role = $useraccess['role'];
                    $user_access = $useraccess['useraccess'];

                    $id = $request->id;

                    // ✅ Fetch event details
                    $event = \App\VendorMarketPlaceEvent::where('id', $id)->latest()->first();
                    if (!$event) {
                        return response()->json([
                            'status' => '0',
                            'message' => t('Event not found'),
                            'data' => [],
                        ], 404);
                    }

                    // ✅ Prepare data (no date formatting)
                    $event_data = [
                        'id' => $event->id,
                        'event_name' => translateEventName($event->event_name) ?? '-',
                        'event_date' => $event->event_date ?? '-',
                        'valid_date' => $event->valid_date ?? '-',
                        'event_state' => translateState($event->event_state) ?? '-',
                        'event_location' => translateVenueLocation($event->event_location) ?? '-',
                        'event_remarks' => transliterateTextKeepNumbers($event->event_remarks) ?? '-',
                    ];

                    // ✅ Headings
                    $page_top_heading = ['show' => 1, 'name' => t('Dashboard')];
                    $page_heading = ['show' => 1, 'name' => t('Event Details')];

                    return response()->json([
                        'message' => t('Event details fetched successfully.'),
                        'status' => '1',
                        'page_top_heading' => $page_top_heading,
                        'page_heading' => $page_heading,
                        'data' => $event_data,
                        'user_role' => $user_role,
                        'user_access' => $user_access,
                        'logged_in_user' => $user_details,
                        'base_url' => 'https://planawedding.in/storage/',
                    ], 200);
                } 
