                                ['service_name' => 'Marriage Ceremony Planning', 'image_path' => 'https://business.planawedding.in/images/couples/editicon.webp'],
                                ['service_name' => 'Muhurat Planning', 'image_path' => 'https://business.planawedding.in/images/couples/editicon.webp'],
                                ['service_name' => 'Reception Planning', 'image_path' => 'https://business.planawedding.in/images/couples/editicon.webp'],
                                ['service_name' => 'Mehendi Ceremony Planning', 'image_path' => 'https://business.planawedding.in/images/couples/editicon.webp'],
                                ['service_name' => 'Haldi Ceremony Planning', 'image_path' => 'https://business.planawedding.in/images/couples/editicon.webp'],
                                ['service_name' => 'Sangeeth Planning', 'image_path' => 'https://business.planawedding.in/images/couples/editicon.webp'],
                                ['service_name' => 'Venue Selection & Booking', 'image_path' => 'https://business.planawedding.in/images/couples/editicon.webp'],
                                ['service_name' => 'Bridal Makeup Coordination', 'image_path' => 'https://business.planawedding.in/images/couples/editicon.webp'],
                                ['service_name' => 'Catering Management', 'image_path' => 'https://business.planawedding.in/images/couples/editicon.webp'],
                                ['service_name' => 'Decoration & Theme Planning', 'image_path' => 'https://business.planawedding.in/images/couples/editicon.webp'],
                                ['service_name' => 'On-ground Event Coordination', 'image_path' => 'https://business.planawedding.in/images/couples/editicon.webp'],
                                ['service_name' => 'Complete Wedding Day Execution', 'image_path' => 'https://business.planawedding.in/images/couples/editicon.webp'],
                            ]
                        ],
    
                    ];

                    // ✅ Fetch user’s previously saved selections
                    $userSelections = \DB::table('user_selected_services')
                        ->where('user_id', $user->id)
                        ->where('servicedetail_id', $id)
                        ->get()
                        ->keyBy('category');

                    $userSubSelections = \DB::table('user_selected_sub_services')
                        ->where('user_id', $user->id)
                        ->where('servicedetail_id', $id)
                        ->get()
                        ->groupBy('category');

                    // ✅ Final Output
                    $final_output = [];
                    foreach ($manual_data as $category => $data) {
                        $isSelected = $userSelections->has($category);
                        $saved = $userSelections->get($category);

                        $subServices = $data['sub_services'];
                        $userSubs = $userSubSelections->has($category)
                            ? $userSubSelections[$category]->pluck('sub_service_name')->toArray()
                            : [];

                        foreach ($subServices as &$ss) {
                            $ss['selected'] = in_array($ss['service_name'], $userSubs);
                        }

                        // ✅ Requirement labels
                        if ($category === 'Catering') {
                            $requirement_label = 'Enter number of guests, session type, and food style for better clarity';
                        } elseif (in_array($category, [
                            'Photography and Videography', 'Mehendi Artists', 'DJ', 'Anchor', 'Purohit'
                        ])) {
                            $requirement_label = 'Enter session details for clarity';
                        } elseif ($category === 'Stage, Sound and Light') {
                            $requirement_label = 'Enter basic information for better understanding';
                        } else {
                            $requirement_label = 'Remarks (if any)';
                        }

                        $translatedSubServices = [];

                        foreach ($subServices as $ss) {
                            $translatedSubServices[] = [
                                'service_name_value'   => $ss['service_name'],
                                'service_name_display' => uiTranslate($ss['service_name']),
                                'image_path'           => $ss['image_path'],
                                'selected'             => $ss['selected'],
                            ];
                        }

                        $final_output[] = [
                            'category_value'   => $category,
                            'category_display' => uiTranslate($category),

                            'selected' => $isSelected,
                            'total_budget' => $saved->total_budget ?? 0,

                            'others' => $saved->others ?? '',
                            'special_requirements' => $saved->special_requirements ?? '',

                            'requirement_label' => uiTranslate($requirement_label),

                            'sub_content_value'   => $data['sub_title'],
                            'sub_content_display' => uiTranslate($data['sub_title']),

                            'sub_services' => $translatedSubServices,
                        ];
                    }

                    return response()->json([
                        'status' => '1',
                        'message' => t('Service details fetched successfully.'),
                        'data' => [
                            'event_state' => translateState($chosenstate),
                            'specializations' => $final_output,
                        ],
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                        'base_url' => 'https://planawedding.in/storage/',
                    ], 200);
                }
        public function saveservices(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user  = $this->getuser($token); // Planner user

                    if (!$user) {
                        return response()->json([
                            'status' => '0',
                            'message' => t('User not found'),
                        ], 401);
                    }

                    if ($request->isJson()) {
                        $request->merge($request->json()->all());
                    }

                    $validator = Validator::make($request->all(), [
                        'servicedetail_id' => 'required|integer|exists:vendor_marketplace_events,id',
                        'selected_services' => 'required|array|min:1',
                        'selected_services.*.category' => 'required|string',
                        'selected_services.*.total_budget' => 'required|numeric|min:0',
                    ]);

                    if ($validator->fails()) {
                        $errors = $validator->errors()->toArray();

                        // 🌐 Translate each validation message
                        foreach ($errors as $field => &$messages) {
                            foreach ($messages as &$msg) {
                                $msg = t($msg);
                            }
                        }

                        return response()->json([
                            'status' => '0',
                             'message' => $errors,
                        ], 422);
                    }

                    $servicedetail_id = $request->servicedetail_id;

                    $selectedServices = collect($request->selected_services)
                        ->filter(fn ($s) => !empty($s['selected']))
                        ->values();

                    if ($selectedServices->isEmpty()) {
                        return response()->json([
                            'status' => '0',
                            'message' => t('Please select at least one category.'),
                        ], 422);
                    }

                    $normalize = function ($c) {
                        return strtolower(
                            preg_replace('/\s+/', ' ',
                                str_replace(['&', '-', '_'], ['and', ' ', ' '], trim($c))
                            )
                        );
                    };

                    $categoryToColumn = [
                        'venue' => 'venue',
                        'flower decorators' => 'flower',
                        'catering' => 'catering',
                        'photo and videographer' => 'photovideo',
                        'photography and videography' => 'photovideo',
                        'mehendi' => 'mehendi',
                        'priests' => 'priest',
                        'purohit' => 'priest',
                        'dj' => 'dj',
                        'makeup artists' => 'makeup',
                    ];

                    $categoryToSlug = [
                        'photo and videographer' => 'photo&videographer',
                        'flower decorators' => 'flower-decorators',
                        'catering' => 'catering',
                        'mehendi' => 'mehendi',
                        'priests' => 'priests',
                        'purohit' => 'priests',
                        'dj' => 'dj',
                        'makeup artists' => 'makeup-artists',
                        'venue' => 'venue',
                    ];

                    $formatIndianCurrency = function ($number) {
                        $number = (int) $number;
                        if (strlen($number) > 3) {
                            $last3 = substr($number, -3);
                            $rest  = substr($number, 0, -3);
                            $rest  = preg_replace("/\B(?=(\d{2})+(?!\d))/", ",", $rest);
                            return '₹' . $rest . ',' . $last3;
                        }
                        return '₹' . $number;
                    };

                    DB::beginTransaction();

                    try {
                        foreach ($selectedServices as $service) {

                            $existing = DB::table('user_selected_services')
                                ->where('user_id', $user->id)
                                ->where('servicedetail_id', $servicedetail_id)
                                ->where('category', $service['category'])
                                ->first();

                            if ($existing) {
                                $serviceId = $existing->id;
                                DB::table('user_selected_services')->where('id', $serviceId)->update([
                                    'total_budget' => $service['total_budget'],
                                    'sub_services' => json_encode($service['sub_services'] ?? []),
                                    'updated_at' => now(),
                                ]);
                            } else {
                                $serviceId = DB::table('user_selected_services')->insertGetId([
                                    'user_id' => $user->id,
                                    'servicedetail_id' => $servicedetail_id,
                                    'category' => $service['category'],
                                    'total_budget' => $service['total_budget'],
                                    'sub_services' => json_encode($service['sub_services'] ?? []),
                                    'created_at' => now(),
                                    'updated_at' => now(),
                                ]);
                            }

                            DB::table('user_selected_sub_services')
                                ->where('user_selected_service_id', $serviceId)
                                ->delete();

                            foreach (($service['sub_services'] ?? []) as $sub) {
                                DB::table('user_selected_sub_services')->insert([
                                    'user_selected_service_id' => $serviceId,
                                    'user_id' => $user->id,
                                    'servicedetail_id' => $servicedetail_id,
                                    'category' => $service['category'],
                                    'sub_service_name' => $sub['service_name'] ?? '',
                                    'sub_service_budget' => $sub['budget'] ?? 0,
                                    'created_at' => now(),
                                    'updated_at' => now(),
                                ]);
                            }
                        }

                        DB::commit();

                        $servicesText = '';
                        $totalBudget  = 0;

                        foreach ($selectedServices as $i => $service) {
                            $servicesText .= ($i + 1) . '. ' . $service['category'] . "\n";
                            $totalBudget += (int) $service['total_budget'];
                        }

                        $leadDescription  = "Client Requirement:\n\n";
                        $leadDescription .= "{$user->name} is looking for the below services.\n\n";
                        $leadDescription .= "Services Required:\n\n";
                        $leadDescription .= $servicesText . "\n";
                        $leadDescription .= "Total Estimated Budget:\n\n";
                        $leadDescription .= $formatIndianCurrency($totalBudget) . "\n\n";
                        $leadDescription .= "NOTE:\n\n";
                        $leadDescription .= "1. Please send a WhatsApp message before calling the client.\n";
                        $leadDescription .= "2. Leads are shown to planners and vendors based on customer requirements.\n";
                        $leadDescription .= "3. Purchase the lead only if interested.";

                        $event = DB::table('vendor_marketplace_events')
                            ->where('id', $servicedetail_id)
                            ->first();

                        $stateRow = DB::table('customer_states')
                            ->where('state_name', $event->event_state ?? null)
                            ->first();

                        $packageSlugs = [];

                        $leadInsert = [
                            'name' => $event->event_name ?? 'Business Lead',
                            'mobile' => $user->mobile ?? null,
                            'lead_time' => now()->format('d/m/Y H:i'),
                            'event_date' => $event->event_date ?? null,
                            'expiry_date' => now()->addDays(3)->format('Y-m-d'),
                            'lead_description' => $leadDescription,
                            'event_category' => 'wedding',
                            'lead_type' => 'hot',
                            'status' => 'not-purchased',
                            'price' => 250,
                            'purchase_allowed' => 3,
                            'city' => $event->event_location ?? null,
                            'event_location' => $event->event_location ?? null,
                            'state_id' => $stateRow->id ?? null,
                            'state_name' => $event->event_state ?? null,
                            'actual_state_tblid' => $stateRow->id ?? null,
                            'actual_state_tbl_name' => $event->event_state ?? null,
                            'actual_stateid' => $stateRow->id ?? null,
                            'this_user_id' => $user->id,
                            'planner_id' => $user->id,
                            'planner_get_quote_id' => $servicedetail_id,
                            'buyleads_category_type' => 'Buy Lead',
                            'not_show_wp' => 0,
                            'lead_source' => 'Internal',
                            'lead_source_show' => 'PAW Lead',
                            'from_source' => 'PAW Leads',
                            'actual_lead_from' => 'B2B APP - Get Quote',
                            'actual_lead_from_to_show' => 'Business Lead',
                            'created_at' => now(),
                            'updated_at' => now(),
                        ];

                        foreach ($selectedServices as $service) {

                            $norm = $normalize($service['category']);
                            if (!isset($categoryToColumn[$norm])) continue;

                            $suffix = $categoryToColumn[$norm];
                            $slug   = $categoryToSlug[$norm] ?? null;

                            if ($slug) $packageSlugs[] = $slug;

                            $desc  = "{$user->name} is looking for the below services.\n\n";
                            $desc .= "Services Required:\n\n";
                            $desc .= "1. {$service['category']}\n\n";
                            $desc .= "Estimated Budget:\n\n";
                            $desc .= $formatIndianCurrency($service['total_budget']) . "\n\n";
                            $desc .= "NOTE:\n\n";
                            $desc .= "1. Please send a WhatsApp message before calling the client.\n";
                            $desc .= "2. Leads are shown to planners and vendors based on customer requirements.\n";
                            $desc .= "3. Purchase the lead only if interested.";

                            $leadInsert["lead_description_{$suffix}"] = $desc;
                            $leadInsert["lead_type_{$suffix}"] = 'hot';
                            $leadInsert["price_{$suffix}"] = 250;
                            $leadInsert["purchase_allowed_{$suffix}"] = 3;
                        }

                        $leadInsert['package_type'] =
                            'wedding,' . implode(',', array_unique($packageSlugs));

                        $generalLeadId = null;

                        if ($user->mobile != '6360200382') {
                            $generalLeadId = DB::table('general_leads')->insertGetId($leadInsert);
                        }

                        /** ===========================
                        *  🔔 TRIGGER NOTIFICATIONS
                        * ============================*/

                         

                        if ($generalLeadId) {
                            dispatch(
                                (new \App\Jobs\SendBuyLeadNotificationJob(
                                    $generalLeadId,
                                    $servicedetail_id,
                                    $packageSlugs,
                                    $event,
                                    $leadInsert,
                                    $user
                                ))->onConnection('database')
                            );
                        }



                        return response()->json([
                            'status' => '1',
                            'message' => t('Services saved, lead created & notifications sent successfully'),
                            'user_id' => $user->id,
                            'servicedetail_id' => $servicedetail_id,
                            'lead_id' => $generalLeadId,
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 200);

                    } catch (\Exception $e) {
                        DB::rollBack();
                        return response()->json([
                            'status' => '0',
                            'message' => t('Something went wrong. Please try again.'),
                            'debug'   => app()->environment('production') ? null : $e->getMessage(),
                        ], 500);
                    }
                }    

        public function plannerevents(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                            'message' => t('User not found'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => "",
                            'logged_in_user' => [],
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 401);
                    }

                    $user_details = [
                        'id' => $user->id,
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name' => $user->business_name
                    ];

                    $useraccess = $this->chkuseraccessstatistics($token);
                    $user_role = $useraccess['role'];

                    // Helper: Indian number formatting
                    $formatIndianNumber = function ($num) {
                        $num = (int) $num;
                        $explrestunits = "";
                        if (strlen($num) > 3) {
                            $lastthree = substr($num, -3);
                            $restunits = substr($num, 0, -3);
                            $restunits = (strlen($restunits) % 2 == 1) ? "0" . $restunits : $restunits;
                            $expunit = str_split($restunits, 2);
                            foreach ($expunit as $i => $unit) {
                                if ($i == 0) $explrestunits .= (int)$unit . ",";
                                else $explrestunits .= $unit . ",";
                            }
                            return $explrestunits . $lastthree;
                        } else {
                            return $num;
                        }
                    };

                    // Helper: Safe field value
                    $safe = fn($v) => (!isset($v) || $v === '' || is_null($v)) ? null : $v;

                    $events = DB::table('vendor_marketplace_events as v')
                        ->leftJoin('user_selected_services as s', 'v.id', '=', 's.servicedetail_id')
                        ->select(
                            'v.id',
                            'v.event_name',
                            'v.event_date',
                            'v.event_state',
                            'v.event_location',
                            'v.event_remarks',
                            'v.display_request',
                            DB::raw('COALESCE(SUM(s.total_budget),0) as total_budget')
                        )
                        ->where('v.user_id', $user->id)
                        ->groupBy('v.id', 'v.event_name', 'v.event_date', 'v.event_state', 'v.event_location', 'v.event_remarks', 'v.display_request')
                        ->orderBy('v.created_at', 'desc')
                        ->get()
                        ->map(function ($event) use ($user, $formatIndianNumber, $safe) {

                            // Event closed keyword
                            $event->event_closed = ($event->display_request == '0') ? 'Event is closed' : null;

                            // Format event date
                            $formattedEventDate = null;
                            if (!empty($event->event_date)) {
                                try {
                                    $dateObj = \Carbon\Carbon::createFromFormat('d-m-Y', $event->event_date);
                                    $formattedEventDate = $dateObj->format('jS F, Y');
                                } catch (\Exception $e) {
                                    $formattedEventDate = $event->event_date;
                                }
                            }

                            $event->event_name = $event->event_name
                                ? translateEventName($event->event_name)
                                : null;

                            $event->event_state = $event->event_state
                                ? translateState($event->event_state)
                                : null;

                            $event->event_location = $event->event_location
                                ? translateVenueLocation($event->event_location)
                                : null;

                            $event->event_remarks = $event->event_remarks
                                ? transliterateTextKeepNumbers($event->event_remarks)
                                : null;
                            $event->total_budget = '₹ ' . $formatIndianNumber($event->total_budget) . ' /-';

                            // Event-level services summary
                            $eventServices = DB::table('user_selected_services')
                                ->where('servicedetail_id', $event->id)
                                ->where('user_id', $user->id)
                                ->select('category', 'total_budget', 'others', 'special_requirements', 'sub_content', 'sub_services')
                                ->get()
                                ->map(function ($srv) use ($formatIndianNumber, $safe) {
                                    $decodedSubServices = [];
                                    $totalBudget = (float) ($srv->total_budget ?? 0);

                                    if (!empty($srv->sub_services)) {
                                        $decoded = json_decode($srv->sub_services, true);
                                        if (is_array($decoded) && count($decoded) > 0) {
                                            $selectedServices = array_filter($decoded, fn($sub) => isset($sub['selected']) && $sub['selected'] === true);
                                            $selectedCount = count($selectedServices);
                                            $splitBudget = $selectedCount > 0 ? ($totalBudget / $selectedCount) : 0;

                                            $decodedSubServices = array_map(function ($sub) use ($safe, $splitBudget, $formatIndianNumber) {
                                                return [
                                                    'service_name' => isset($sub['service_name']) && $sub['service_name']
                                                        ? t($sub['service_name'])
                                                        : null,

                                                    'service_budget' => '₹ ' . $formatIndianNumber($splitBudget) . ' /-',
                                                    'selected' => $sub['selected'] ?? false,
                                                    'image_path' => $safe($sub['image_path'] ?? null),
                                                ];
                                            }, $decoded);
                                        }
                                    }

                                    return [
                                        'category' => $srv->category
                                                        ? t($srv->category)
                                                        : null,

                                                    'total_budget' => '₹ ' . $formatIndianNumber($srv->total_budget) . ' /-',

                                                    'others' => $safe($srv->others),

                                                    'special_requirements' => $srv->special_requirements
                                                        ? transliterateTextKeepNumbers($srv->special_requirements)
                                                        : null,

                                                    'sub_content' => $srv->sub_content
                                                        ? t($srv->sub_content)
                                                        : null,

                                                    'sub_services' => $decodedSubServices
                                    ];
                                });

                            $event->event_services_summary = ($eventServices->isEmpty()) ? [] : $eventServices;

                            // Helper: Format planner/vendor response data
                            $formatPlannerData = function ($plannerItems) use ($event, $formatIndianNumber, $safe) {
                                if ($plannerItems->isEmpty()) return [];

                                $plannersList = [];
                                foreach ($plannerItems->groupBy('planner_id') as $plannerId => $plannerData) {
                                    $plannerUser = DB::table('users')->where('id', $plannerId)->first();
                                    $categoriesList = [];

                                    foreach ($plannerData as $itm) {
                                        $servicesOffered = [];

                                        if (!empty($itm->sub_services)) {
                                            $subServices = json_decode($itm->sub_services, true);
                                            if (is_array($subServices) && count($subServices) > 0) {
                                                $selectedServices = array_filter($subServices, fn($srv) => isset($srv['selected']) && $srv['selected'] === true);
                                                $selectedCount = count($selectedServices);
                                                $splitBudget = $selectedCount > 0 ? ($itm->total_budget / $selectedCount) : 0;

                                                $servicesOffered = array_map(function ($srv) use ($safe, $splitBudget, $formatIndianNumber) {
                                                    return [
                                                        'service_name' => $safe($srv['service_name'] ?? null),
                                                        'service_budget' => '₹ ' . $formatIndianNumber($splitBudget) . ' /-',
                                                        'image_path' => $safe($srv['image_path'] ?? null)
                                                    ];
                                                }, $selectedServices);
                                            }
                                        }

                                        $sentTime = !empty($itm->created_at)
                                            ? \Carbon\Carbon::parse($itm->created_at)->format('d-m-Y H:i:s')
                                            : null;

                                        $categoriesList[] = [
                                            'accepted_id' => $safe($itm->id ?? null),
                                            'sent_time' => $safe($sentTime),
                                            'category' => $safe($itm->category),
                                            'service_budget' => '₹ ' . $formatIndianNumber($itm->total_budget) . ' /-',
                                            'others' => $safe($itm->others),
                                            'special_requirements' => $safe($itm->special_requirements),
                                            'sub_content' => $safe($itm->sub_content),
                                            'service_heading' => 'Services Offered',
                                            'services_offered' => $servicesOffered
                                        ];
                                    }

                                    $plannersList[] = [
                                        'event_id' => $event->id,
                                        'planner_id' => $plannerUser->id ?? null,
                                        'planner_business_name' => $safe($plannerUser->business_name ?? null),
                                        'contact_person' => $safe($plannerUser->mobile ?? null),
                                        'profile_details' => [
                                            'business_name' => $safe($plannerUser->business_name ?? null),
                                            'contact_person_name' => $safe($plannerUser->name ?? null),
                                            'mobile' => $safe($plannerUser->mobile ?? null),
                                            'specialization' => $safe($plannerUser->specialization ?? null),
                                            'business_years' => $safe($plannerUser->business_years ?? null),
                                            'completed_events' => $safe($plannerUser->completed_events ?? null),
                                            'rating' => 10,
                                            'state' => $safe($plannerUser->user_lead_state_name ?? null),
                                            'city' => $safe($plannerUser->city ?? null)
                                        ],
                                        'event_name' => $event->event_name,
                                        'event_date' => $event->event_date,
                                        'event_state' => $event->event_state,
                                        'event_location' => $event->event_location,
                                        'event_remarks' => $event->event_remarks,
                                        'total_budget_of_the_event' => '₹ ' . $formatIndianNumber($event->total_budget) . ' /-',
                                        'categories' => $categoriesList
                                    ];
                                }

                                return count($plannersList) > 0 ? $plannersList : [];
                            };

                            // Fetch planner/vendor responses
                            if ($event->display_request == '0') {
                                $listed_vendor_response = [];
                                $listed_planner_response = [];
                            } else {
                                $listed_vendor_response = $formatPlannerData(
                                    DB::table('accepted_vendor_requests')
                                        ->where('event_id', $event->id)
                                        ->where(function ($q) {
                                            $q->whereNull('selected_person')->orWhere('selected_person', '!=', '1');
                                        })
                                        ->where('planner_category', '!=', 'wedding')
                                        ->get()
                                );

                                $listed_planner_response = $formatPlannerData(
                                    DB::table('accepted_vendor_requests')
                                        ->where('event_id', $event->id)
                                        ->where('planner_category', 'wedding')
                                        ->where(function ($q) {
                                            $q->whereNull('selected_person')->orWhere('selected_person', '!=', '1');
                                        })
                                        ->get()
                                );
                            }

                            $selected_vendor_list = $formatPlannerData(
                                DB::table('accepted_vendor_requests')
                                    ->where('event_id', $event->id)
                                    ->where('selected_person', '1')
                                    ->where('planner_category', '!=', 'wedding')
                                    ->get()
                            );

                            $selected_planner_list = $formatPlannerData(
                                DB::table('accepted_vendor_requests')
                                    ->where('event_id', $event->id)
                                    ->where('planner_category', 'wedding')
                                    ->where('selected_person', '1')
                                    ->get()
                            );

                            // Count totals based on display_request
                            if ($event->display_request == '0') {
                                $event->total_response = DB::table('accepted_vendor_requests')
                                    ->where('event_id', $event->id)
                                    ->whereNotNull('selected_person')
                                    ->count();

                                $event->planner_count = DB::table('accepted_vendor_requests')
                                    ->where('event_id', $event->id)
                                    ->where('planner_category', 'wedding')
                                    ->whereNotNull('selected_person')
                                    ->count();

                                $event->vendor_count = DB::table('accepted_vendor_requests')
                                    ->where('event_id', $event->id)
                                    ->where('planner_category', '!=', 'wedding')
                                    ->whereNotNull('selected_person')
                                    ->count();
                            } else {
                                $event->total_response = DB::table('accepted_vendor_requests')
                                    ->where('event_id', $event->id)
                                    ->count();

                                $event->planner_count = DB::table('accepted_vendor_requests')
                                    ->where('event_id', $event->id)
                                    ->where('planner_category', 'wedding')
                                    ->count();

                                $event->vendor_count = DB::table('accepted_vendor_requests')
                                    ->where('event_id', $event->id)
                                    ->where('planner_category', '!=', 'wedding')
                                    ->count();
                            }

                            // Always return [] instead of null
                            $event->listed_vendor_response = $listed_vendor_response;
                            $event->listed_planner_response = $listed_planner_response;
                            $event->selected_vendor_list = $selected_vendor_list;
                            $event->selected_planner_list = $selected_planner_list;

                            return $event;
                        });

                    return response()->json([
                        'message' => t('Events Listing'),
                        'status' => '1',
                        'data' => $events,
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                        'base_url' => 'https://planawedding.in/storage/',
                    ], 200);
                }

        public function deleteplannerevents(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                            'message' => t('User not found'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => "",
                            'logged_in_user' => [],
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 401);
                    }

                    $user_details = [
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name' => $user->business_name
                    ];

                    $useraccess = $this->checkeditaccess($token);
                    $user_role = $useraccess['role'];

                    $rules = [
                        'event_id' => 'required|numeric',
                    ];

                    $validator = Validator::make($request->all(), $rules);
                    if ($validator->fails()) {
                        $errors = $validator->errors()->toArray();

                        // 🌐 Translate each validation message
                        foreach ($errors as $field => &$messages) {
                            foreach ($messages as &$msg) {
                                $msg = t($msg);
                            }
                        }

                        return response()->json([
                            'message' => $errors,
                        ], 422);
                    }

                    $id = $request->event_id;

                    // Find the event
                    $vendorevent = VendorMarketPlaceEvent::where('id', $id)->where('user_id', $user->id)->first();
                    if (!$vendorevent) {
                        return response()->json([
                            'message' => t('Event not found'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 404);
                    }

                    // Step 1: Get all user_selected_services linked to this event
                    $userServices = UserSelectedService::where('servicedetail_id', $id)->get();

                    if ($userServices->isNotEmpty()) {
                        foreach ($userServices as $service) {
                            // Step 2: Delete sub-services mapped to each service
                            UserSelectedSubService::where('servicedetail_id', $id)
                                ->where('user_selected_service_id', $service->id)
                                ->delete();
                        }

                        // Step 3: Delete all user_selected_services linked to this event
                        UserSelectedService::where('servicedetail_id', $id)->delete();
                    }

                    // Step 4: Delete the event itself
                    $vendorevent->delete();

                    return response()->json([
                        'message' => t('Event and related service data deleted successfully'),
                        'status' => '1',
                        'data' => "",
