        public function listmeevents(Request $request)
                {
                    // ----------------- HELPER FUNCTIONS -----------------
                    $formatINR = function($amount) {
                        if ($amount === null) return "₹0.00";
                        $decimal = number_format($amount, 2, '.', '');
                        $expl = explode('.', $decimal);
                        $num = $expl[0];
                        $dec = $expl[1];
                        $len = strlen($num);
                        if($len > 3){
                            $last3digits = substr($num, -3);
                            $restUnits = substr($num, 0, -3);
                            $restUnits = preg_replace("/\B(?=(\d{2})+(?!\d))/", ",", $restUnits);
                            $num = $restUnits . "," . $last3digits;
                        }
                        return "₹" . $num . "." . $dec;
                    };

                    // Profit formatting in Indian style, no decimals
                    $formatProfit = function($amount) {
                        if ($amount === null || $amount == 0) return "-";
                        $num = floor($amount); // remove decimals
                        $len = strlen($num);
                        if($len > 3){
                            $last3digits = substr($num, -3);
                            $restUnits = substr($num, 0, -3);
                            $restUnits = preg_replace("/\B(?=(\d{2})+(?!\d))/", ",", $restUnits);
                            $num = $restUnits . "," . $last3digits;
                        }
                        return "₹ " . $num . " /-";
                    };

                    // ----------------- GET USER -----------------
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                            'message' => t('User not found'),
                            'status' => '0',
                            'data' => [],
                            'user_id' => "",
                            'user_role' => "",
                            'logged_in_user' => [],
                        ], 401);
                    }

                    $user_details = [
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name'=> $user->business_name
                    ];

                    $useraccess = $this->checkeditaccess($token);
                    $user_role = $useraccess['role'];
                    $user_id = $user->id;

                    $page_i_content = ['show' =>1,'name' => t('Check your Events')];

                    // ----------------- VALIDATION -----------------
                    $validator = Validator::make($request->all(), [
                        'type' => 'required|string|in:pagelisting,monthlylisting',
                        'month' => 'required_if:type,monthlylisting',
                        'year' => 'required_if:type,monthlylisting|digits:4|integer',
                        'search' => 'nullable|string',
                        'paginate' => 'nullable|string|in:true,false',
                    ]);

                    if ($validator->fails()) {
                        $errors = $validator->errors()->toArray();

                        // 🌐 Translate each validation message
                        foreach ($errors as $field => &$messages) {
                            foreach ($messages as &$msg) {
                                $msg = t($msg);
                            }
                        }

                        return response()->json([
                            'message' => $errors,
                        ], 422);
                    }

                    // ----------------- INPUTS -----------------
                    $type = $request->input('type');
                    $search = $request->input('search');
                    $paginate = $request->input('paginate', 'true');
                    $monthInput = $request->input('month');
                    $yearInput = $request->input('year');
                    $allowsearch = !empty($search);

                    $page_heading= ['show' =>1,'name' => t('My Events'),];

                    // ----------------- FORMAT EVENTS -----------------
                    $formatEvents = function($query, $isMonthly = false) use ($paginate, $formatINR, $formatProfit) {
                        $data = ($paginate === "false") ? $query->get() : $query->paginate(30);
                        $collection = ($paginate === "false") ? $data : $data->getCollection();

                        $collection->transform(function($item) use ($formatINR, $formatProfit, $isMonthly) {

                            // ---------- Event Name (transliterate) ----------
                            $item->event_name = $item->event_name !== "-"
                                ? translateEventName($item->event_name)
                                : "-";

                            // ---------- Event Status ----------
                            $eventStatus = $item->event_status !== "-" ? $item->event_status : null;

                            $item->event_status_value = $eventStatus;
                            $item->event_status_show  = $eventStatus ? t($eventStatus) : "-";

                            unset($item->event_status);

                            // ---------- Vendors Count (translate only word) ----------
                            if ($item->total_vendors !== "-" && preg_match('/^(\d+)\s+Vendors$/', $item->total_vendors, $m)) {
                                $item->total_vendors = $m[1] . ' ' . t('Vendors');
                            }

                            // ---------- PROFIT CALCULATION (RESTORED CORRECTLY) ----------

                            // event budget (numeric only)
                            $eventBudget = is_numeric($item->total_budget ?? null)
                                ? (float) $item->total_budget
                                : 0;

                            // vendor total
                            $vendorCost = $item->vendors()->sum('total_budget');

                            // profit amount
                            $profitAmount = $eventBudget - $vendorCost;

                            // formatted profit
                            $item->profit_amount = $formatProfit($profitAmount);

                            // profit type (value + translated show)
                            if ($profitAmount > 0) {
                                $item->profit_type_value = 'profit';
                                $item->profit_type_show  = t('profit');
                            } elseif ($profitAmount < 0) {
                                $item->profit_type_value = 'loss';
                                $item->profit_type_show  = t('loss');
                            } else {
                                $item->profit_type_value = null;
                                $item->profit_type_show  = '-';
                            } 



                            // ---------- Vendors Count (RESTORE FIELD) ----------
                            $vendorsCount = $item->vendors()->count();

                            if ($vendorsCount > 0) {
                                $item->total_vendors = $vendorsCount . ' ' . t('Vendors');
                            } else {
                                $item->total_vendors = '-';
                            }


                            return $item;
                        });


                        return $data;
                    };

                    // ----------------- COMPUTE STATS -----------------
                    $computeStats = function($planner_id, $month = null, $year = null) use ($formatINR, $formatProfit) {
                        $queryMonth = $month ? "MONTH(STR_TO_DATE(event_date, '%d-%m-%Y')) = $month" : "1=1";
                        $queryYear = $year ? "YEAR(STR_TO_DATE(event_date, '%d-%m-%Y')) = $year" : "1=1";

                        $totalEvents = MyEvent::where('planner_id',$planner_id)
                            ->whereRaw($queryMonth)
                            ->whereRaw($queryYear)
                            ->count();

                        $totalBudget = MyEvent::where('planner_id',$planner_id)
                            ->whereRaw($queryMonth)
                            ->whereRaw($queryYear)
                            ->sum('total_budget');

                        $vendorPayouts = DB::table('vendor_events_myvendors as vemv')
                            ->join('vendor_events as ve','ve.id','=','vemv.event_id')
                            ->where('ve.planner_id', $planner_id)
                            ->whereRaw($queryMonth)
                            ->whereRaw($queryYear)
                            ->sum('vemv.total_budget');

                        $profit = $totalBudget - $vendorPayouts;

                        return [
                            'total_events' => $totalEvents,
                            'total_budget' => $formatINR($totalBudget),
                            'profit' => $formatProfit($profit),
                            'profit_percentage' => $totalBudget > 0 ? number_format(($profit/$totalBudget)*100,2,'.','') : "0.00"
                        ];
                    };

                    // ----------------- PAGELISTING -----------------
                    if ($type === "pagelisting") {
                        $query = MyEvent::where('planner_id', $user_id)
                            ->when($allowsearch, function ($q) use ($search) {
                                $q->where(function ($sub) use ($search) {
                                    $sub->where('event_name', 'like', '%' . $search . '%')
                                        ->orWhere('event_date', 'like', '%' . $search . '%')
                                        ->orWhere('total_budget', 'like', '%' . $search . '%')
                                        ->orWhere('event_status', 'like', '%' . $search . '%');
                                });
                            })
                            ->orderBy('id', 'desc');

                        $data = $formatEvents($query, false);
                        $stats = $computeStats($user_id, null, Carbon::now()->year);

                        $responseData = ($paginate === "false") ? [
                            'events' => $data->toArray(),
                            'total_events_this_year' => $stats['total_events'],
                            'current_year' => Carbon::now()->year,
                            'profit_this_year' => $stats['profit'],
                            'total_budget_this_year' => $stats['total_budget'],
                            'profit_percentage' => $stats['profit_percentage']
                        ] : $data->toArray() + [
                            'total_events_this_year' => $stats['total_events'],
                            'current_year' => Carbon::now()->year,
                            'profit_this_year' => $stats['profit'],
                            'total_budget_this_year' => $stats['total_budget'],
                            'profit_percentage' => $stats['profit_percentage']
                        ];

                        return response()->json([
                            'message' => t('My Events'),
                            'status' => '1',
                            'data' => $responseData,
                            'page_heading' => $page_heading,
                            'page_i_content' => $page_i_content,
                            'user_id' => $user->id,
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 200);
                    }

                    // ----------------- MONTHLYLISTING -----------------
                    if ($type === "monthlylisting") {
                        $yearNumber = (int)$request->input('year');

                        if (!is_numeric($monthInput)) {
                            try {
                                $dateObj = \DateTime::createFromFormat('!F', ucfirst(strtolower($monthInput)));
                                if (!$dateObj) throw new \Exception("Invalid month name");
                                $monthNumber = (int) $dateObj->format('m');
                                $monthFullName = $dateObj->format('F');
                            } catch (\Exception $e) {
                                return response()->json([
                                    'message' => t('Invalid month input'),
                                    'status' => '0',
                                ], 200);
                            }
                        } else {
                            $monthNumber = (int)$monthInput;
                            if ($monthNumber < 1 || $monthNumber > 12) {
                                return response()->json([
                                    'message' => t('Invalid month number'),
                                    'status' => '0',
                                ], 200);
                            }
                            $monthFullName = Carbon::create()->month($monthNumber)->format('F');
                        }

                        $page_heading = [
                            'show' => 1,
                            'name' => t('Details for') . ' ' . t($monthFullName) . ' - ' . $yearNumber,
                        ];

                        $query = MyEvent::where('planner_id', $user_id)
                            ->whereRaw("MONTH(STR_TO_DATE(event_date, '%d-%m-%Y')) = ?", [$monthNumber])
                            ->whereRaw("YEAR(STR_TO_DATE(event_date, '%d-%m-%Y')) = ?", [$yearNumber])
                            ->orderBy('id','desc')
                            ->when($allowsearch, function($q) use($search){
                                $q->where(function($sub) use($search){
                                    $sub->where('event_name','like','%'.$search.'%')
                                        ->orWhere('event_date','like','%'.$search.'%')
                                        ->orWhere('total_budget','like','%'.$search.'%')
                                        ->orWhere('event_status','like','%'.$search.'%');
                                });
                            });

                        $data = $formatEvents($query, true);

                        $totalEventsThisMonth = MyEvent::where('planner_id',$user_id)
                            ->whereRaw("MONTH(STR_TO_DATE(event_date, '%d-%m-%Y')) = ?", [$monthNumber])
                            ->whereRaw("YEAR(STR_TO_DATE(event_date, '%d-%m-%Y')) = ?", [$yearNumber])
                            ->count();

                        $totalBudgetThisMonth = MyEvent::where('planner_id',$user_id)
                            ->whereRaw("MONTH(STR_TO_DATE(event_date, '%d-%m-%Y')) = ?", [$monthNumber])
                            ->whereRaw("YEAR(STR_TO_DATE(event_date, '%d-%m-%Y')) = ?", [$yearNumber])
                            ->sum('total_budget');

                        $vendorPayouts = DB::table('vendor_events_myvendors as vemv')
                            ->join('vendor_events as ve','ve.id','=','vemv.event_id')
                            ->where('ve.planner_id', $user_id)
                            ->whereRaw("MONTH(STR_TO_DATE(ve.event_date, '%d-%m-%Y')) = ?", [$monthNumber])
                            ->whereRaw("YEAR(STR_TO_DATE(ve.event_date, '%d-%m-%Y')) = ?", [$yearNumber])
                            ->sum('vemv.total_budget');

                        $profitThisMonth = $totalBudgetThisMonth - $vendorPayouts;
                        $profitFormatted = $formatProfit($profitThisMonth);

                        $profitPercentage = ($totalBudgetThisMonth > 0) 
                            ? number_format(($profitThisMonth/$totalBudgetThisMonth)*100,2,'.','') 
                            : "0.00";

                        $averageBudget = $totalEventsThisMonth > 0 ? round($totalBudgetThisMonth / $totalEventsThisMonth, 2) : 0;

                        $responseData = ($paginate === "false") ? [
                            'events' => $data->toArray(),
                            'total_events_this_month' => $totalEventsThisMonth,
                            'year' => $yearNumber,
                            'month' => $monthNumber,
                            'average_monthly_budget' => $formatINR($averageBudget),
                            'profit_this_month' => $profitFormatted,
                            'total_budget_this_month' => $formatINR($totalBudgetThisMonth),
                            'profit_percentage' => $profitPercentage
                        ] : $data->toArray() + [
                            'total_events_this_month' => $totalEventsThisMonth,
                            'year' => $yearNumber,
                            'month' => $monthNumber,
                            'average_monthly_budget' => $formatINR($averageBudget),
                            'profit_this_month' => $profitFormatted,
                            'total_budget_this_month' => $formatINR($totalBudgetThisMonth),
                            'profit_percentage' => $profitPercentage
                        ];

                        return response()->json([
                            'message' => t('My Events - Monthly Listing'),
                            'status' => '1',
                            'data' => $responseData,
                            'page_heading' => $page_heading,
                            'page_i_content' => $page_i_content,
                            'user_id' => $user->id,
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 200);
                    }

                    // ----------------- DEFAULT -----------------
                    return response()->json([
                        'message' => t('Invalid type'),
                        'status' => '0',
                        'data' => [],
                    ], 422);
                }
