        public function singleeventlisting(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                            'message' => 'User not found',
                            'status' => '0',
                            'data' => [],
                            'user_role' => "",
                            'logged_in_user' => [],
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 401);
                    }

                    $user_details = [
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name'=> $user->business_name
                    ];                    

                    $useraccess = $this->checkeditaccess($token);
                    $user_role = $useraccess['role'];

                    
                    $page_heading = [
                        'show' => 1,
                        'name' => t('My Events'),
                    ];

                    $page_i_content = [
                        'show' => 1,
                        'name' => t('Check your Events for the Year'),
                    ];

                    $item_id = $request->id;

                    if (empty($item_id)) {
                        return response()->json([
                            'message' => 'Event id is mandatory',
                            'status' => '0',
                            'data' => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 400);
                    }

                    // get event
                    $event = MyEvent::where('id', $item_id)->latest()->first();

                    if (!$event) {
                        return response()->json([
                            'message' => 'Not able to find Item',
                            'status' => '0',
                            'data' => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 503);
                    }

                    $page_heading = [
                        'show' => 1,
                        'name' => translateEventName($event->event_name ?? t('My Events')),
                    ];

                    $page_i_content = [
                        'show' => 1,
                        'name' => t('Check details for') . ' ' . translateEventName($event->event_name),
                    ];


                    // fetch vendors
                    $vendors = MyVendor::where('event_id', $item_id)
                        ->orderByDesc('id')
                        ->get()
                        ->map(function ($vendor) {
                            $total_budget = (float) $vendor->total_budget;
                            $advance_paid = (float) $vendor->advance_paid;

                            $balance_due = $total_budget - $advance_paid;
                            $status = $balance_due == 0 ? "Paid" : "Pending";

                            // profit for this vendor = total_budget - advance_paid (or actual cost if you have)
                            $profit_amount = $total_budget - $advance_paid;
                            $profit_percentage = $total_budget > 0
                                ? number_format(($profit_amount / $total_budget) * 100, 2, '.', '')
                                : "0.00";

                            // payment dates
                            $payment = MyPayment::where('vendor_id', $vendor->id)
                                ->orderByDesc('id')
                                ->first();

                            return [
                                'vendor_id'           => $vendor->id ?? '-',
                                'event_id'            => $vendor->event_id ?? '-',
                                'vendor_type_value'   => $vendor->vendor_type ?? '-',
                                'vendor_type_display' => $vendor->vendor_type
                                    ? t($vendor->vendor_type)
                                    : '-',
                                // ✅ Vendor name
                                'vendor_name_value'   => $vendor->vendor_name ?? '-',
                                'vendor_name_display' => $vendor->vendor_name
                                    ? transliterateTextKeepNumbers($vendor->vendor_name)
                                    : '-',
                                // ✅ Contact person
                                'contact_person_value'   => $vendor->contact_person ?? '-',
                                'contact_person_display' => $vendor->contact_person
                                    ? transliterateTextKeepNumbers($vendor->contact_person)
                                    : '-',
                                'mobile_number'       => $vendor->mobile_number ?? '-',
                                'email_id'            => $vendor->email_id ?? '-',
                                // ✅ Scope of work
                                'scope_of_work_value'   => $vendor->scope_of_work ?? '-',
                                'scope_of_work_display' => $vendor->scope_of_work
                                    ? transliterateTextKeepNumbers($vendor->scope_of_work)
                                    : '-',
                                'total_budget'        => number_format($total_budget, 2),
                                'advance_paid'        => number_format($advance_paid, 2),
                                'balance_due'         => "₹".number_format($balance_due, 2),
                                'status_value'        => $status,
                                'status_display'      => t($status),
                                'advance_paid_date'   => $payment->advance_paid_date ?? '-',
                                'balance_due_date'    => $payment->balance_due_date ?? '-',
                                'service_date'         => $vendor->service_date ?? '-',
                                'profit_earned'       => [
                                    'amount'     => "₹".number_format($profit_amount, 2),
                                    'percentage' => $profit_percentage . "%"
                                ]
                            ];
                        });

                    $total_no_of_vendors = $vendors->count();

                    // total payment to vendors
                    $total_payment_made_to_vendors = MyVendor::where('event_id', $item_id)->sum('total_budget');

                    // total profit for event
                    $profit_earned_amount = (float) $event->total_budget - (float) $total_payment_made_to_vendors;
                    $profit_earned_percentage = $event->total_budget > 0
                        ? number_format(($profit_earned_amount / $event->total_budget) * 100, 2, '.', '')
                        : "0.00";

                    $event_listing = [
                        'event_id'                     => $event->id,
                        'event_name'                   => translateEventName($event->event_name),
                        'event_date'                   => $event->event_date,
                        'full_event_date'              => \Carbon\Carbon::createFromFormat('d-m-Y', $event->event_date)->format('F j, Y'),
                        'total_budget'                 => "₹".number_format($event->total_budget, 2),
                        'event_status_value'           => $event->event_status ?? '-',
                        'event_status_display'         => $event->event_status ? t($event->event_status): '-',
                        'vendors'                      => $vendors,
                        'total_no_of_vendors'          => $total_no_of_vendors,
                        'total_payment_made_to_vendors'=> "₹".number_format($total_payment_made_to_vendors, 2),
                        'profit_earned'                => [
                            'amount'     => "₹".number_format($profit_earned_amount, 2),
                            'percentage' => $profit_earned_percentage . "%"
                        ],
                    ];

                    return response()->json([
                        'message' => t('Single Event Listing'),
                        'status' => '1',
                        'data' => $event_listing,
                        'page_heading' => $page_heading,
                        'page_i_content' => $page_i_content,
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details, 
                        'base_url' => 'https://planawedding.in/storage/',
                    ], 200);
                }
