        public function eventyearlyprofit(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                            'message' => t('User not found'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => "",
                            'logged_in_user' => [],
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 401);
                    }

                    $user_details = [
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name'=> $user->business_name
                    ];

                    $useraccess = $this->checkeditaccess($token);
                    $user_role = $useraccess['role'];
                    $user_id = $user->id;

                    // Validation
                    $validator = Validator::make($request->all(), [ 
                        'year' => 'required|digits:4|integer',
                    ]);

                    if ($validator->fails()) {
                            

                        $errors = $validator->errors()->toArray();

                        // 🌐 Translate each validation message
                        foreach ($errors as $field => &$messages) {
                            foreach ($messages as &$msg) {
                                $msg = t($msg);
                            }
                        }

                        return response()->json([
                            'message' => $errors,
                        ], 200);
                    }
                    $lang = app()->getLocale();

                    $year = (int)$request->input('year');

                    // Helper: Indian currency formatting
                    $formatINR = function($amount) {
                        return '₹' . number_format((float)$amount, 2, '.', ',');
                    };

                    $yearlyEventsTotal = 0;
                    $yearlyTotalBudget = 0;
                    $yearlyVendorPayouts = 0;
                    $monthlyData = [];

                    for ($m = 1; $m <= 12; $m++) {
                        $monthNumber = str_pad($m, 2, '0', STR_PAD_LEFT);

                        $monthNameValue = Carbon::create()->month($m)->format('F');
                        $monthNameDisplay = uiFast($monthNameValue);


                        // Default monthly values
                        $monthEvents = [];
                        $monthlyTotalBudget = null;
                        $monthlyVendorPayouts = null;
                        $monthlyProfitLossAmount = null;
                        $monthlyProfitLossType = null;

                        // Fetch events for this month
                        $events = DB::table('vendor_events')
                            ->select('id as event_id', 'event_name', 'total_budget', 'event_date')
                            ->where('planner_id', $user_id)
                            ->whereRaw("MONTH(STR_TO_DATE(event_date, '%d-%m-%Y')) = ?", [$m])
                            ->whereRaw("YEAR(STR_TO_DATE(event_date, '%d-%m-%Y')) = ?", [$year])
                            ->get();

                        if (!$events->isEmpty()) {
                            // Map events to include profit/loss per event
                            $monthEvents = $events->map(function($event) use ($formatINR) {

                                // Event name
                                $event->event_name_value = $event->event_name;
                                $event->event_name_display = translateEventName($event->event_name);

                                unset($event->event_name);

                                $vendorBudget = DB::table('vendor_events_myvendors')
                                    ->where('event_id', $event->event_id)
                                    ->sum('total_budget');

                                $profitAmount = $event->total_budget - $vendorBudget;
                                $event->profit_amount = $formatINR($profitAmount);
                                $profitType = $profitAmount >= 0 ? "Profit" : "Loss";

                                $event->profit_type_value = $profitType;
                                $event->profit_type_display = uiFast($profitType);


                                return $event;
                            });

                            $monthlyTotalBudget = $events->sum('total_budget');

                            // Vendor payouts for the month
                            $monthlyVendorPayouts = DB::table('vendor_events_myvendors as vemv')
                                ->join('vendor_events as ve','ve.id','=','vemv.event_id')
                                ->where('ve.planner_id', $user_id)
                                ->whereRaw("MONTH(STR_TO_DATE(ve.event_date, '%d-%m-%Y')) = ?", [$m])
                                ->whereRaw("YEAR(STR_TO_DATE(ve.event_date, '%d-%m-%Y')) = ?", [$year])
                                ->sum('vemv.total_budget');

                            $monthlyProfitLoss = $monthlyTotalBudget - $monthlyVendorPayouts;
                            $monthlyProfitLossAmount = $formatINR($monthlyProfitLoss);
                            $monthlyProfitLossTypeValue = $monthlyProfitLoss >= 0 ? "Profit" : "Loss";
                            $monthlyProfitLossTypeDisplay = uiFast($monthlyProfitLossTypeValue);

                        }

                        // Update yearly totals (only numeric values)
                        $yearlyEventsTotal += $events->count();
                        $yearlyTotalBudget += is_numeric($monthlyTotalBudget) ? $monthlyTotalBudget : 0;
                        $yearlyVendorPayouts += is_numeric($monthlyVendorPayouts) ? $monthlyVendorPayouts : 0;

                        $monthlyData[] = [
                            'month_number' => $monthNumber,
                            'month_name_value'   => $monthNameValue,
                            'month_name_display' => $monthNameDisplay,
                            'events' => $monthEvents,
                            'monthly_total_budget' => is_numeric($monthlyTotalBudget) ? $formatINR($monthlyTotalBudget) : null,
                            'monthly_vendor_payouts' => is_numeric($monthlyVendorPayouts) ? $formatINR($monthlyVendorPayouts) : null,  
                            'monthly_profit_loss_amount' => $monthlyProfitLossAmount,
                            'monthly_profit_loss_type_value'   => $monthlyProfitLossTypeValue ?? null,
                            'monthly_profit_loss_type_display' => $monthlyProfitLossTypeDisplay ?? null,
                        ];
                    }

                    // Yearly profit/loss
                    $yearlyProfitLoss = $yearlyTotalBudget - $yearlyVendorPayouts;
                    $yearlyProfitLossAmount = $formatINR(abs($yearlyProfitLoss));
                    $yearlyProfitLossType = $yearlyProfitLoss >= 0 ? "Profit" : "Loss";
                    $averageMonthly = $yearlyEventsTotal > 0 ? round($yearlyTotalBudget / 12, 2) : 0;

                    // Page heading & info content
                    $page_heading = [
                        'show' => 1,
                        'name' => t("My Events")
                    ];

                    $page_i_content = [
                        'show' => 1,
                        'name' => t('Profit List') . ' - ' . $year
                    ];

                    return response()->json([
                        'message' => t('Yearly Event Profit & Loss'),
                        'status' => '1',
                        'data' => [
                            'monthly' => $monthlyData,
                            'total_no_of_events' => $yearlyEventsTotal,
                            'yearly_total_budget' => $formatINR($yearlyTotalBudget),
                            'yearly_vendor_payouts' => $formatINR($yearlyVendorPayouts),
                            'yearly_profit_loss_amount' => $yearlyProfitLossAmount,
                            'yearly_profit_loss_type' => $yearlyProfitLossType,
                            'average_monthly_budget' => $formatINR($averageMonthly)
                        ],
                        'page_heading' => $page_heading,
                        'page_i_content' => $page_i_content,
                        'user_id' => $user->id,
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                        'base_url' => 'https://planawedding.in/storage/',
                    ], 200);
                }

        public function addeditvendors(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);

                    if($user) 
                        {
                            $user_details = ['name' => $user->name,'email' => $user->email,'mobile' => $user->mobile,'business_name'=> $user->business_name];                    
                            $useraccess = $this->checkeditaccess($token);
                            $user_role = $useraccess['role'];
                            $user_access_array = $useraccess['access_array'];

                            $rules = [
                                'type'        => 'required',                                
                            ];

                            $validator = Validator::make($request->all(), $rules);

                            if($validator->fails())
                                {
                                    $errors = $validator->errors()->toArray();

                                    // 🌐 Translate each validation message
                                    foreach ($errors as $field => &$messages) {
                                        foreach ($messages as &$msg) {
                                            $msg = t($msg);
                                        }
                                    }

                                    return response()->json([
                                        'message' => $errors,
                                    ], 422);
                                } 
                            else 
                                {
                                    $type = $request->type;

                                    $page_heading= ['show' =>1,'name' =>uiFast('My Events')];
                                                    
                                    $page_i_content = ['show' =>1,'name' => uiFast('Check your Events for the Year')];

                                    $user_id = $user->id;


                                    if($type == "add")
                                        {
                                            $rules =
                                                [
                                                    'event_id'         => 'required|numeric', 
                                                    'vendor_type'        => 'required',
                                                    'vendor_name'        => 'required',
                                                    'contact_person'      => 'required',
                                                    'mobile_number'         => 'required|numeric', 
                                                    //'email_id'         => 'required|email', 
                                                    'scope_of_work'        => 'required',
                                                    'total_budget'        => 'required|numeric',   
                                                    'advance_paid'   => 'nullable|numeric', // not mandatory
                                                ];

                                            $validator = Validator::make($request->all(), $rules);

                                            // extra check: advance_paid < total_budget
                                            $validator->after(function ($validator) use ($request) {
                                                if (!is_null($request->advance_paid)) {
                                                    if ($request->advance_paid >= $request->total_budget) {
                                                        $validator->errors()->add('advance_paid', 'Advance paid must be less than total budget.');
                                                    }
                                                }
                                            });

                                            if($validator->fails())
                                                {
                                                    // Validation failed
                                                    $errors = $validator->errors()->toArray();

                                                    // 🌐 Translate each validation message
                                                    foreach ($errors as $field => &$messages) {
                                                        foreach ($messages as &$msg) {
                                                            $msg = t($msg);
                                                        }
                                                    }

                                                    return response()->json([
                                                        'message' => $errors,
                                                    ], 422);
                                                } 
                                            else 
                                                {
                                                    $myvendor = new MyVendor();

                                                    $myvendor->planner_id   = $user_id;
                                                    $myvendor->event_id   = $request->event_id;
                                                    $myvendor->vendor_type   = $request->vendor_type;
                                                    $myvendor->vendor_name = $request->vendor_name;

                                                    $myvendor->contact_person = $request->contact_person;
                                                    $myvendor->mobile_number = $request->mobile_number;
                                                    $myvendor->email_id = $request->email_id;
                                                    $myvendor->scope_of_work = $request->scope_of_work;
                                                    $myvendor->total_budget = $request->total_budget;
                                                    $myvendor->advance_paid = $request->advance_paid;

                                                    $myvendor->service_date = $request->service_date;

                                                    $myvendor->first_entry_on   = now()->format('d/m/Y H:i:s');

                                                    if($myvendor->save())
                                                        {


                                                            // Create a payment record linked to this vendor
                                                            $mypayment = new MyPayment();
                                                            $mypayment->planner_id   = $user_id;
                                                            $mypayment->event_id   = $request->event_id;
                                                            $mypayment->vendor_id = $myvendor->id; // link to newly created vendor                                                            
                                                            $mypayment->advance_paid    = $myvendor->advance_paid ?? 0; // if you want to start with advance
                                                            $mypayment->advance_paid_date = $request->advance_paid_date;
                                                            $mypayment->balance_due_date = $request->balance_due_date; 
                                                            $mypayment->entered_on = now()->format('d/m/Y H:i:s');
                                                            //$mypayment->created_by   = $user_id; // optional, if you track who added
                                                            $mypayment->save();

                                                            // 🔹 Translate fields BEFORE response
                                                            $translatedVendor = $myvendor->toArray();

                                                            $translatedVendor['vendor_type'] = domainTranslate($myvendor->vendor_type);

                                                            $translatedVendor['vendor_name'] = transliterateTextKeepNumbers($myvendor->vendor_name);

                                                            $translatedVendor['contact_person'] = transliterateTextKeepNumbers($myvendor->contact_person);

                                                            $translatedVendor['scope_of_work'] = translateLongText($myvendor->scope_of_work);

                                                            
                                                            return response()->json([
                                                                'message' => t('Added Vendor'),
                                                                'status' => '1',
                                                                'data' => $translatedVendor,
                                                                'page_heading' => $page_heading,
                                                                'page_i_content' => $page_i_content,
                                                                'user_role' => $user_role,
                                                                'logged_in_user' => $user_details,
                                                                'base_url' => 'https://planawedding.in/storage/',
                                                            ], 200);
                                                        }
                                                    else 
                                                        {
                                                            return response()->json([
                                                                    'message' => t('Unable to Add Vendor'),
                                                                    'status' => '0',
                                                                    'data' => [],
                                                                    'page_heading' => NULL,
                                                                    'page_i_content' => NULL,
                                                                    'user_role' => $user_role,
                                                                    'logged_in_user' => $user_details,
                                                                    'base_url' => 'https://planawedding.in/storage/',
                                                                ], 200);
                                                        }


                                                }
                                        }
                                    else if($type == "edit")
                                        {
                                            $rules =
                                                [
                                                    'vendor_id'         => 'required|numeric', 
                                                    'event_id'         => 'required|numeric', 
                                                    'vendor_type'        => 'required',
                                                    'vendor_name'        => 'required',
                                                    'contact_person'      => 'required',
                                                    'mobile_number'         => 'required|numeric', 
                                                    //'email_id'         => 'required|email', 
                                                    'scope_of_work'        => 'required',
                                                    'total_budget'        => 'required|numeric',   
                                                    'advance_paid'   => 'nullable|numeric', // not mandatory
                                                ];

                                            $validator = Validator::make($request->all(), $rules);

                                            // extra check: advance_paid < total_budget
                                            $validator->after(function ($validator) use ($request) {
                                                if (!is_null($request->advance_paid)) {
                                                    if ($request->advance_paid >= $request->total_budget) {
                                                        $validator->errors()->add('advance_paid', 'Advance paid must be less than total budget.');
                                                    }
                                                }
                                            });

                                            if($validator->fails())
                                                {
                                                    $errors = $validator->errors()->toArray();

                                                    // 🌐 Translate each validation message
                                                    foreach ($errors as $field => &$messages) {
                                                        foreach ($messages as &$msg) {
                                                            $msg = t($msg);
                                                        }
                                                    }

                                                    return response()->json([
                                                        'message' => $errors,
                                                    ], 422);
                                                } 
                                            else 
                                                {
                                                    $vendor_id = $request->vendor_id;

                                                    $myvendor = MyVendor::where('id',$vendor_id)->latest()->first();  

