                                                        {
                                                            $myvendor->vendor_type   = $request->vendor_type;
                                                            $myvendor->vendor_name = $request->vendor_name;

                                                            $myvendor->contact_person = $request->contact_person;
                                                            $myvendor->mobile_number = $request->mobile_number;
                                                            $myvendor->email_id = $request->email_id;
                                                            $myvendor->scope_of_work = $request->scope_of_work;
                                                            $myvendor->total_budget = $request->total_budget;
                                                            $myvendor->advance_paid = $request->advance_paid;

                                                            $myvendor->service_date = $request->service_date;


                                                            $myvendor->vendor_updated_on   = now()->format('d/m/Y H:i:s');


                                                            if($myvendor->save())
                                                                {


                                                                    // update or create payment
                                                                    $mypayment = MyPayment::where('vendor_id', $vendor_id)->latest()->first();

                                                                    if (!$mypayment) {
                                                                        $mypayment = new MyPayment();
                                                                        $mypayment->vendor_id = $myvendor->id;
                                                                        $mypayment->planner_id = $user_id;
                                                                        $mypayment->event_id   = $request->event_id;
                                                                        $mypayment->entered_on = now()->format('d/m/Y H:i:s');
                                                                    }

                                                                    $mypayment->advance_paid       = $myvendor->advance_paid ?? 0;
                                                                    $mypayment->advance_paid_date  = $request->advance_paid_date;
                                                                    $mypayment->balance_due_date   = $request->balance_due_date;
                                                                    $mypayment->save();

                                                                    // 🔹 Translate fields BEFORE response
                                                                    $translatedVendor = $myvendor->toArray();

                                                                    $translatedVendor['vendor_type'] = domainTranslate($myvendor->vendor_type);

                                                                    $translatedVendor['vendor_name'] = transliterateTextKeepNumbers($myvendor->vendor_name);

