        public function addeditpayment(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                            'message' =>  uiFast('User not found'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => "",
                            'logged_in_user' => [],
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 401);
                    }

                    $user_details = [
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name'=> $user->business_name
                    ];                    

                    $useraccess = $this->checkeditaccess($token);
                    $user_role = $useraccess['role'];

                    $page_heading= ['show' =>1,'name' => "My Events"];
                    $page_i_content = ['show' =>1,'name' => "Check your Events for the Year"];

                    $rules = [
                        'type' => 'required|string',                                
                    ];

                    $validator = Validator::make($request->all(), $rules);

                    if ($validator->fails()) {
                        $errors = $validator->errors()->toArray();

                        // 🌐 Translate each validation message
                        foreach ($errors as $field => &$messages) {
                            foreach ($messages as &$msg) {
                                $msg = t($msg);
                            }
                        }

                        return response()->json([
                            'message' => $errors,
                        ], 422);
                    }

                    $type = $request->type;
                    $user_id = $user->id;

                    if ($type == "add") {
                        $rules = [
                            'vendor_id'         => 'required|numeric', 
                            'event_id'          => 'required|numeric', 
                            'advance_paid'      => 'required|numeric',  
                            'advance_paid_date' => 'required|date_format:d-m-Y',  
                            'balance_due_date'  => 'nullable|date_format:d-m-Y',
                        ];

                        $validator = Validator::make($request->all(), $rules);

                        if ($validator->fails()) {
                            $errors = $validator->errors()->toArray();

                            // 🌐 Translate each validation message
                            foreach ($errors as $field => &$messages) {
                                foreach ($messages as &$msg) {
                                    $msg = t($msg);
                                }
                            }

                            return response()->json([
                                'message' => $errors,
                            ], 422);
                        }

                        // ✅ Check vendor exists
                        $vendor = \DB::table('vendor_events_myvendors')
                                    ->where('id', $request->vendor_id)
                                    ->first();

                        if (!$vendor) {
                            return response()->json([
                                'message' => uiFast('Vendor not found'),
                                'status' => '0',
                            ], 404);
                        }

                        $totalBudget = (float) $vendor->total_budget;
                        $advancePaid = (float) $request->advance_paid;

                        // ✅ Cumulative check: advance_paid + already paid <= total_budget
                        $totalAlreadyPaid = (float) \DB::table('vendor_advance_payment')
                                                ->where('vendor_id', $request->vendor_id)
                                                ->sum('advance_paid');

                        if ($advancePaid + $totalAlreadyPaid > $totalBudget) {
                            return response()->json([
                                'message' => uiFast('Advance paid exceeds vendor total budget'),
                                'status' => '0',
                            ], 200);
                        }

                        // ✅ Create new payment
                        $mypayment = new MyPayment();
                        $mypayment->planner_id        = $user_id;
                        $mypayment->event_id          = $request->event_id;
                        $mypayment->vendor_id         = $request->vendor_id;
                        $mypayment->advance_paid      = $advancePaid;
                        $mypayment->advance_paid_date = $request->advance_paid_date;
                        $mypayment->balance_due_date  = $request->balance_due_date ?? null;
                        $mypayment->entered_on        = now()->format('d/m/Y H:i:s');
                        $mypayment->save();

                        // ✅ Update advance_paid in vendor_events_myvendors
                        \DB::table('vendor_events_myvendors')
                            ->where('id', $request->vendor_id)
                            ->increment('advance_paid', $advancePaid);

                        return response()->json([
                            'message' => uiFast('Payment added successfully'),
                            'status' => '1',
                            'data' => [
                                'payment_id' => $mypayment->id,
                                'vendor_id' => $mypayment->vendor_id,
                                'event_id' => $mypayment->event_id,
                                'advance_paid' => "₹" . number_format($mypayment->advance_paid, 2),
                                'advance_paid_date' => $mypayment->advance_paid_date,
                                'balance_due_date' => $mypayment->balance_due_date ?? "-",
                            ],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                            'page_heading' => $page_heading,
                            'page_i_content' => $page_i_content,
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 200);
                    }

                    // You can extend for $type == "edit" etc.

                    else if ($type == "edit") {
                        $rules = [
                            'vendor_id'         => 'required|numeric', 
                            'event_id'          => 'required|numeric', 
                            'payment_id'        => 'required|numeric',
                            'advance_paid'      => 'required|numeric',  
                            'advance_paid_date' => 'required|date_format:d-m-Y',  
                            'balance_due_date'  => 'nullable|date_format:d-m-Y',
                        ];

                        $validator = Validator::make($request->all(), $rules);

                        if ($validator->fails()) {
                            $errors = $validator->errors()->toArray();

                            // 🌐 Translate each validation message
                            foreach ($errors as $field => &$messages) {
                                foreach ($messages as &$msg) {
                                    $msg = t($msg);
                                }
                            }

                            return response()->json([
                                'message' => $errors,
                            ], 422);
                        }

                        // Check vendor exists
                        $vendor = \DB::table('vendor_events_myvendors')
                                    ->where('id', $request->vendor_id)
                                    ->first();

                        if (!$vendor) {
                            return response()->json([
                                'message' => uiFast('Vendor not found'),
                                'status' => '0',
                            ], 404);
                        }

                        // Check payment exists
                        $payment = MyPayment::find($request->payment_id);
                        if (!$payment) {
                            return response()->json([
                                'message' =>  uiFast('Payment not found'),
                                'status' => '0',
                            ], 404);
                        }

                        $totalBudget = (float) $vendor->total_budget;
                        $newAdvancePaid = (float) $request->advance_paid;

                        // Total already paid excluding this payment
                        $totalOtherPaid = (float) \DB::table('vendor_advance_payment')
                                            ->where('vendor_id', $request->vendor_id)
                                            ->where('id', '<>', $request->payment_id)
                                            ->sum('advance_paid');

                        // Remaining balance
                        $remainingBalance = max(0, $totalBudget - $totalOtherPaid);

                        if ($newAdvancePaid > $remainingBalance) {
                            return response()->json([
                                'message' =>  uiFast('Advance paid exceeds remaining balance for this vendor'),
                                'status' => '0',
                            ], 200);
                        }

                        // Update the payment
                        $payment->advance_paid      = $newAdvancePaid;
                        $payment->advance_paid_date = $request->advance_paid_date;
                        $payment->balance_due_date  = $request->balance_due_date ?? null;
                        $payment->save();

                        // Update vendor_events_myvendors.advance_paid (sum of all payments)
                        $updatedTotalAdvancePaid = \DB::table('vendor_advance_payment')
                                                    ->where('vendor_id', $request->vendor_id)
                                                    ->sum('advance_paid');

                        \DB::table('vendor_events_myvendors')
                            ->where('id', $request->vendor_id)
                            ->update(['advance_paid' => $updatedTotalAdvancePaid]);

                        return response()->json([
                            'message' =>  uiFast('Payment updated successfully'),
                            'status' => '1',
                            'data' => [
                                'payment_id' => $payment->id,
                                'vendor_id' => $payment->vendor_id,
                                'event_id' => $payment->event_id,
                                'advance_paid' => "₹" . number_format($payment->advance_paid, 2),
                                'advance_paid_date' => $payment->advance_paid_date,
                                'balance_due_date' => $payment->balance_due_date ?? "-",
                                'total_advance_paid' => "₹" . number_format($updatedTotalAdvancePaid, 2),
                                'total_balance_due'  => "₹" . number_format(max(0, $totalBudget - $updatedTotalAdvancePaid), 2)
                            ],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                            'page_heading' => $page_heading,
                            'page_i_content' => $page_i_content,
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 200);
                    }

                }
        public function deletemypayment(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                            'message' => uiFast('User not found'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => "",
                            'logged_in_user' => [],
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 401);
                    }

                    $user_details = [
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name'=> $user->business_name
                    ];                    

                    $useraccess = $this->checkeditaccess($token);
                    $user_role = $useraccess['role'];

                    $rules = [
                        'payment_id' => 'required|numeric',   
                    ];

                    $validator = Validator::make($request->all(), $rules);
                    if ($validator->fails()) {
                        $errors = $validator->errors()->toArray();

                        // 🌐 Translate each validation message
                        foreach ($errors as $field => &$messages) {
                            foreach ($messages as &$msg) {
                                $msg = t($msg);
                            }
                        }

                        return response()->json([
                            'message' => $errors,
                        ], 422);
                    }

                    $payment_id = $request->payment_id;

                    $payment = MyPayment::where('id', $payment_id)->first();
                    if (!$payment) {
                        return response()->json([
                            'message' => uiFast('Payment not found'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 404);
                    }

                    // Subtract advance_paid from vendor_events_myvendors
                    $advancePaid = (float) $payment->advance_paid;

                    \DB::table('vendor_events_myvendors')
                        ->where('id', $payment->vendor_id)
                        ->decrement('advance_paid', $advancePaid);

                    // Delete the payment
                    $payment->delete();

                    // Fetch updated vendor totals
                    $vendor = \DB::table('vendor_events_myvendors')->where('id', $payment->vendor_id)->first();
                    $totalAdvancePaid = $vendor ? (float) $vendor->advance_paid : 0;
                    $totalBalanceDue  = $vendor ? max(0, (float) $vendor->total_budget - $totalAdvancePaid) : 0;

                    return response()->json([
                        'message' => uiFast('Payment deleted successfully'),
                        'status' => '1',
                        'data' => [
                            'vendor_id' => $payment->vendor_id,
                            'payment_id' => $payment_id,
                            'deleted_advance_paid' => "₹" . number_format($advancePaid, 2),
                            'total_advance_paid' => "₹" . number_format($totalAdvancePaid, 2),
                            'total_balance_due' => "₹" . number_format($totalBalanceDue, 2),
                        ],
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                        'base_url' => 'https://planawedding.in/storage/',
                    ], 200);
                }
        public function singlevendorlisting(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                            'message' => uiFast('User not found'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => "",
                            'logged_in_user' => [],
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 401);
                    }

                    $user_details = [
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name'=> $user->business_name
                    ];                    

                    $useraccess = $this->checkeditaccess($token);
                    $user_role = $useraccess['role'];

                    $page_heading= ['show' =>1,'name' => "My Vendors"];
                    $page_i_content = ['show' =>1,'name' => "Check your Vendor details"];

                    $item_id = $request->id;

                    if (empty($item_id)) {
                        return response()->json([
                            'message' => uiFast('Vendor id is mandatory'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 400);
                    }

                    // get vendor details
                    $vendor = \DB::table('vendor_events_myvendors')->where('id', $item_id)->first();

                    if (!$vendor) {
                        return response()->json([
                            'message' => uiFast('Not able to find Vendor'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 503);   
                    }

                    $page_heading = [
                        'show' => 1,
                        'name' => $vendor->vendor_name
                        ? transliterateTextKeepNumbers($vendor->vendor_name)
                        : "-"
                    ];
                    
                    $page_i_content = [
                        'show' => 1,
                        'name' => $vendor->vendor_name
                            ? uiFast('Check details for') . ' ' . transliterateTextKeepNumbers($vendor->vendor_name)
                            : "-"
                    ];

                    // fetch vendor payments
                    $payments = \DB::table('vendor_advance_payment')
                        ->where('vendor_id', $vendor->id)
                        ->orderByDesc('id')
                        ->get();

                    $latestAdvancePaidDate = $payments->max('advance_paid_date') ?? "-";
                    $latestBalanceDueDate = $payments->max('balance_due_date') ?? "-";
                    $totalAdvancePaid = $payments->sum('advance_paid') ?: 0;

                    // totals from vendor table
                    $vendorBudget = $vendor->total_budget ?: 0;
                    $totalBalanceDue = $vendorBudget - $totalAdvancePaid;

                    // get event budget from vendor_events
                    $event = \DB::table('vendor_events')->where('id', $vendor->event_id)->first();
                    $eventBudget = $event ? $event->total_budget : 0;

                    // profit = event budget - vendor budget
                    $profit = $eventBudget - $vendorBudget;
                    $profitPercentage = ($eventBudget > 0) 
                        ? number_format(($profit / $eventBudget) * 100, 2, '.', '') 
                        : "0.00";

                    // format vendor data
                    $event_listing = [
                        'vendor_id'           => $vendor->id ?? "-",
                        'event_id'            => $vendor->event_id ?? "-",
                        'vendor_type'         => $vendor->vendor_type ? domainTranslate($vendor->vendor_type): "-",
                        'vendor_name'         => $vendor->vendor_name ? transliterateTextKeepNumbers($vendor->vendor_name): "-",
                        'contact_person'      => $vendor->contact_person ? transliterateTextKeepNumbers($vendor->contact_person) : "-",
                        'mobile_number'       => $vendor->mobile_number ?? "-",
                        'email_id'            => $vendor->email_id ?? "-", 
                        'scope_of_work'       => $vendor->scope_of_work ? translateLongText ($vendor->scope_of_work): "-",
                        'total_budget'        => number_format($vendorBudget, 2),
                        'total_advance_paid'  => number_format($totalAdvancePaid, 2),
                        'total_balance_due'   => "₹" . number_format($totalBalanceDue, 2),
                        'advance_paid_date'   => $latestAdvancePaidDate,
                        'balance_due_date'    => $latestBalanceDueDate,
                        'service_date'        => $vendor->service_date ?? "-",
                        'event_total_budget'  => "₹" . number_format($eventBudget, 2),
                        'profit_earned'       => "₹" . number_format($profit, 2),
                        'profit_percentage'   => $profitPercentage . "%",
                        'profit_currency'     => "₹" . number_format($profit, 2),
                    ];

                    // add payment listings
                    $payment_listings = $payments->map(function ($payment) {
                        return [
                            'payment_id'        => $payment->id ?? "-",
                            'event_id'          => $payment->event_id ?? "-",
                            'vendor_id'         => $payment->vendor_id ?? "-",
                            'advance_paid'      => isset($payment->advance_paid) ? "₹".number_format($payment->advance_paid, 2) : "-",
                            'advance_paid_date' => $payment->advance_paid_date ?? "-",
                            'balance_due_date'  => $payment->balance_due_date ?? "-"
                        ];
                    });

                    // include payment listings inside data
                    $event_listing['payment_listings'] = $payment_listings;

                    return response()->json([
                        'message' => uiFast('Single Vendor Listing'),
                        'status' => '1',
                        'data' => $event_listing,
                        'page_heading' => $page_heading,
                        'page_i_content' => $page_i_content,
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details, 
                        'base_url' => 'https://planawedding.in/storage/',
                    ], 200);
                }
