        public function myfoldersubscribed(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user  = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                            'message'        => uiFast('User not found'),
                            'status'         => '0',
                            'folder_image'   => '',
                            'data'           => [],
                            'user_role'      => "",
                            'logged_in_user' => [],
                            'base_url'       => 'https://planawedding.in/storage/',
                        ], 401);
                    }

                    // -----------------------------
                    // BASIC DETAILS
                    // -----------------------------
                    $page_title       = uiFast('My Folders');
                    $page_description = uiFast('This feature allows you to store all your decoration images in one place, making them easily accessible during client meetings.');
                    $user_details     = [
                        'name'          => $user->name,
                        'email'         => $user->email,
                        'mobile'        => $user->mobile,
                        'business_name' => $user->business_name
                    ];

                    $useraccess        = $this->checkeditaccess($token);
                    $user_role         = $useraccess['role'];
                    $user_access_array = $useraccess['access_array'];
                    $paginate          = $request->paginate;

                    // -----------------------------
                    // SEARCH IMPLEMENTATION
                    // -----------------------------
                    $search      = $request->search;
                    $allowsearch = !empty($search);

                    // -----------------------------
                    // FETCH FOLDERS BASED ON ROLE
                    // -----------------------------
                    if ($user_role == 'admin' || $user_role == 'partner admin') {
                        $datas = BusinessFolder::select([
                            'id',
                            'display_folder_name',
                            'folder_color',
                            'folder_created_on',
                            'actual_folder_name',
                            'folder_full_path',
                            'folder_mid_path'
                        ])
                        ->where('user_id', $user->id)
                        ->when($allowsearch, function ($query) use ($search) {
                            $query->where('display_folder_name', 'like', '%' . $search . '%');
                        })
                        ->orderBy('display_folder_name', 'asc')
                        ->paginate(10);
                    }
                    elseif ($user_role == 'sub admin') {
                        $datas = BusinessFolder::select([
                            'id',
                            'display_folder_name',
                            'folder_color',
                            'folder_created_on',
                            'actual_folder_name',
                            //'folder_full_path',
                            'folder_mid_path'
                        ])
                        ->where('user_id', $user->team_id)
                        ->when($allowsearch, function ($query) use ($search) {
                            $query->where('display_folder_name', 'like', '%' . $search . '%');
                        })
                        ->orderBy('display_folder_name', 'asc')
                        ->paginate(10);
                    }

                    // -----------------------------
                    // ADD total_files_available FOR EACH FOLDER
                    // -----------------------------
                    $datas->getCollection()->transform(function ($folder) {


                        $folder->display_folder_name = translateLongText(
                            $folder->display_folder_name
                        );
                        
                        $folderPath = $folder->folder_full_path;
                        $totalFiles = 0;

                        if (!empty($folderPath) && is_dir($folderPath)) {
                            $totalFiles = count(
                                array_filter(scandir($folderPath), function ($file) use ($folderPath) {
                                    return !in_array($file, ['.', '..']) &&
                                        is_file($folderPath . '/' . $file);
                                })
                            );
                        }

                        $folder->total_files_available = $totalFiles;

                        return $folder;
                    });

                    // -----------------------------
                    // CRM TOOL (NO CHANGES TO LOGIC)
                    // -----------------------------
                    $folder_image = "myfolder/folderimage.png";

                    $planner_actual_id      = $user->id;
                    $planner_actual_team_id = $user->team_id;

                    if (empty($planner_actual_team_id)) {

                        $planner_main_id = $user->id;
                        $planner_buiness_name = $user->business_name;
                        $planner_name  = $user->name;
                        $planner_mobile = $user->mobile;
                        $partner = $user->is_partner;
                        $subscriber = $user->chk_subscription;
                        $subscribed_tenure = $user->subscribed_tenure;
                        $planner_state = $user->user_lead_state_name;
                        $planner_city  = $user->city;

                        $findtotalfolder = BusinessFolder::where('user_id', $planner_actual_id)->count();
                    }
                    else {
                        $planner_main_id = $user->team_id;
                        $planner_buiness_name = $user->business_name;
                        $planner_name  = $user->name;
                        $planner_mobile = $user->mobile;

                        $chkmainuser = User::where('id', $planner_main_id)->first();
                        $partner = $chkmainuser->is_partner;
                        $subscriber = $chkmainuser->chk_subscription;
                        $subscribed_tenure = $chkmainuser->subscribed_tenure;
                        $planner_state = $chkmainuser->user_lead_state_name;
                        $planner_city  = $chkmainuser->city;

                        $findtotalfolder = BusinessFolder::where('user_id', $planner_main_id)->count();
                    }

                    // -----------------------------
                    // SUBSCRIPTION LOGIC
                    // -----------------------------
                    $planner_subscriptions = NULL;

                    $getplanner = PlannerSubscription::where('user_id', $user->id)->count();

                    if ($partner == 1) {
                        $palnner_role = "Partner";
                    }
                    elseif ($subscriber == 1) {
                        $palnner_role = "Subscribed Planner";
                        $planner_subscriptions = $subscribed_tenure;
                    }
                    elseif ($subscriber == 0 && $getplanner > 0) {
                        $palnner_role = "Expired Subscription";
                        $planner_subscriptions = $subscribed_tenure;
                    }
                    else {
                        $palnner_role = "Registered and not Subscribed Yet";
                    }

                    // -----------------------------
                    // CRM COUNTER UPDATE
                    // -----------------------------
                    $pagename = "FOLDER CREATED";
                    $findcrm  = CrmCounter::where('planner_id', $planner_actual_id)
                                ->where('page_name', $pagename)
                                ->latest()
                                ->first();

                    $visitcount = ($findcrm) ? $findcrm->no_of_visti_times + 1 : 1;
                    $recent_visit = now()->format('d/m/Y H:i:s');
                    $newfolder = $findtotalfolder;

                    if ($findcrm) {
                        $findcrm->no_of_visti_times = $visitcount;
                        $findcrm->recent_visit = $recent_visit;
                        $findcrm->total_no_of_folders = $newfolder;
                        $findcrm->save();
                    }
                    else {
                        $newcrm = new CrmCounter();
                        $newcrm->page_name = $pagename;
                        $newcrm->planner_id  = $planner_actual_id;
                        $newcrm->planner_team_id  = $planner_actual_team_id;
                        $newcrm->planner_main_id   = $planner_main_id;
                        $newcrm->planner_business_name  = $planner_buiness_name;
                        $newcrm->planner_name  = $planner_name;
                        $newcrm->planner_mobile  = $planner_mobile;
                        $newcrm->planner_role  = $palnner_role;
                        $newcrm->planner_subscriptions  = $planner_subscriptions;
                        $newcrm->no_of_visti_times  = $visitcount;
                        $newcrm->recent_visit  = $recent_visit;
                        $newcrm->planner_state  = $planner_state;
                        $newcrm->planner_city  = $planner_city;
                        $newcrm->total_no_of_folders = $newfolder;
                        $newcrm->save();
                    }

                    // -----------------------------
                    // FINAL RESPONSE
                    // -----------------------------
                    return response()->json([
                        'message'          => uiFast('Folder Details'),
                        'status'           => '1',
                        'folder_image'     => $folder_image,
                        'data'             => $datas,
                        'page_title'       => $page_title,
                        'page_description' => $page_description,
                        'user_role'        => $user_role,
                        'logged_in_user'   => $user_details,
                        'base_url'         => 'https://planawedding.in/storage/',
                    ], 200);
                }

