        public function deletemyfolder(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user  = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                            'message' => uiFast('User not found'),
                            'status'  => '0',
                            'data'    => [],
                        ], 401);
                    }

                    $user_details = [
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name' => $user->business_name
                    ];

                    $useraccess = $this->chkuseraccess($token);
                    $user_role  = $useraccess['role'];

                    $folder_id = $request->id;

                    if (empty($folder_id)) {
                        return response()->json([
                            'message' => uiFast('Folder id is mandatory'),
                            'status'  => '0',
                            'data'    => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 400);
                    }

                    if ($user_role === 'team member') {
                        return response()->json([
                            'message' => uiFast('User do not have access'),
                            'status'  => '0',
                            'data'    => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 401);
                    }

                    // OWNER ID
                    $owner_id = ($user_role === 'sub admin') ? $user->team_id : $user->id;

                    $folder = BusinessFolder::where('id', $folder_id)
                        ->where('user_id', $owner_id)
                        ->first();

                    if (!$folder) {
                        return response()->json([
                            'message' => uiFast('Folder not exists'),
                            'status'  => '0',
                            'data'    => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 404);
                    }

                    // DELETE FILE RECORDS + FILES
                    $files = BusinessFileFolder::where('fodler_id', $folder_id)->get();

                    foreach ($files as $file) {
                        if (!empty($file->actual_file_path) && file_exists($file->actual_file_path)) {
                            @unlink($file->actual_file_path);
                        }
                        $file->delete();
                    }

                    // DELETE FOLDER FROM DISK
                    $basePath   = "/home/gjymj6oxru2v/planawedding/storage/app/public/";
                    $folderPath = $basePath . trim($folder->folder_mid_path, '/') . '/';

                    if (File::exists($folderPath)) {
                        File::deleteDirectory($folderPath);
                    }

                    // DELETE FOLDER DB ROW
                    $folder->delete();

                    return response()->json([
                        'message' => uiFast('Folder Deleted'),
                        'status'  => '1',
                        'data'    => [],
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                        'base_url' => 'https://planawedding.in/storage/',
                    ], 200);
                } 
        public function addfilestofoldermany(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user  = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                            'message' => uiFast('User not found'),
                            'status' => '0',
                            'data' => [],
                        ], 401);
                    }

                    $validator = Validator::make($request->all(), [
                        'folder_id' => 'required',
                        'files'     => 'required',
                    ]);

                    if ($validator->fails()) {
                        $errors = $validator->errors()->toArray();

                        // 🌐 Translate each validation message
                        foreach ($errors as $field => &$messages) {
                            foreach ($messages as &$msg) {
                                $msg = t($msg);
                            }
                        }

                        return response()->json([
                            'message' => $errors,
                        ], 422);
                    }

                    $useraccess = $this->chkuseraccess($token);
                    $user_role  = $useraccess['role'];

                    $target_id = ($user_role == 'admin' || $user_role == 'partner admin')
                        ? $user->id
                        : $user->team_id;

                    $sub_id = ($user_role == 'sub admin') ? $user->id : null;

                    $folder = BusinessFolder::where('id', $request->folder_id)
                        ->where('user_id', $target_id)
                        ->first();

                    if (!$folder) {
                        return response()->json([
                            'message' => uiFast('Folder not found'),
                            'status'  => '0',
                            'data'    => [],
                        ], 200);
                    }

                    $uploadBase = "/home/gjymj6oxru2v/planawedding/storage/app/public/business_dir/";
                    $savedCount = 0;

                    foreach ($request->file('files') as $file) {

                        if (!$file->isValid()) {
                            continue;
                        }

                        $ext = strtolower($file->getClientOriginalExtension());

                        // ✅ allow all common image formats
                        if (!in_array($ext, ['jpg','jpeg','png','gif','webp','svg'])) {
                            continue;
                        }

                        $originalName = $file->getClientOriginalName();

                        // GIF & SVG → save as-is (no recompress)
                        if (in_array($ext, ['gif','svg'])) {
                            $filename = time().uniqid().'.'.$ext;
                            $relativePath = $folder->actual_folder_name.'/'.$filename;
                            $fullPath = $uploadBase.$relativePath;

                            $file->move($uploadBase.$folder->actual_folder_name, $filename);
                        }
                        else {
                            // JPG / PNG / WEBP → re-encode as WEBP (lossless-ish)
                            $filename = time().uniqid().'.webp';
                            $relativePath = $folder->actual_folder_name.'/'.$filename;
                            $fullPath = $uploadBase.$relativePath;

                            $image = Image::make($file->getRealPath())
                                ->encode('webp', 88); // 🔥 visually lossless

                            $image->save($fullPath);
                        }

                        // DB INSERT
                        BusinessFileFolder::create([
                            'users_id'            => $target_id,
                            'teams_id'            => $sub_id,
                            'fodler_id'           => $folder->id,
                            'folder_name_display' => $folder->display_folder_name,
                            'folder_name_actual'  => $folder->actual_folder_name,
                            'folder_full_path'    => $folder->folder_full_path,
                            'folder_mid_path'     => $folder->folder_mid_path,
                            'original_file_name'  => $originalName,
                            'file_name'           => $filename,
                            'actual_file_path'    => $fullPath,
                            'mid_file_path'       => $relativePath,
                            'file_uploaded_on'    => now()->format('d/m/Y H:i:s'),
                        ]);

                        $savedCount++;
                    }

                    return response()->json([
                        'message' => uiFast('File Added'),
                        'status'  => '1',
                        'data'    => [
                            'folder' => transliterateTextKeepNumbers($folder->display_folder_name),
                            'files_saved' => $savedCount
                        ],
                        'user_role' => $user_role,
                        'base_url' => 'https://planawedding.in/storage/',
                    ], 200);
                }
        public function deletefilefrmfoldersmany(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user  = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                            'message' => uiFast('User not found'),
                            'status'  => '0',
                            'data'    => [],
                            'user_role' => "",
                            'logged_in_user' => [],
                        ], 401);
                    }

                    $user_details = [
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name' => $user->business_name
                    ];

                    $useraccess = $this->chkuseraccess($token);
                    $user_role  = $useraccess['role'];

                    $item_id = $request->ids;

                    if (empty($item_id)) {
                        return response()->json([
                            'message' => uiFast('File id is mandatory'),
                            'status'  => '0',
                            'data'    => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 400);
                    }

                    // ❌ Team members not allowed
                    if ($user_role === 'team member') {
                        return response()->json([
                            'message' => uiFast('User do not have access'),
                            'status'  => '0',
                            'data'    => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 401);
                    }

                    // ROLE TARGET
                    if ($user_role === 'sub admin') {
                        $target_id = $user->team_id;
                    } else {
                        $target_id = $user->id;
                    }

                    $ids = explode(',', $item_id);
                    $deletedCount = 0;

                    foreach ($ids as $id) {

                        $image = BusinessFileFolder::where('id', trim($id))->first();

                        // ✅ If record not found → skip safely
                        if (!$image) {
                            continue;
                        }

                        // ✅ Delete file only if exists
                        if (!empty($image->actual_file_path) && file_exists($image->actual_file_path)) {
                            @unlink($image->actual_file_path);
                        }

                        // ✅ Delete DB record
                        $image->delete();
                        $deletedCount++;
                    }

                    return response()->json([
                        'message' => uiFast('File Deleted'),
                        'status'  => '1',
                        'data'    => [
                            'files_deleted' => $deletedCount
                        ],
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                        'base_url' => 'https://planawedding.in/storage/',
                    ], 200);
                } 
