                    $user = $this->getuser($token);
                    
                    if($user) 
                    {
                        
                        $page_title = uiFast('Wedding News');
                        $page_description = uiFast('In the wedding industry, staying informed on the latest trends and events is crucial. This feature keeps you up-to-date with all the happenings.');
