                        ->whereIn('to_show_in', ['B2B', 'Both'])->orderBy("id",'desc');
            
                        $datas = ($paginate == "false") ? $dropdowntheme->get() : $dropdowntheme->paginate(10);
                        
                        // 🌐 Translate news content (FAST – UI only)
                        $datas->getCollection()->transform(function ($item) {

                            $item->actual_category_name = uiFast($item->actual_category_name);
                            $item->news_title           = translateLongText($item->news_title);
                            $item->news_source          = translateLongText($item->news_source);

                            return $item;
                        });
                        /* CRM tool starts*/

                            $planner_actual_id = $user->id; 
                            $planner_actual_team_id = $user->team_id;



                            if(empty($planner_actual_team_id) || $planner_actual_team_id == NULL)
                                {
                                    $planner_actual_id = $user->id; 
                                    $planner_actual_team_id = $user->team_id;
                                    $planner_main_id = $user->id; 
                                    $planner_buiness_name = $user->business_name; 
                                    $planner_name = $user->name; 
                                    $planner_mobile = $user->mobile; 
                                    
                                    $partner = $user->is_partner;
                                    $subscriber = $user->chk_subscription;
                                    $subscribed_tenure = $user->subscribed_tenure;
                                    
                                    
                                    $planner_state = $user->user_lead_state_name;
                                    $planner_city = $user->city;


                                }

                            if(!empty($planner_actual_team_id) || $planner_actual_team_id != NULL)
                                {
                                    $planner_actual_id = $user->id; 
                                    $planner_actual_team_id = $user->team_id;
                                    $planner_main_id = $user->team_id; 
                                    $planner_buiness_name = $user->business_name; 
                                    $planner_name = $user->name;
                                    $planner_mobile = $user->mobile; 


                                    $chkmainuser = User::where('id',$planner_main_id)->latest()->first();
                                    if($chkmainuser)
                                    {
                                        $partner = $chkmainuser->is_partner;
                                        $subscriber = $chkmainuser->chk_subscription;
                                        $subscribed_tenure = $chkmainuser->subscribed_tenure;
                                        $planner_state = $chkmainuser->user_lead_state_name;
                                        $planner_city = $chkmainuser->city;
                                        
                                    }

                                    
                                }

                            $planner_subscriptions = NULL;


                            $getplanner =  PlannerSubscription::where('user_id',$user->id)->get()->count();
                            
                            $thiscount = "";

                            if($getplanner > 0)
                                {
                                    $thiscount = "exists";       
                                }
                            else 
                                {
                                    $thiscount = "not-exists";
                                }    

                                
                            if($partner == 1)
                                {
                                    $palnner_role = "Partner";
                                    
                                }
                            else if($subscriber == 1)  
                                {
                                    $palnner_role = "Subscribed Planner";
                                    $planner_subscriptions = $subscribed_tenure;
                                }
                            else if($subscriber == 0 & $thiscount == "exists")
                                {
                                    $palnner_role = "Expired Subscription";
                                    $planner_subscriptions = $subscribed_tenure;
                                }
                            else if($subscriber == 0 & $thiscount == "not-exists")
                                {
                                    $palnner_role = "Registered and not Subscribed Yet";
                                }
                                

                            $pagename = "WEDDING NEWS";

                            $findcrm = CrmCounter::where('planner_id',$planner_actual_id)->where('page_name',$pagename)->latest()->first();


                            if($findcrm)
                                {
                                    //$visitcount = $findcrm->no_of_visti_times += 1;

                                    $visittime = $findcrm->no_of_visti_times;
                                    $visittime = $visittime + 1;
                                    $visitcount = $visittime;
                                }
                            else 
                                {
                                    $visitcount = 1;
                                }

                                $recent_visit = now()->format('d/m/Y H:i:s');


                            if($findcrm)
