                }

        public function newscategorysingle(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user  = $this->getuser($token);

                    if (!$user) {
                        return response()->json([
                            'message' => uiFast('User not found'),
                            'status'  => '0',
                            'data'    => [],
                            'user_role' => "",
                            'logged_in_user' => [],
                        ], 401);
                    }

                    $user_details = [
                        'name'          => $user->name,
                        'email'         => $user->email,
                        'mobile'        => $user->mobile,
                        'business_name' => $user->business_name
                    ];

                    $useraccess = $this->checkeditaccess($token);
                    $user_role  = $useraccess['role'];

                    // -----------------------------
                    // VALIDATION
                    // -----------------------------
                    $validator = Validator::make($request->all(), [
                        'newsid' => 'required|numeric',
                    ]);

                    if ($validator->fails()) {
                        return response()->json([
                            'message' => uiFast('News id is mandatory'),
                            'status'  => '0',
                            'data'    => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 422);
                    }

                    // -----------------------------
                    // FETCH NEWS
                    // -----------------------------
                    $newsid = $request->newsid;

                    $data = NewsCategoryDetails::where('id', $newsid)
                        ->latest()
                        ->first();

                    if (!$data) {
                        return response()->json([
                            'message' => uiFast('News item not found'),
                            'status'  => '0',
                            'data'    => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 200);
                    }

                    // -----------------------------
                    // TRANSLATED RESPONSE DATA
                    // -----------------------------
                    $items = [
                        'id' => $data->id,
                        'actual_category_id' => $data->actual_category_id,

                        // 🔹 FAST UI TRANSLATIONS
                        'actual_category_name' => uiFast($data->actual_category_name),
                        'news_title'           => translateLongText($data->news_title),
                        'news_source'          => translateLongText($data->news_source),

                        'news_image' => $data->news_image,

                        // 🔹 HTML-SAFE BODY TRANSLATION
                        'actual_news_details' => translateHtmlUiFast($data->news_details),

                        // 🔹 DATE FIELDS
                        'created_date'  => $data->created_date,
                        'created_day'   => $data->created_day,
                        'created_month' => translateFullMonth($data->created_month),
                        'created_year'  => $data->created_year,
                    ];

                    // -----------------------------
                    // FINAL RESPONSE
                    // -----------------------------
                    return response()->json([
                        'message' => uiFast('News Single Details'),
                        'status'  => '1',
                        'data'    => $items,
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                        'logged_in_id' => $user->id,
                        'base_url' => 'https://planawedding.in/storage/',
                    ], 200);
                } 
    /* News Ends */

    /* Team Starts */
        public function teammembers(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);
                    
                    if($user) 
                    {
                        $user_details = ['name' => $user->name,'email' => $user->email,'mobile' => $user->mobile,'business_name' => $user->business_name];
                        
                        $useraccess = $this->checkeditaccess($token);
                        
                        $user_role = $useraccess['role'];
                        $user_access_array = $useraccess['access_array'];
                        
                        $search = $request->search;
                        
                        if(!empty($search))
                        {
                            $allowsearch = true;
                        }
                        else
                        {
                            $allowsearch = false;
                        }
                        
                        //dd($user_role,$user->id);
                        
                        if($user_role !== 'team member')
                        {
                            if($user_role == 'admin' || $user_role == 'partner admin')
                            {
                                $team_id = $user->id;
                            }
                            else if( $user_role == 'sub admin')
                            {
                                $team_id = $user->team_id;
                            }
                            
                            $users = User::select('id', 'name', 'username', 'email', 'mobile')
                            ->where('team_id',$team_id)
                            ->when($allowsearch, function ($query) use ($search) {
                                $query->where(function($q) use ($search){
                                    $q->where('name', 'like', '%'.$search.'%')
                                        ->orWhere('email', 'like', '%'.$search.'%')
                                        ->orWhere('mobile', 'like', '%'.$search.'%');
                                });
                            })
                            ->paginate(10);
                            


                            // 🔹 Transliterate only the name field (FAST & SAFE)
                            $users->getCollection()->transform(function ($user) {
                                $user->name = transliterateTextKeepNumbers($user->name);
                                return $user;
                            });

                            return response()->json([
                                'message' => uiFast('team members list'),
                                'status' => '1',
                                'data' => $users,
                                'user_role' => $user_role,
                                'logged_in_user' => $user_details,
                            ], 200);
                        }
                        else
                        {
                            return response()->json([
                                'message' => uiFast('User do not have access'),
                                'status' => '0',
                                'data' => [],
                                'user_role' => $user_role,
                                'logged_in_user' => $user_details,
                            ], 401);
                        }
                    } 
                    else 
                    {
                        return response()->json([
                            'message' => uiFast('User not found'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => "",
                            'logged_in_user' => [],
                        ], 401);
                    }
                }
