        public function delteammembers(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);
                    
                    if($user) 
                    {
                        $user_details = ['name' => $user->name,'email' => $user->email,'mobile' => $user->mobile,'business_name' => $user->business_name];
                        
                        $useraccess = $this->checkeditaccess($token);
                        
                        $user_role = $useraccess['role'];
                        $user_access_array = $useraccess['access_array'];
                        
                        $item_id = $request->id;
                        
                        if(empty($item_id))
                        {
                            return response()->json([
                                'message' => uiFast('Member id is mandatory'),
                                'status' => '0',
                                'data' => [],
                                'user_role' => $user_role,
                                'logged_in_user' => $user_details,
                            ], 400);
                        }
                        
                        if($user_role !== 'team member')
                        {
                            if($user_role == 'sub admin')
                            {
                                $team_id = $user->team_id;
                            }
                            else
                            {
                                $team_id = $user->id;
                            }
                            
                            $member = User::where('team_id',$team_id)->where('id',$item_id)->first();
                            
                            if($member)
                            {
                                if($member->delete())
                                {            
                                    return response()->json([
                                        'message' => uiFast('Team Member Deleted'),
                                        'status' => '1',
                                        'data' => [],
                                        'user_role' => $user_role,
                                        'logged_in_user' => $user_details,
