                                    ], 200);  
                                }
                                else
                                {
                                    return response()->json([
                                        'message' => uiFast('Issues in Team Member delete'),
                                        'status' => '0',
                                        'data' => $member,
                                        'user_role' => $user_role,
                                        'logged_in_user' => $user_details,
                                        'base_url' => 'https://planawedding.in/storage/',
                                    ], 304);
                                } 
                            }
                            else
                            {
                                return response()->json([
                                    'message' => uiFast('team member not found'),
                                    'status' => '0',
                                    'data' => [],
                                    'user_role' => $user_role,
                                    'logged_in_user' => $user_details,
                                ], 200);
                            }
                        }
                        else
                        {
                            return response()->json([
                                'message' => uiFast('User do not have access'),
                                'status' => '0',
                                'data' => [],
                                'user_role' => $user_role,
                                'logged_in_user' => $user_details,
                            ], 401);
                        }
                    } 
