        private function removeImageIfNo($imagesArray, $dbImagePath)
                {
                    if (empty($imagesArray) || empty($dbImagePath)) {
                        return null;
                    }

                    $values = explode(",", $imagesArray);

                    if (in_array('no', $values)) {
                        $fullPath = "/home/gjymj6oxru2v/planawedding/storage/app/public/" . $dbImagePath;

                        if (file_exists($fullPath)) {
                            unlink($fullPath);
                        }
                        return null;
                    }

                    return $dbImagePath;
                }
        public function addvenue(Request $request)   
                {
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);

                

                    if($user) 
                        {
                            $user_details = ['name' => $user->name,'email' => $user->email,'mobile' => $user->mobile,'business_name' => $user->business_name];
                
                            $useraccess = $this->checkeditaccess($token);
                            $user_role = $useraccess['role'];
                            $user_access_array = $useraccess['access_array'];
                            
                            $users = [];
                                        
                            $rules = array(
                                'venue_name' => 'required', 
                                'venue_type' => 'required',
                                'seating_capactiy' => 'required',
                                'floating_capactiy' => 'required',
                                "other_pricing" => "required_if:venue_type,Wedding Lawns,Marriage Halls", 
                                "other_pricing_amount" => "required_if:venue_type,Wedding Lawns,Marriage Halls", 
                                'caters_allowed' => 'required', 
                                'phhotovideo_allowed' => 'required',    
                                'decorators_allowed' => 'required',    
                                'music_allowed' => 'required',    
                                'rooms_availble' => 'required',    


                                'show_address' => 'required',   


                                "banq_ac_nonac" => "required_if:venue_type,==,Banquet Halls",
                                "veg_pricing" => "required_if:venue_type,==,Banquet Halls",
                                "veg_pricing_amount" => "required_if:venue_type,==,Banquet Halls",
                                "nonveg_pricing_amount" => "required_if:venue_type,==,Banquet Halls",
                                "nonveg_pricing" => "required_if:venue_type,==,Banquet Halls", 
                            );
                
                            $error = Validator::make($request->all(), $rules);

                            if($error->fails())
                            {
                                

                                $errors = $error->errors()->toArray();

                                // 🌐 Translate each validation message
                                foreach ($errors as $field => &$messages) {
                                    foreach ($messages as &$msg) {
                                        $msg = t($msg);
                                    }
                                }

                                return response()->json([
                                    'message' => $errors,
                                ], 422);
                            }
                            else
                            {
                                $user_id = $user->id;
                                $userteamid = $user->team_id;

                                if($userteamid == null || $userteamid == "" || $userteamid='' || $userteamid == NULL)
                                {
                                    $thisuser = $user_id;
                                    $thisteam = NULL;
                                }
                                else
                                {
                                    $userteam = User::where('id', $user_id)->latest()->first(); 
                    
                                    $thisuser = $userteam->team_id;
                                    $thisteam = $userteam->id;
                                }


                                $item_id = $request->id;

                            
                                    

                                $banq_seating_capactiy   = NULL;
                                $banq_floating_capactiy  = NULL;

                                $other_seating_capactiy  = NULL;
                                $other_floating_capactiy = NULL;

                                $about_venue  = NULL;

                                        
                                
                                    
                                    $thisid = $request->id; 
                                    $data = VenueList::where('id',$thisid)->latest()->first();    
                                    
                                            

                                        if ($data)
                                            {

                                                $oldData = $data->replicate();
                                                $venue_name = $request->venue_name;
                                                $venue_type = $request->venue_type;

                                                if ($venue_type == "Banquet Halls") {
                                                    $banq_seating_capactiy  = $request->seating_capactiy;
                                                    $banq_floating_capactiy = $request->floating_capactiy;
                                                }

                                                $banq_ac_nonac  = $request->banq_ac_nonac;
                                                $veg_pricing    = $request->veg_pricing;
                                                $nonveg_pricing = $request->nonveg_pricing;

                                                if ($venue_type == "Wedding Lawns" || $venue_type == "Marriage Halls") {
                                                    $other_seating_capactiy  = $request->seating_capactiy;
                                                    $other_floating_capactiy = $request->floating_capactiy;
                                                }

                                                $other_pricing       = $request->other_pricing;
                                                $caters_allowed      = $request->caters_allowed;
                                                $phhotovideo_allowed = $request->phhotovideo_allowed;
                                                $decorators_allowed  = $request->decorators_allowed;
                                                $music_allowed       = $request->music_allowed;
                                                $rooms_availble      = $request->rooms_availble;
                                                $about_venue         = $request->about_venue;
                                                $venue_location      = $request->show_address;
                                                $show_address        = $request->show_address;

                                                    /*$dates_available = NULL;*/
                                                $dates_available = $request->dates_available ?? $data->dates_available;
                                                $country = $state = $txtCity = $txtZip = $address = NULL;

                                                $veg_pricing_amount    = $request->veg_pricing_amount;
                                                $nonveg_pricing_amount = $request->nonveg_pricing_amount;
                                                $other_pricing_amount  = $request->other_pricing_amount;

                                                /* ===== DEFAULT IMAGE VALUES ===== */
                                                $newfilename   = NULL;
                                                $newfilename1  = NULL;
                                                $newfilename2  = NULL;
                                                $newfilename3  = NULL;
                                                $newfilename4  = NULL;
                                                $newfilename5  = NULL;
                                                $newfilename6  = NULL;
                                                $newfilename7  = NULL;
                                                $newfilename8  = NULL;
                                                $newfilename9  = NULL;
                                                $newfilename10 = NULL;


