        public function createPaytmSubscription($customerId, $amount, $orderId, $userMobile, $tenureType)
                {
                    $mid  = "aUrqBh85345734866262";
                    $mkey = "X_b1mPyvIOMp@ry0";

                    $frequency = "1";
                    $frequencyUnit = "MONTH";
                    $expiryDate = date("Y-m-d", strtotime("+1 year"));

                    if($tenureType == "Monthly_Subscription")
                    {
                        $frequency = "1";
                        $frequencyUnit = "MONTH";
                        $expiryDate = date("Y-m-d", strtotime("+1 month"));
                    }
                    else if($tenureType == "Quarterly_Subscription")
                    {
                        $frequency = "3";
                        $frequencyUnit = "MONTH";
                        $expiryDate = date("Y-m-d", strtotime("+3 months"));
                    }
                    else if($tenureType == "Annual_Subscription")
                    {
                        $frequency = "12";
                        $frequencyUnit = "MONTH";
                        $expiryDate = date("Y-m-d", strtotime("+1 year"));
                    }

                    $paytmParams = [];

                    $paytmParams["body"] = [
                        "requestType" => "NATIVE_SUBSCRIPTION",
                        "mid" => $mid,
                        "orderId" => (string)$orderId,

                        "paymentFlow" => "ADDANDPAY",

                        "subscriptionAmountType" => "FIX",
                        "subscriptionAmount" => (string)$amount,
                        "subscriptionMaxAmount" => (string)$amount,

                        "subscriptionFrequency" => (string)$frequency,
                        "subscriptionFrequencyUnit" => (string)$frequencyUnit,

                        "subscriptionStartDate" => date("Y-m-d"),
                        "subscriptionExpiryDate" => $expiryDate,

                        "subscriptionGraceDays" => "0",
                        "subscriptionEnableRetry" => "1",

                        "txnAmount" => [
                            "value" => (string)$amount,
                            "currency" => "INR",
                        ],

                        "userInfo" => [
                            "custId" => (string)$customerId,
                            "mobile" => (string)$userMobile,
                        ],
                    ];

                    $checksum = $this->generateSignature(
                        json_encode($paytmParams["body"], JSON_UNESCAPED_SLASHES),
                        $mkey
                    );

                    $paytmParams["head"] = [
                        "signature" => $checksum
                    ];

                    $url = "https://secure.paytmpayments.com/subscription/create?mid=".$mid."&orderId=".$orderId;

                    $post_data = json_encode($paytmParams, JSON_UNESCAPED_SLASHES);

                    $ch = curl_init($url);

                    curl_setopt($ch, CURLOPT_POST, true);
                    curl_setopt($ch, CURLOPT_POSTFIELDS, $post_data);
                    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
                    curl_setopt($ch, CURLOPT_HTTPHEADER, [
                        "Content-Type: application/json",
                    ]);

                    $response = curl_exec($ch);

                    return json_decode($response, true);
                }
        public function initiatesubscriptionpayment(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);
                    
                    if($user) 
                    {
                        $user_details = ['name' => $user->name,'email' => $user->email,'mobile' => $user->mobile,'business_name' => $user->business_name];
                        
                        $useraccess = $this->chkuseraccess($token);
                        $user_role = $useraccess['role'];
                        $user_access_role = $useraccess['useraccess'];
                        $user_access_array = $useraccess['access_array'];
                        
                        if($user_role == 'admin')
                        {
                            $rules = [
                                'amount' => 'required',
                                'tenure' => 'required',
                                'tenure_type' => 'required',
                            ];
                            
                            $validator = Validator::make($request->all(), $rules);

                            if ($validator->fails()) 
                            {
                                $messages = $validator->messages()->toArray();
                                $translatedMessages = [];

                                foreach ($messages as $field => $errs) {
                                    foreach ($errs as $err) {
                                        $translatedMessages[$field][] = t($err);
                                    }
                                }

                                return response()->json([
                                    'message' => $translatedMessages,
                                ], 422);
                            }
                            else
                            {
                                $itemid = $request->tenure;
                                $type = $request->tenure_type;
                                $amount = $request->amount;

                                if($amount == '1999'|| $amount == '499'|| $amount == '4999'|| $amount == '9999')
                                {
                                    return response()->json([
                                        'message' => t('Payment can be initiated'),
                                        'status' => '1',
                                        'data' => [],
                                        'user_role' => $user_role,
                                        'payment_initiated' => 1,
                                        'orderid' => "",
                                        'logged_in_user' => $user_details,
                                    ], 200);
                                }
                                else if($amount == "Free")
                                {
                                    $amount = $request->amount;
                                    $tenure = $request->tenure;
                                    $tenure_type = $request->tenure_type;
                                    $itemid = $request->tenure_type;
                                    $today = date('d/m/Y H:i:s');

                                    if(!empty($user->team_id))
                                        $update_user = $user->team_id; 
                                    else
                                        $update_user = $user->id;

                                    if($itemid == "3_days_free")
                                    {
                                        $itemid = $type;
                                        $orderid = time().'00'.$itemid;

                                        $payment = new Payment();
                                        
                                        if(empty($user->team_id))
                                            $payment->user_id = $user->id;
                                        else
                                            $payment->user_id = $user->team_id;

                                        $payment->orderid = $orderid;
                                        $payment->reference = '';
                                        $payment->status = '';
                                        $payment->payable_id = $itemid;
                                        $payment->payable_type = "App\PlannerSubscription";  
                                        $payment->save();

                                        $remainingDays = "3";
                                        $actualend_date = date('Y-m-d', strtotime(date('Y-m-d'). ' + 3 days'));

                                        $planner_subscribe = new PlannerSubscription();
                                        $planner_subscribe->user_id = $update_user;
                                        $planner_subscribe->subscriptoin_amount = $amount;
                                        $planner_subscribe->subscription_type = $tenure_type;
                                        $planner_subscribe->subscription_date = $today;
                                        $planner_subscribe->subscription_tenure = "Free";
                                        $planner_subscribe->subscription_exist = "1";
                                        $planner_subscribe->subscription_closed = "no";
                                        $planner_subscribe->remaining_days = $remainingDays;
                                        $planner_subscribe->remaining_month = "0";
