        public function updatesubscriptionpaymnet(Request $request)
                {
                    $token = $request->header('Authorization');
                    $user = $this->getuser($token);
                    
                    if($user) 
                    {
                        $user_details = [
                            'name' => $user->name,
                            'email' => $user->email,
                            'mobile' => $user->mobile,
                            'business_name' => $user->business_name
                        ];
                        
                        $useraccess = $this->chkuseraccess($token);
                        $user_role = $useraccess['role'];
                        $user_access_role = $useraccess['useraccess'];
                        $user_access_array = $useraccess['access_array'];
                        
                        if($user_role == 'admin')
                        {
                            $rules = [
                                'amount' => 'required',
                                'tenure' => 'required',
                                'tenure_type' => 'required',
                            ];
                            
                            $validator = Validator::make($request->all(), $rules);
                    
                            if ($validator->fails()) 
                            {
                                $messages = $validator->messages()->toArray();
                                $translatedMessages = [];

                                foreach ($messages as $field => $errs) {
                                    foreach ($errs as $err) {
                                        $translatedMessages[$field][] = t($err);
                                    }
                                }

                                return response()->json([
                                    'message' => $translatedMessages,
                                ], 422);
                            }
                            else
                            {
                                /* ============================= */
                                /* DEFINE VARIABLES */
                                /* ============================= */

                                $autoRenew = $request->auto_renew ?? 'no';
                                $mandateToken = $request->mandate_token ?? NULL;

                                $amount = (string)$request->amount;

                                /* ============================= */
                                /* AMOUNT LOCK */
                                /* ============================= */

                                if(!in_array($amount, ['Free','499','1999','4999', '9999', '19999']))
                                {
                                    return response()->json([
                                        'message' => t('Invalid subscription amount'),
                                        'status'  => '0',
                                        'data'    => [],
                                        'user_role' => $user_role,
                                        'logged_in_user' => $user_details,
                                    ], 200);
                                }

                                /* ============================= */
                                /* SUBSCRIPTION PLAN LOGIC */
                                /* ============================= */

                                $subscriptionPlan = 'legacy_full';

                                if($amount == '499')
                                {
                                    $subscriptionPlan = 'launch_499_partial';
                                }
                                else if($amount == '1999')
                                {
                                    $subscriptionPlan = 'launch_1999_full';
                                }
                                /*
                                    else if($amount == '4999')
                                    {
                                        $subscriptionPlan = 'legacy_full';
                                    }
                                */
                                else if($amount == '4999')
                                {
                                    $subscriptionPlan = 'launch_4999_full';
                                }
                                else if($amount == '9999')
                                {
                                    $subscriptionPlan = 'legacy_full';
                                }
                                else if($amount == '19999')
                                {
                                    $subscriptionPlan = 'launch_19999_full';
                                }
                                else if($amount == 'Free')
                                {
                                    $subscriptionPlan = 'free_plan';
                                }

                                $tenure = $request->tenure;
                                $tenure_type = $request->tenure_type;
                                $itemid = $request->tenure_type;
                                $today = date('d/m/Y H:i:s');
                                
                                if($itemid)
                                {
                                    if(!empty($user->team_id))
                                        $update_user = $user->team_id; 
                                    else
                                        $update_user = $user->id;

                                    /* ============================= */
                                    /* SUBSCRIPTION CALCULATION */
                                    /* ============================= */

                                    if($itemid == "Monthly_Subscription" || $itemid == "monthly_Subscription")
                                    {
                                        $tenure = "monthly";
                                        $remaining_month = "0";
                                        $remainingDays = "30";
                                        $month1 = date("M");
                                        $actualend_date = date('Y-m-d', strtotime('+30 days'));
                                    } 
                                    else if($itemid == "Quarterly_Subscription")
                                    {
                                        $tenure = "quarterly";
                                        $remaining_month = "0";
                                        $remainingDays = "90";
                                        $month1 = date("M");
                                        $actualend_date = date('Y-m-d', strtotime('+90 days'));
                                    } 
                                    else if($itemid == "Half_Yearly_Subscription")
                                    {
                                        $tenure = "halfyearly";
                                        $remaining_month = "0";
                                        $remainingDays = "180";
                                        $month1 = date("M");
                                        $actualend_date = date('Y-m-d', strtotime('+180 days'));
                                    } 
                                    else if($itemid == "Annual_Subscription")
                                    {
                                        $tenure = "annual";
                                        $remaining_month = "Annual";
                                        $remainingDays = "365";
                                        $month1 = date("M");
                                        $actualend_date = date('Y-m-d', strtotime('+365 days'));
                                    }
                                    else if($itemid == "3_days_free")
                                    {
                                        $tenure = "Free";
                                        $remaining_month = "0";
                                        $remainingDays = "3";
                                        $month1 = date("M");
                                        $actualend_date = date('Y-m-d', strtotime('+3 days'));
                                    }

                                    $subscription_exist = "1";
                                    $subscription_closed = "no";
                                    $thisday = date("Y-m-d");

                                    $planner_subscribe = new PlannerSubscription();
                                
                                    $planner_subscribe->user_id = $update_user;
                                    $planner_subscribe->subscriptoin_amount = $amount;
                                    $planner_subscribe->subscription_type = $tenure_type;
                                    $planner_subscribe->subscription_date = $today;
                                    $planner_subscribe->subscription_tenure = $tenure;
                                    $planner_subscribe->subscription_exist = $subscription_exist;
                                    $planner_subscribe->subscription_closed = $subscription_closed;
                                    $planner_subscribe->remaining_days = $remainingDays;
                                    $planner_subscribe->remaining_month = $remaining_month;
                                    $planner_subscribe->actual_subscription_date = $thisday;
                                    $planner_subscribe->actual_subscription_end_date = $actualend_date;

                                    /* ✅ SAVE PLAN HERE */
                                    $planner_subscribe->subscription_plan = $subscriptionPlan;

                                    /* RECURRING FIELDS (kept intact) */
                                    $planner_subscribe->auto_renew = $autoRenew;
                                    $planner_subscribe->mandate_token = $mandateToken;
                                    $planner_subscribe->next_billing_date = $actualend_date;

                                    $planner_subscribe->subscribed_month = $month1;

                                    if($planner_subscribe->save())
                                    {
                                        $chkuser = User::where('id',$update_user)->latest()->first();

                                        $chkuser->chk_subscription = "1";
                                        $chkuser->subscribed_tenure = $tenure;
                                        $chkuser->subscribed_on = $today;
                                        $chkuser->auto_renew = $autoRenew;

                                        if($chkuser->save())
                                        {
                                            return response()->json([
                                                'message' => t('Data saved and details mailed'),
                                                'status' => '1',
                                                'data' => [],
                                                'user_role' => $user_role,
                                                'logged_in_user' => $user_details,
                                            ], 200);
                                        }
                                        else
                                        {
                                            return response()->json([
                                                'message' => t('Required user not found for adding subscription details'),
                                                'status' => '0',
                                                'data' => [],
                                                'user_role' => $user_role,
                                                'logged_in_user' => $user_details,
                                            ], 200);
                                        }
                                    }
                                    else 
                                    {
                                        return response()->json([
                                            'message' => t('Unable to save the details'),
                                            'status' => '0',
                                            'data' => [],
                                            'user_role' => $user_role,
                                            'logged_in_user' => $user_details,
                                        ], 200);
                                    }
                                }
                                else
                                {
                                    return response()->json([
                                        'message' => t('Lead not found'),
                                        'status' => '0',
                                        'data' => [],
                                        'user_role' => $user_role,
                                        'logged_in_user' => $user_details,
                                    ], 200);
                                }
                            }
                        }
                        else
                        {
                            return response()->json([
                                'message' => t('User do not have access'),
                                'status' => '0',
                                'data' => [],
                                'user_role' => $user_role,
                                'logged_in_user' => $user_details,
                            ], 401);
                        }
                    } 
                    else 
                    {
                        return response()->json([
