                    ], 401);
                }

                $page_title = __('dashboard.buy_leads');
                $page_description = t('Wedding couples requesting services via our website will be listed here after mobile number validation.');

                $user_details = [
                    'name' => $user->name,
                    'email' => $user->email,
                    'mobile' => $user->mobile,
                    'business_name' => $user->business_name
                ];

