                /* ✅ USER TYPE LOGIC */

                $isPartner = (int)$user->is_partner === 1;

                $subscription = DB::table('planners_subscription')
                    ->where('user_id', $user->id)
                    ->orderBy('created_at', 'desc')
                ->first();

                $subAmount = $subscription->subscriptoin_amount ?? 0;
                $subPlan   = $subscription->subscription_plan ?? '';

                $isLaunch499 = $user->chk_subscription == 1 && $subAmount == 499 && $subPlan == 'launch_499_partial';


               
                $isLegacyPartial =
                    $user->chk_subscription == 1 &&
                    (
                        ($subAmount == 1999 && $subPlan == 'legacy_full') ||
                        ($subAmount == 1999 && $subPlan == 'launch_1999_full') ||
                        ($subAmount == 499  && $subPlan == 'legacy_full')
                    );

                $isLegacyFull4999 =
                    $user->chk_subscription == 1 &&
                    $subAmount == 4999 &&
                    $subPlan == 'legacy_full';

                $isNoSubscription = $user->chk_subscription == 0;

                    

                $filterState        = trim($request->input('state_name', ''));
                $filterLeadCategory = trim($request->input('lead_category', ''));
                $page               = (int) $request->input('paginate', 1);

               

                $alreadyPurchased = DB::table('general_leads_buy')
                                    ->where('user_id', $user->id)
                                    ->pluck('general_leads_id')
                ->toArray();

                /* ✅ CURRENT MONTH & YEAR PURCHASE COUNTS */


                $todayPurchasedLeads = DB::table('general_leads_buy')
                    ->where('user_id', $user->id)
                    ->whereDate('created_at', now())
                ->count();
                
                $currentMonthLeadsPurchased = DB::table('general_leads_buy')
                    ->where('user_id', $user->id)
                    ->whereYear('created_at', now()->year)
                    ->whereMonth('created_at', now()->month)
                ->count();

                $currentYearLeadsPurchased = DB::table('general_leads_buy')
                    ->where('user_id', $user->id)
                    ->whereYear('created_at', now()->year)
                ->count();

                 

                $purchaseCounts = DB::table('general_leads_buy')
                    ->select('general_leads_id', 'purchase_type', DB::raw('COUNT(*) as total'))
                    ->groupBy('general_leads_id', 'purchase_type')
                    ->get()
                    ->groupBy(fn ($row) => $row->general_leads_id . '_' . $row->purchase_type);

                $leads = GeneralLead::where('from_source', 'PAW Leads')
                ->whereNotIn('id', $alreadyPurchased)
                ->orderBy('id', 'desc')
                ->get();

                $finalLeads = [];

                foreach ($leads as $lead) {

                    

                    if ((int)$lead->not_show_wp === 1 && (int)$lead->this_user_id !== (int)$user->id) continue;

                    if ($filterState !== '' && strcasecmp($lead->actual_state_tbl_name ?? '', $filterState) !== 0) continue;

                    if ($filterLeadCategory !== '' && strcasecmp($lead->actual_lead_from_to_show ?? '', $filterLeadCategory) !== 0) continue;

                    $packageTypes = array_map('trim', explode(',', strtolower($lead->package_type ?? '')));
                    $spec = strtolower($user->specialization ?? '');
                        /* ✅ SPECIALIZATION FILTER */
                    if ($spec === 'venue' && !(
                            in_array('venue', $packageTypes) ||
                            in_array('wedding', $packageTypes)
                        )) {
                        continue;
                    }
                    $matchedCat = null;

                    if (in_array('photo&videographer', $packageTypes) && str_contains($spec, 'photo')) {
                        $matchedCat = 'photo&videographer';
                        $desc = $lead->lead_description_photovideo;
                        $dbPrice = $lead->price_photovideo;
                        $eventCat = $lead->event_category_photovideo;

                    } elseif (in_array('catering', $packageTypes) && str_contains($spec, 'cater')) {
                        $matchedCat = 'catering';
                        $desc = $lead->lead_description_catering;
                        $dbPrice = $lead->price_catering;
                        $eventCat = $lead->event_category_catering;

                    } elseif (in_array('flower-decorators', $packageTypes) && str_contains($spec, 'flower')) {
                        $matchedCat = 'flower-decorators';
                        $desc = $lead->lead_description_flower;
                        $dbPrice = $lead->price_flower;
                        $eventCat = $lead->event_category_flower;

