                        $matchedCat = 'venue';
                        $desc = $lead->lead_description_venue;
                        $dbPrice = $lead->price_venue;
                        $eventCat = $lead->event_category_venue;

                    } elseif (in_array('wedding', $packageTypes)) {
                        $matchedCat = 'wedding';
                        $desc = $lead->lead_description;
                        $dbPrice = $lead->price;
                        $eventCat = $lead->event_category;

                    } else {
                        continue;
                    }


                    /* ✅ PURCHASE LIMIT CHECK */

                    $multiPurchaseCategories = ['wedding', 'photo&videographer'];

                    $maxPurchase = in_array($matchedCat, $multiPurchaseCategories) ? 3 : 1;

                    $key = $lead->id . '_' . $matchedCat;
                    $currentCount = isset($purchaseCounts[$key])
                        ? optional($purchaseCounts[$key]->first())->total
                        : 0;

                    if ($currentCount >= $maxPurchase) {
                        continue;
                    }

                    $today  = \Carbon\Carbon::today();
                    $expiry = \Carbon\Carbon::parse($lead->expiry_date)->startOfDay();

                    $cleanPrice = strtolower(trim((string)$dbPrice));

                    /* FORCE FREE FOR LEGACY 4999 USERS */
                    if ($isLegacyFull4999) {

                        if ($today->gt($expiry)) {
                            continue; // do not show after expiry
                        }

                        $Payment_api = 0;
                        $price_to_pass = "Free Purchase";
                        $price_to_display = "Free Purchase";
                        $button_label = "Free Purchase";
                    }

                    /* NON-SUBSCRIPTION USERS SHOULD NOT SEE FREE LEADS */
                    if ($isNoSubscription && $cleanPrice === 'free') {
                        continue;
                    }
 

                    $paid75Start = $expiry->copy()->addDays(1);
                    $paid75End   = $expiry->copy()->addDays(3);
                   

                    /* ==========================================================
                    PARTNER USERS
                    ========================================================== */

                    if ($isPartner) {

                        if ($today->lte($expiry)) {

                            $Payment_api = 1;
                            $price_to_pass = $dbPrice;
                            $price_to_display = "₹ {$dbPrice}/-";
                            $button_label = __('dashboard.buttons.buy_now');

                        } else {
                            continue;
                        }
                    }

