                    LEGACY FULL 4999 (ALL FREE)
                    ========================================================== */

                    elseif ($isLegacyFull4999) {
                        // already handled above
                    }

                    /* ==========================================================
                    LAUNCH 499 PARTIAL
                    ========================================================== */

                    elseif ($isLaunch499) {

                        if ($today->lte($expiry)) {

                            $Payment_api = 1;
                            $price_to_pass = $dbPrice;
                            $price_to_display = "₹ {$dbPrice}/-";
                            $button_label = __('dashboard.buttons.buy_now');

                        } elseif ($today->between($paid75Start, $paid75End)) {

                            $Payment_api = 1;
                            $price_to_pass = "75";
                            $price_to_display = "₹ 75/-";
                            $button_label = __('dashboard.buttons.buy_now');

                        } else {
                            continue;
                        }
                    }

                    /* ==========================================================
                    LEGACY PARTIAL (1999 / 1999 launch_1999_full / 499 legacy_full)
                    ========================================================== */

                    elseif ($isLegacyPartial) {

                        if ($today->lte($expiry)) {

                            $Payment_api = 1;
                            $price_to_pass = $dbPrice;
                            $price_to_display = "₹ {$dbPrice}/-";
                            $button_label = __('dashboard.buttons.buy_now');

                        } elseif ($today->between($paid75Start, $paid75End)) {

                            $Payment_api = 1;
                            $price_to_pass = "75";
                            $price_to_display = "₹ 75/-";
                            $button_label = __('dashboard.buttons.buy_now');

                        } else {
                            continue;
                        }
                    }


                    /* ==========================================================
                    USERS WITHOUT SUBSCRIPTION
                    ========================================================== */

                    elseif ($isNoSubscription) {

                        if ($today->lte($expiry)) {

                            $price = $dbPrice;

                            $Payment_api = 1;
                            $price_to_pass = $price;
                            $price_to_display = "₹ {$price}/-";
                            $button_label = __('dashboard.buttons.buy_now');

                        } elseif ($today->between($paid75Start, $paid75End)) {

                            $Payment_api = 1;
                            $price_to_pass = "75";
                            $price_to_display = "₹ 75/-";
                            $button_label = __('dashboard.buttons.buy_now');

                        } else {
                            continue;
                        }
                    }

                    /* ==========================================================
                    NORMAL USERS (OLD LOGIC)
                    ========================================================== */

                    else {

                        if ($cleanPrice === 'free') {

                            if ($today->lte($expiry)) {

                                $Payment_api = 0;
                                $price_to_pass = "Free Purchase";
                                $price_to_display = __('dashboard.buttons.free_purchase');
                                $button_label = __('dashboard.buttons.free_purchase');

                            } else {
                                continue;
                            }

                        } else {

                            if ($today->lte($expiry)) {

                                $Payment_api = 1;
                                $price_to_pass = $dbPrice;
                                $price_to_display = "₹ {$dbPrice}/-";
                                $button_label = __('dashboard.buttons.buy_now');

                            } elseif ($today->between($paid75Start, $paid75End)) {

                                $Payment_api = 1;
                                $price_to_pass = "75";
                                $price_to_display = "₹ 75/-";
                                $button_label = __('dashboard.buttons.buy_now');

                            }  else {
                                continue;
                            }
                        }
                    }

                    $location = trim(($lead->event_location ?? '') . ', ' . ($lead->actual_state_tbl_name ?? ''), ', ');

                    $finalLeads[] = [
                        'lead_type' => __('dashboard.buy_leads'),
                        'id' => $lead->id,
                        'name' => t($lead->name),
                        'category' => __('dashboard.categories.' . $matchedCat),
                        'wedding_date' => $lead->event_date
                            ? \Carbon\Carbon::parse($lead->event_date)->format('d/m/Y')
                            : '-',

                        'lead_time' => $lead->lead_time,
                        'location' => translateText($location, app()->getLocale()),
                        'requirement' => translateText($eventCat, app()->getLocale()),
                        'additional_requirements' => translateLongText($desc),
                        'actual_lead_from_to_show' => $lead->actual_lead_from_to_show ?? '',
                        'enable_paynow_button' => 1,
                        'Payment_api' => $Payment_api,
                        'price_to_display' => $price_to_display,
                        'price_to_pass' => $price_to_pass,
                        'button_label' => $button_label,
                        'purchase_allowed' => 0,
