                }

                 $perPage = 15;
                $total = count($finalLeads);
                $pagedData = array_slice($finalLeads, ($page - 1) * $perPage, $perPage);



                if ($isLegacyFull4999) {

                    $showStatisticsCard = [
                        'today_purchased_leads' => $todayPurchasedLeads,
                        'current_month_leads_purchased' => $currentMonthLeadsPurchased,
                        'current_year_leads_purchased' => $currentYearLeadsPurchased,
                        'daily_max_limit' => 3,
                        'monthly_max_limit' => 30,
                        'yearly_max_limit' => 360,
                    ];

                } else {

                    $showStatisticsCard = null;
                }

                return response()->json([
                    'status' => '1',
                    'message' => __('dashboard.buy_leads'),
                    'page_title' => $page_title,
                    'page_description' => $page_description,
                    'show_statistics_card' => $showStatisticsCard,
                    'data' => [
                        'current_page' => $page,
                        'per_page' => $perPage,
                        'total' => $total,
                        'last_page' => ceil($total / $perPage),
                        'data' => $pagedData,
