                    ->where('user_id', $user->id)
                    ->orderBy('created_at', 'desc')
                ->first();

                $subscriptionStart = $subscription
                ? \Carbon\Carbon::parse($subscription->created_at)->startOfDay()
                : now()->startOfDay();


                $today = now();

                /* MONTHLY CYCLE START */
                $monthStart = $subscriptionStart->copy();

                while ($monthStart->addMonth()->lte($today)) {
                    // move forward until current cycle
                }

                $monthStart = $monthStart->subMonth();
                $monthEnd   = $monthStart->copy()->addMonth()->subDay()->endOfDay();

                /* YEARLY CYCLE START */
                $yearStart = $subscriptionStart->copy();

