                    $is_partner = $user->is_partner;
                    $is_admin = $user->is_admin;
                    
                    if($team_id == null)
                    {
                        $team_members = User::where('team_id',$user->id)->where('is_active',1)->select('id','name')->get()->toArray();
                    }
                    else
                    {
                        $team_members = User::where('team_id',$user->team_id)->where('is_active',1)->select('id','name')->get()->toArray();
                    }
                
        
        
                    
                    $statuses = [
                        "list" => [
                            ['value' => 'meeting-confirmed', 'display_text' => __('dashboard.statuses.meeting_confirmed')],
                            ['value' => 'requirements-gathered', 'display_text' => __('dashboard.statuses.requirements_gathered')],
                            ['value' => 'follow-up', 'display_text' => __('dashboard.statuses.follow_up')],
                            ['value' => 'prospect', 'display_text' => __('dashboard.statuses.prospect')],
                            ['value' => 'quote-sent', 'display_text' => __('dashboard.statuses.quote_sent')],
                            ['value' => 'negotiation', 'display_text' => __('dashboard.statuses.negotiation')],
                            ['value' => 'wedding-confirmed', 'display_text' => __('dashboard.statuses.wedding_confirmed')],
                            ['value' => 'lost', 'display_text' => __('dashboard.statuses.lost')],
