                        $filter_user_id = $team_id;
                    }

 
                    $status_count = ['customers' => 0,'confirmed' => 0,'prospect' => 0,'followup' => 0,'completed' => 0];
                        
                    /* =============================================
                    LEADS STATISTICS (FAST QUERY)
                    ============================================= */

                    $statsBase = DB::table('general_leads_buy as glb')
                        ->leftJoin('general_leads as gl','glb.general_leads_id','=','gl.id')
                        ->where('glb.user_id',$filter_user_id)
                        ->where('gl.mute',0);

                    $statsFiltered = clone $statsBase;

                    /* DATE FILTER */

                    if(!empty($from_date) && !empty($to_date)){

                        $start = \Carbon\Carbon::parse($from_date)->startOfDay();
                        $end   = \Carbon\Carbon::parse($to_date)->endOfDay();

                        $statsFiltered->whereBetween('glb.created_at',[$start,$end]);

                    }
                    elseif(!empty($from_date)){

                        $start = \Carbon\Carbon::parse($from_date)->startOfDay();
                        $statsFiltered->where('glb.created_at','>=',$start);

                    }
                    elseif(!empty($to_date)){

                        $end = \Carbon\Carbon::parse($to_date)->endOfDay();
                        $statsFiltered->where('glb.created_at','<=',$end);

                    }

                    /* DISTINCT TOTAL LEADS */

                    

                    $total_leads_count = (clone $statsBase)
                        ->distinct('glb.general_leads_id')
                        ->count('glb.general_leads_id');

                    /* TODAY */

                    $total_leads_purchased_today = (clone $statsBase)
                        ->whereDate('glb.created_at',\Carbon\Carbon::today())
                        ->count();

                    /* MONTH */

                    if(!empty($from_date)){

                        $month = \Carbon\Carbon::parse($from_date)->month;
                        $year  = \Carbon\Carbon::parse($from_date)->year;

                    }else{

                        $month = now()->month;
                        $year  = now()->year;
                    }

                    $leads_purchased_month = (clone $statsBase)
                        ->whereYear('glb.created_at',$year)
                        ->whereMonth('glb.created_at',$month)
                        ->count();

                    /* YEAR */

                    if(!empty($from_date)){

                        $year = \Carbon\Carbon::parse($from_date)->year;

                    }else{

                        $year = now()->year;
                    }

                    $leads_purchased_year = (clone $statsBase)
                        ->whereYear('glb.created_at',$year)
                        ->count();

                    /* FILTERED COUNT */

                    $filtered_leads_count = (clone $statsFiltered)
                        ->distinct('glb.general_leads_id')
                        ->count('glb.general_leads_id');

                    $statistics_data = [
                        'total_leads_count' => $total_leads_count,
                        'total_leads_purchased_today' => $total_leads_purchased_today,
                        'leads_purchased_month' => $leads_purchased_month,
                        'leads_purchased_year' => $leads_purchased_year,
                        'filtered_leads_count' => $filtered_leads_count
                    ];
                    
                        if(!empty($lead_id))
                        {
                            $leads_data = GeneralLeadBuy::where('general_leads_buy.user_id', $filter_user_id)
                                ->where('general_leads_buy.general_leads_id', $lead_id)
                                ->where('general_leads.mute', '=', "0")
                                /* DATE FILTER */

                                ->when($from_date && $to_date, function ($query) use ($from_date,$to_date) {

                                    $start = \Carbon\Carbon::parse($from_date)->startOfDay();
                                    $end   = \Carbon\Carbon::parse($to_date)->endOfDay();

                                    $query->whereBetween('general_leads_buy.created_at',[$start,$end]);

                                })
                                ->when($from_date && !$to_date, function ($query) use ($from_date) {

                                    $start = \Carbon\Carbon::parse($from_date)->startOfDay();
                                    $query->where('general_leads_buy.created_at','>=',$start);

                                })
                                ->when(!$from_date && $to_date, function ($query) use ($to_date) {

                                    $end = \Carbon\Carbon::parse($to_date)->endOfDay();
                                    $query->where('general_leads_buy.created_at','<=',$end);

                                })
                                ->when($filter_managed_by, function ($query) use ($user) {
                                    $query->where(function($q) use ($user){
                                        $q->where('general_leads_remarks.managed_by', $user->id);
                                    });
                                })
                                ->groupBy('general_leads_buy.general_leads_id')
                                ->leftJoin("general_leads","general_leads_buy.general_leads_id","=","general_leads.id")
                                ->leftJoin("users","general_leads_buy.user_id","=","users.id")
                                ->leftJoin("general_leads_remarks","general_leads_buy.id","=","general_leads_remarks.general_leads_buy_id")               
                                ->leftJoin('general_leads_remarks as p', 'p.managed_by', '=', 'users.id')
                                ->leftJoin('users as u', 'u.id', '=', 'general_leads_remarks.managed_by')
                                ->orderBy('general_leads.id','desc')
                                ->select(
                                    'general_leads.id as id',                          // This will be returned as "id"
                                    'general_leads_buy.id as general_leads_buy_id',    // Original buy id
                                    'general_leads.team_remarks',
                                    'general_leads.lead_type',
                                    'general_leads.price',
