                                    'general_leads.event_date',
                                    'general_leads.address',
                                    'general_leads.package_type',
                                    'general_leads.expiry_date',
                                    'general_leads.city',
                                    'general_leads.lead_time',
                                    'general_leads.purchase_allowed',
                                    'general_leads.wedding_type',
                                    'general_leads_buy.general_leads_id',
                                    'general_leads_buy.user_id',
                                    'general_leads_buy.user_id as userid',
                                    'general_leads.name',
                                    'general_leads.email',
                                    'general_leads.mobile',
                                    'general_leads.event_category',
                                    'general_leads.event_location',
                                    'general_leads.lead_description',
                                    'general_leads.buyleads_category_type',
                                    'general_leads.leads_link',
