                                    DB::raw("(SELECT count(*) FROM general_leads_buy WHERE general_leads_buy.general_leads_id = general_leads.id) as purchase_made"),
                                    'general_leads_remarks.remarks as glr_remarks',
                                    'general_leads_remarks.status  as glr_status',
                                    'general_leads_remarks.tentative_budget',
                                    'general_leads_remarks.actual_budget',
                                    'general_leads_remarks.followup as glr_followup',
                                    'general_leads_remarks.follow_up_time',
                                    'general_leads_remarks.managed_by as glr_manage',
                                    'u.name as managebyname',
                                    'general_leads_remarks.updated_at as glr_updatedat',
                                    'general_leads_buy.purchase_type',
                                    'general_leads.lead_description_venue',
                                    'general_leads.event_category_venue',
                                    'general_leads.lead_type_venue',
                                    'general_leads.price_venue',
                                    'general_leads.purchase_allowed_venue',


                                    'general_leads.lead_description_jewellers',
                                    'general_leads.event_category_jewellers',
                                    'general_leads.lead_type_jewellers',
                                    'general_leads.price_jewellers',
                                    'general_leads.purchase_allowed_jewellers',


                                    'general_leads.lead_description_weddingwear',
                                    'general_leads.event_category_weddingwear',
                                    'general_leads.lead_type_weddingwear',
                                    'general_leads.price_weddingwear',
                                    'general_leads.purchase_allowed_weddingwear',
                                    DB::raw("TIMESTAMPDIFF(day,date(NOW()),date(general_leads.expiry_date)) as days_left")
                                );

                            $leads_data = ($paginate == "false") ? $leads_data->get() : $leads_data->paginate(10); 

                            // Apply Free Purchase feature for the passed general_leads_id
                            $leads_data->getCollection()->transform(function($lead) use ($user, $lead_id) {
                                if(
                                    isset($lead->price_purchase) &&
                                    $lead->price_purchase === "Free Purchase" &&
                                    $lead->user_id == $user->id &&
                                    $lead->general_leads_id == $lead_id
                                ) {
                                    $lead->name .= " - Free Purchase"; // Append to name
                                }
                                return $lead;
                            });
                        }
 
                        else
                        {
                            $specialization_items = explode(',',$user->specialization);
            
                            $allowsearch = false;
                            $allowfilter= false;
                            
                            if(!empty($search))
                            { 
                                $allowsearch = true;
                            }
            
                            if(!empty($filter))
                            { 
                                $allowfilter = true;
                            }
            
                            $leads_data = GeneralLeadBuy::where('general_leads_buy.user_id', $filter_user_id)
                            ->where('general_leads.mute','=', "0")
                            /* DATE FILTER */

                            ->when($from_date && $to_date, function ($query) use ($from_date,$to_date) {

                                $start = \Carbon\Carbon::parse($from_date)->startOfDay();
                                $end   = \Carbon\Carbon::parse($to_date)->endOfDay();

                                $query->whereBetween('general_leads_buy.created_at',[$start,$end]);

                            })
                            ->when($from_date && !$to_date, function ($query) use ($from_date) {

                                $start = \Carbon\Carbon::parse($from_date)->startOfDay();
                                $query->where('general_leads_buy.created_at','>=',$start);

                            })
                            ->when(!$from_date && $to_date, function ($query) use ($to_date) {

                                $end = \Carbon\Carbon::parse($to_date)->endOfDay();
                                $query->where('general_leads_buy.created_at','<=',$end);

                            })
                            ->when($allowsearch, function ($query) use ($search) {
                                $query->where(function($q) use ($search){
                                        $q->where('general_leads.name', 'like', '%'.$search.'%')
                                        ->orWhere('general_leads.email', 'like', '%'.$search.'%')
                                        ->orWhere('general_leads.mobile', 'like', '%'.$search.'%');
                                });
                            })
                            ->when($allowfilter, function ($query) use ($filter) {
                                $query->where(function($q) use ($filter){
                                    $q->where('general_leads_remarks.status', 'like', '%'.$filter.'%');
                                });
                            })
                            ->when($filter_managed_by, function ($query) use ($user) {
                                $query->where(function($q) use ($user){
                                    $q->where('general_leads_remarks.managed_by', $user->id);
                                });
                            })
                            ->leftJoin("general_leads","general_leads_buy.general_leads_id","=","general_leads.id")
                            ->leftJoin("users","general_leads_buy.user_id","=","users.id")
                            ->leftJoin("general_leads_remarks","general_leads_buy.id","=","general_leads_remarks.general_leads_buy_id")
                            ->leftJoin('general_leads_remarks as p', 'p.managed_by', '=', 'users.id')
                            ->leftJoin('users as u', 'u.id', '=', 'general_leads_remarks.managed_by')
