          public function myleadswithfree(Request $request)
            {
                $token = $request->header('Authorization');
                $user = $this->getuser($token);
                
                
                if($user) 
                {


                    $useraccess = $this->chkuseraccess($token);
                    $user_access_role = $useraccess['useraccess'];

                    $page_title = __('dashboard.my_leads');
                    $page_description =  __('dashboard.my_leads_description');
        


                    $show_add_leads_button = "yes";

                    $wedding_date_dropdown = "";

                    $sources_from_dropdown = "";

                    $approx_wedding_dropdown = "";



                    
                    $wedding_date_dropdown = [
                        "list" => [
                            ['value' => 'dateyes', 'display_text' => __('dashboard.wedding_date.yes')],
                            ['value' => 'dateno',  'display_text' => __('dashboard.wedding_date.no')],
                        ],
                    ];


                    $sources_from_dropdown = [
                        "list" => [
                            ['value' => 'Instagram',      'display_text' => __('dashboard.sources.instagram')],
                            ['value' => 'Just Dial',      'display_text' => __('dashboard.sources.justdial')],
                            ['value' => 'Sulekha',        'display_text' => __('dashboard.sources.sulekha')],
