        public function getNotificationLogsalllist_1(Request $request)
            {
                $token = $request->header('Authorization');

                // -----------------------------------
                // Get User
                // -----------------------------------
                $user = $this->getuser($token);

                if (!$user) {
                    return response()->json([
                        'message' => translateText('User not found', app()->getLocale()),
                        'status'  => 0
                    ], 401);
                }

                $useraccess = $this->checkeditaccess($token);
                $user_role  = $useraccess['role'];

                $user_details = [
                    'name'          => $user->name,
                    'email'         => $user->email,
                    'mobile'        => $user->mobile,
                    'business_name' => $user->business_name
                ];

                // -----------------------------------
                // SPECIALIZATION FILTER
                // -----------------------------------
                $specialization = $user->specialization;
                $specialization_array = array_map('trim', explode(',', $specialization));

                // -----------------------------------
                // Pagination
                // -----------------------------------
                $page      = $request->input('page', 1);
                $per_page  = 25;
                $offset    = ($page - 1) * $per_page;

                // -----------------------------------
                // BASE QUERY
                // -----------------------------------
                $baseQuery = \App\BuyleadNotificationsLog::select(
                        'buylead_notifications_logs.id',
                        'lead_id',
                        'custom_lead_id',
                        'lead_name',
                        'package_type',
                        'type',
                        'sent_for',
                        'message',
                        'buylead_notifications_logs.created_at',
                        'buylead_notification_user_status.is_read'
                    )
                    ->join(
                        'buylead_notification_user_status',
                        'buylead_notifications_logs.id',
                        '=',
                        'buylead_notification_user_status.log_id'
                    )
                    ->where('buylead_notification_user_status.user_id', $user->id)

                    ->where(function($q) use ($specialization_array) {
                        $q->where('type', 'news')
                        ->orWhere('type', 'create')
                        ->orWhereIn('sent_for', $specialization_array);
                    });

                // -----------------------------------
                // TOTAL RECORDS
                // -----------------------------------
                $total_records = $baseQuery->count();
                $total_pages   = ceil($total_records / $per_page);

                // -----------------------------------
                // FETCH PAGINATED LOGS
                // -----------------------------------
                $logs = $baseQuery
                        ->orderBy('buylead_notifications_logs.created_at', 'desc')
                        ->offset($offset)
                        ->limit($per_page)
                        ->get();

                // -----------------------------------
                // DATA
                // -----------------------------------
                $data = [];

                foreach ($logs as $log) {

                    $created = Carbon::parse($log->created_at);

                    $data[] = [
                        'id'              => $log->id,
                        'lead_id'         => $log->lead_id,
                        'custom_lead_id'  => $log->custom_lead_id,
                        'lead_name'       => transliterateTextKeepNumbers($log->lead_name, app()->getLocale()),
                        'package_type'    => $log->package_type,
                        'type'            => $log->type,
                        'sent_for'        => $log->sent_for,
                        'message'         => translateText($log->message, app()->getLocale()),
                        'read_status'     => ($log->is_read == 1 ? 'read' : 'unread'),

                        // dd-mm-yyyy format
                        'notification_on' => $created->format('d-m-Y'),
                    ];
                }

                // -----------------------------------
                // OVERALL UNREAD COUNT
                // -----------------------------------
                $overall_unread = \App\BuyleadNotificationsLog::join(
                        'buylead_notification_user_status',
                        'buylead_notifications_logs.id',
                        '=',
                        'buylead_notification_user_status.log_id'
                    )
                    ->where('buylead_notification_user_status.user_id', $user->id)
                    ->where('buylead_notification_user_status.is_read', 0)
                    ->where(function($q) use ($specialization_array) {
                        $q->where('type', 'news')
                        ->orWhere('type', 'create')
                        ->orWhereIn('sent_for', $specialization_array);
                    })
                    ->count();

                // -----------------------------------
                // RESPONSE
                // -----------------------------------
                return response()->json([
                    'message' => translateText('Log list fetched successfully', app()->getLocale()),
                    'status'  => 1,

                    'data' => $data,

                    'unread_counts' => $overall_unread,

                    'pagination' => [
                        'current_page'  => (int)$page,
                        'per_page'      => (int)$per_page,
                        'total_records' => (int)$total_records,
                        'total_pages'   => (int)$total_pages,
                    ],

                    'user_role'      => $user_role,
                    'logged_in_user' => $user_details,
                    'base_url'       => 'https://planawedding.in/storage/',
                ], 200);
            }

