    /* New Initiate subscription payment starts */

        public function initiatesubscriptionpayment19999(Request $request)
            {
                $token = $request->header('Authorization');
                $user = $this->getuser($token);
                
                if($user) 
                {
                    $user_details = ['name' => $user->name,'email' => $user->email,'mobile' => $user->mobile,'business_name' => $user->business_name];
                    
                    $useraccess = $this->chkuseraccess($token);
                    $user_role = $useraccess['role'];
                    $user_access_role = $useraccess['useraccess'];
                    $user_access_array = $useraccess['access_array'];
                    


                    $startDate = Carbon::today();
                    $endDate = $startDate->copy()->addYear();

                    $remainingDays = $startDate->diffInDays($endDate);


                    if($user_role == 'admin')
                    {
                        $rules = [
                            'amount' => 'required',
                            'tenure' => 'required',
                            'tenure_type' => 'required',
                            'tenure_name' => 'required',
                        ];
                        
                        $validator = Validator::make($request->all(), $rules);

                        if ($validator->fails()) 
                        {
                            $messages = $validator->messages()->toArray();
                            $translatedMessages = [];

                            foreach ($messages as $field => $errs) {
                                foreach ($errs as $err) {
                                    $translatedMessages[$field][] = t($err);
                                }
                            }

                            return response()->json([
                                'message' => $translatedMessages,
                            ], 422);
                        }
                        else
                        {
                            $itemid = $request->tenure;
                            $type = $request->tenure_type;
                            $amount = $request->amount;
                            $tenure_name = $request->tenure_name;

                            if(
                                $amount == '1999' ||
                                $amount == '499' ||
                                $amount == '4999' ||
                                $amount == '9999' ||
                                $amount == '19999'
                            )
                            {
                                return response()->json([
                                    'message' => t('Payment can be initiated'),
                                    'status' => '1',
                                    'data' => [],
                                    'user_role' => $user_role,
                                    'payment_initiated' => 1,
                                    'next_api' => 'yes',
                                    'orderid' => "",
                                    'logged_in_user' => $user_details,
                                ], 200);
                            }

                            else if(
                                $amount == "0" &&
                                $request->tenure_name == "zero_plan"
                            )
                            {
                                $amount = $request->amount;
                                $tenure = $request->tenure;
                                $tenure_type = $request->tenure_type;
                                $subscriptionPlan = $request->tenure_name;

                                $today = date('d/m/Y H:i:s');

                                if(!empty($user->team_id))
                                    $update_user = $user->team_id;
                                else
                                    $update_user = $user->id;

                                $orderid = time().'00'.$subscriptionPlan;

                                $payment = new Payment();

                                if(empty($user->team_id))
                                    $payment->user_id = $user->id;
                                else
                                    $payment->user_id = $user->team_id;

                                $payment->orderid = $orderid;
                                $payment->reference = '';
                                $payment->status = '';
                                $payment->payable_id = $subscriptionPlan;
                                $payment->payable_type = "App\PlannerSubscription";
                                $payment->save();

                                $startDate = Carbon::today();
                                $endDate = $startDate->copy()->addYear();

                                $remainingDays = $startDate->diffInDays($endDate);

                                $planner_subscribe = new PlannerSubscription();
                                $planner_subscribe->user_id = $update_user;
                                $planner_subscribe->subscriptoin_amount = 0;
                                $planner_subscribe->subscription_plan = 'zero_plan';
                                $planner_subscribe->subscription_type = $tenure_type;
                                $planner_subscribe->subscription_date = $today;

                                $planner_subscribe->subscription_tenure = 'annual';
                                $planner_subscribe->subscribed_month = date('M');

                                $planner_subscribe->subscription_exist = "1";
                                $planner_subscribe->subscription_closed = "no";

                                $planner_subscribe->remaining_days = $remainingDays;
                                $planner_subscribe->remaining_month = "Annual";

                                $planner_subscribe->actual_subscription_date = $startDate->format('Y-m-d');
                                $planner_subscribe->actual_subscription_end_date = $endDate->format('Y-m-d');

                                if($planner_subscribe->save())
                                {
                                    $chkuser = User::where('id',$update_user)->first();

                                    $chkuser->chk_subscription = "1";
                                    $chkuser->subscribed_tenure = "annual";
                                    $chkuser->subscribed_on = $today;

                                    if($chkuser->save())
                                    {
                                        return response()->json([
                                            'message' => t('Data saved successfully'),
                                            'status' => '1',
                                            'data' => [],
                                            'user_role' => $user_role,
                                            'next_api' => 'no',
                                            'logged_in_user' => $user_details,
                                        ], 200);
                                    }
                                    else
                                    {
                                        return response()->json([
                                            'message' => t('Required user not found for adding subscription details'),
                                            'status' => '0',
                                            'data' => [],
                                            'user_role' => $user_role,
                                            'next_api' => 'no',
                                            'logged_in_user' => $user_details,
                                        ], 200);
                                    }
                                }
                                else
                                {
                                    return response()->json([
                                        'message' => t('Unable to save the details'),
                                        'status' => '0',
                                        'data' => [],
                                        'user_role' => $user_role,
                                        'next_api' => 'no',
                                        'logged_in_user' => $user_details,
                                    ], 200);
                                }
                            }
                            else if($amount == "Free")
                            {
                                $amount = $request->amount;
                                $tenure = $request->tenure;
                                $tenure_type = $request->tenure_type;
                                $itemid = $request->tenure_type;
                                $today = date('d/m/Y H:i:s');

                                if(!empty($user->team_id))
                                    $update_user = $user->team_id; 
                                else
                                    $update_user = $user->id;

                                if($itemid == "3_days_free")
                                {
                                    $itemid = $type;
                                    $orderid = time().'00'.$itemid;

                                    $payment = new Payment();
                                    
                                    if(empty($user->team_id))
                                        $payment->user_id = $user->id;
                                    else
                                        $payment->user_id = $user->team_id;

                                    $payment->orderid = $orderid;
                                    $payment->reference = '';
                                    $payment->status = '';
                                    $payment->payable_id = $itemid;
                                    $payment->payable_type = "App\PlannerSubscription";  
                                    $payment->save();

                                    $remainingDays = "3";
                                    $actualend_date = date('Y-m-d', strtotime(date('Y-m-d'). ' + 3 days'));

                                    $planner_subscribe = new PlannerSubscription();
                                    $planner_subscribe->user_id = $update_user;
                                    $planner_subscribe->subscriptoin_amount = $amount;
                                    $planner_subscribe->subscription_type = $tenure_type;
                                    $planner_subscribe->subscription_date = $today;
                                    $planner_subscribe->subscription_tenure = "Free";
                                    $planner_subscribe->subscription_exist = "1";
                                    $planner_subscribe->subscription_closed = "no";
                                    $planner_subscribe->remaining_days = $remainingDays;
                                    $planner_subscribe->remaining_month = "0";
                                    $planner_subscribe->actual_subscription_date = date("Y-m-d");
                                    $planner_subscribe->actual_subscription_end_date = $actualend_date;

                                    if($planner_subscribe->save())
                                    {
                                        $chkuser = User::where('id',$update_user)->latest()->first();
                                        $chkuser->chk_subscription = "1";
                                        $chkuser->subscribed_tenure = "Free";
                                        $chkuser->subscribed_on = $today;

                                        if($chkuser->save())
                                        {
                                            return response()->json([
                                                'message' => t('Data saved successfully'),
                                                'status' => '1',
                                                'data' => [],
                                                'user_role' => $user_role,
                                                'logged_in_user' => $user_details,
                                            ], 200);
                                        }
                                        else
                                        {
                                            return response()->json([
                                                'message' => t('Required user not found for adding subscription details'),
                                                'status' => '0',
                                                'data' => [],
                                                'user_role' => $user_role,
                                                'logged_in_user' => $user_details,
                                            ], 200); 
                                        }
                                    }
                                    else 
                                    {
                                        return response()->json([
                                            'message' => t('Unable to save the details'),
                                            'status' => '0',
                                            'data' => [],
                                            'user_role' => $user_role,
                                            'logged_in_user' => $user_details,
                                        ], 200); 
                                    }
                                }
                            }
                            else
                            {
                                return response()->json([
                                    'message' => t('Type is not defined'),
                                    'status' => '0',
                                    'data' => [],
                                    'user_role' => $user_role,
                                    'payment_initiated' => 0,
                                    'orderid' => "",
                                    'logged_in_user' => $user_details,
                                ], 200);
                            }
                        }
                    }
                    else
                    {
                        return response()->json([
                            'message' => t('User do not have access'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => $user_role,
                            'payment_initiated' => "",
                            'orderid' => "",
                            'logged_in_user' => $user_details,
                        ], 401);
                    }
                } 
                else 
                {
                    return response()->json([
                        'message' => t('User not found'),
                        'status' => '0',
                        'data' => [],
                        'user_role' => "",
                        'payment_initiated' => "",
                        'orderid' => "",
                        'logged_in_user' => [],
                    ], 401);
                }
            }
                
    /* New Initiate subscription payment ends */
}